-- ── Noob Army Team (real Roblox Team object) ────────────────
-- Creates or reuses a Team in the Teams service so:
--   1. Humanoid.Team is set → Roblox's native friendly-fire prevention applies
--   2. isNoobTeam() BoolValue tag stays as a backup check for bullets/AoE
local NOOB_TEAM_NAME  = "Noob Army"
local NOOB_TEAM_COLOR = BrickColor.new("Bright yellow")
local noobTeam = TeamsService:FindFirstChild(NOOB_TEAM_NAME)
if not noobTeam then
    local ok, result = pcall(function()
        local t = Instance.new("Team")
        t.Name          = NOOB_TEAM_NAME
        t.TeamColor     = NOOB_TEAM_COLOR
        t.AutoAssignable = false   -- only noobs get assigned to this team
        t.Parent        = TeamsService
        return t
    end)
    if ok then noobTeam = result end
end

