-- ── Utility ─────────────────────────────────────────────────
local function safeChat(head, msg, color)
    if head and head.Parent then
        pcall(function() Chat:Chat(head, msg, color or Enum.ChatColor.White) end)
    end
end

local function isAlive(h)  -- humanoid alive check
    return h and h.Parent and h.Health > 0
end

local function rootOf(model)
    if not model then return nil end
    return model:FindFirstChild("HumanoidRootPart") or model:FindFirstChild("Torso")
end

local function posOf(model)
    local r = rootOf(model)
    return r and r.Position or nil
end

local function humanoidOf(model)
    return model and model:FindFirstChildOfClass("Humanoid")
end

-- ── Team check: is this model a fellow noob? ────────────────
-- Checks both the BoolValue tag (fast, always present on our noobs)
-- and Humanoid.Team (Roblox native, prevents friendly-fire system-wide)
local function isNoobTeam(model)
    if not model then return false end
    -- Primary check: our custom tag
    local tag = model:FindFirstChild("IsNoobTeam")
    if tag and tag.Value == true then return true end
    -- Secondary check: Roblox Team object (catches edge cases)
    -- v9.2.1: wrap in pcall — some games have Humanoids in a destroyed/
    -- mid-replication state where reading `.Team` throws "Team is not a
    -- valid member of Humanoid". This caused noob scanning to abort
    -- entirely (see isHostileNPC → findNearestKillerNPC → scanForKillers).
    if noobTeam then
        local hum = model:FindFirstChildOfClass("Humanoid")
        if hum then
            local ok, teamVal = pcall(function() return hum.Team end)
            if ok and teamVal == noobTeam then return true end
        end
    end
    -- v9.2.4: BLACKLIST ALL REAL PLAYERS (not just the local player).
    -- The user reported that noobs were still targeting them as a "killer"
    -- even after the v9.2.3 fix. This is because some games tag the local
    -- player's Humanoid with attributes or in-game state that made
    -- isHostileNPC return true. By blacklisting EVERY real player here,
    -- noobs will NEVER target any player character — they only target
    -- NPCs and killer NPCs. This uses Players:GetPlayerFromCharacter
    -- (the "get:players thingy" the user requested).
    local isRealPlayer = false
    pcall(function()
        isRealPlayer = Players:GetPlayerFromCharacter(model) ~= nil
    end)
    if isRealPlayer then return true end
    -- Also explicitly include the local player's character (covers edge
    -- cases where the local player isn't yet registered in the Players
    -- service, e.g. during character respawn).
    local pchar = player.Character
    if pchar and model == pchar then return true end
    return false
end

-- v9.2 FORWARD DECLARATIONS for storage-folder helpers.
-- These are assigned later (after KILLER_STORAGE_NAMES / NPC_STORAGE_NAMES
-- are defined) but `findNearest` (below) needs to reference them, so we
-- declare them as locals up here.
local getKillerStorage  -- function() -> Folder  (assigned later)
local getNpcStorage     -- function() -> Folder  (assigned later)

local function findNearest(pos, excludeModel, range)
    range = range or AGGRO_RANGE
    local best, bestDist = nil, range

    -- Direct workspace children (players + loose NPC models)
    -- v9.2.1: each child check is pcalled.
    for _, obj in pairs(workspace:GetChildren()) do
        pcall(function()
            if obj:IsA("Model") and obj ~= excludeModel then
                if not isNoobTeam(obj) then
                    local h = humanoidOf(obj)
                    local r = rootOf(obj)
                    if h and r then
                        local healthOk = true
                        pcall(function() healthOk = h.Health > 0 end)
                        if healthOk then
                            local d = (r.Position - pos).Magnitude
                            if d < bestDist then bestDist = d; best = h end
                        end
                    end
                end
            end
        end)
    end

    -- v9.2: also scan known storage folders so killers/NPCs in
    -- workspace["Killer Storage"] (and similar) are detected even by
    -- this legacy child-only scan. This makes the original `findNearest`
    -- work correctly with organized-storage games.
    if getKillerStorage or getNpcStorage then
        local function scanFolder(folder)
            if not folder then return end
            for _, obj in ipairs(folder:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= excludeModel and not isNoobTeam(obj) then
                        local h = humanoidOf(obj)
                        local r = rootOf(obj)
                        if h and r then
                            local healthOk = true
                            pcall(function() healthOk = h.Health > 0 end)
                            if healthOk then
                                local d = (r.Position - pos).Magnitude
                                if d < bestDist then bestDist = d; best = h end
                            end
                        end
                    end
                end)
            end
        end
        pcall(function()
            if getKillerStorage then scanFolder(getKillerStorage()) end
            if getNpcStorage    then scanFolder(getNpcStorage())    end
        end)
    end

    return best, bestDist
end

