-- v9.0 ENHANCED TARGETING SYSTEM
-- Detects hostile NPCs, killer NPCs, and threats to the player.
-- Uses folder detection + name heuristics + Roblox attributes.
-- ════════════════════════════════════════════════════════════

-- Name patterns that strongly suggest an NPC is a "killer" / hostile.
-- Matched case-insensitively against the model name AND humanoid display name.
local KILLER_NAME_PATTERNS = {
    "killer","murder","slasher","monster","demon","enemy","hostile","boss",
    "raider","attacker","predator","alien","zombie","ghost","vampire","werewolf",
    "wendigo","siren","backrooms","nextbot","fnf","horror","threat","saw","jigsaw",
    "freddy","chica","bonnie","jason","michael","slender","jeff","homicidal",
}

-- v9.2: Folder paths where killer NPCs and neutral NPCs are stored.
-- Many popular Roblox horror / killer games keep hostile NPCs in a
-- dedicated workspace folder (e.g. workspace["Killer Storage"]).
-- Checking these folders directly is dramatically faster and more
-- reliable than scanning every workspace descendant.
--
-- We list multiple candidates because different games use different
-- naming conventions; the first match wins.
local KILLER_STORAGE_NAMES = {
    "Killer Storage", "Killers", "KillerStorage", "Killer",
    "Hostile NPCs", "Hostiles", "Hostile", "Enemies", "Enemy Storage",
    "Monsters", "Monster Storage", "Threats", "Bosses", "Slashers",
    -- v9.2.1: added based on real-game explorer reports
    "bots", "Bots", "BOTS",                   -- many killer games use lowercase "bots"
    "Killers", "KillerFolder", "AI", "AIs",
    "Monsters", "Mon", "BossFolder", "Raider",
}
local NPC_STORAGE_NAMES = {
    "NPC Storage", "NPCs", "NPCStorage", "NPC", "Npc", "npcs",
    "Mobs", "Mob Storage", "Creatures", "Characters",
    "AI Storage", "AIStorage", "Bots",
    -- v9.2.1: added based on real-game explorer reports
    "bots", "Bots", "BOTS",
    "Characters", "Actors",
}

-- Returns the first workspace child folder whose name matches `names`.
-- Caches the result so subsequent calls are O(1). Returns nil if no
-- matching folder exists (some games may add it later — we re-scan
-- if the cached folder was destroyed).
-- v9.2.1: case-insensitive matching. Some games use "bots", some "Bots",
-- some "BOTS" — we accept all of them. We list both forms in the names
-- array for clarity, but the case-insensitive scan is the real safety net.
local function makeStorageFinder(names)
    local cached = nil
    -- Pre-build a lowercase lookup set for O(1) case-insensitive matching
    local lowerSet = {}
    for _, n in ipairs(names) do
        lowerSet[string.lower(n)] = true
    end
    return function()
        if cached and cached.Parent then return cached end
        for _, child in ipairs(workspace:GetChildren()) do
            local lower = string.lower(child.Name)
            if lowerSet[lower] then
                cached = child
                return child
            end
        end
        return nil
    end
end

-- Assign to the forward-declared locals (no `local` keyword here —
-- re-declaring would shadow them and break findNearest's references).
getKillerStorage = makeStorageFinder(KILLER_STORAGE_NAMES)
getNpcStorage    = makeStorageFinder(NPC_STORAGE_NAMES)

-- Returns true if `model` is a descendant of any killer-storage folder.
-- This is the FAST path for killer detection.
local function isInKillerStorage(model)
    if not model then return false end
    local kf = getKillerStorage()
    if not kf then return false end
    return model:IsDescendantOf(kf)
end

-- Returns true if `model` is a descendant of any neutral-NPC-storage folder.
local function isInNpcStorage(model)
    if not model then return false end
    local nf = getNpcStorage()
    if not nf then return false end
    return model:IsDescendantOf(nf)
end

-- Returns true if the model's name (or humanoid display name) matches a
-- known killer/hostile pattern. This catches the vast majority of hostile
-- NPC packs found in popular Roblox horror / killer games.
-- v9.2: Also returns true if the model lives inside a known killer-storage
-- folder — this is the most reliable signal.
-- v9.2.1: All Humanoid property accesses are pcalled to prevent a single
-- broken NPC from crashing the entire scan.
local function isHostileNPC(model)
    if not model then return false end
    if isNoobTeam(model) then return false end
    -- Must be a real NPC (Humanoid present, NOT a real player character)
    local h = humanoidOf(model)
    if not h then return false end
    -- Player check (pcall for safety — rare games return weird values)
    local isPlayer = false
    pcall(function() isPlayer = Players:GetPlayerFromCharacter(model) ~= nil end)
    if isPlayer then return false end

    -- FAST PATH: model is inside the killer-storage folder.
    -- This is the most reliable detection method — games that organize
    -- killers into a dedicated folder are detected here.
    if isInKillerStorage(model) then return true end

    -- Check Roblox "Hostile" / "Aggressive" / "Killer" attributes (pcall'd)
    local hostileAttr = false
    pcall(function()
        if model:GetAttribute("Hostile") == true then hostileAttr = true end
        if model:GetAttribute("Aggressive") == true then hostileAttr = true end
        if model:GetAttribute("Killer") == true then hostileAttr = true end
        if h:GetAttribute("Hostile") == true then hostileAttr = true end
    end)
    if hostileAttr then return true end

    -- Name heuristic (fallback for games without a killer-storage folder)
    local nameLower = string.lower(model.Name or "")
    for _, pat in ipairs(KILLER_NAME_PATTERNS) do
        if string.find(nameLower, pat, 1, true) then return true end
    end
    -- Display name heuristic (pcall'd — DisplayName access can fail)
    local dispLower = nil
    pcall(function() dispLower = h.DisplayName and string.lower(h.DisplayName) or nil end)
    if dispLower then
        for _, pat in ipairs(KILLER_NAME_PATTERNS) do
            if string.find(dispLower, pat, 1, true) then return true end
        end
    end
    return false
end

-- Returns true for any non-player, non-noob character (NPC of any kind).
-- v9.2: Includes anything inside an NPC-storage folder.
-- v9.2.1: pcall'd player check + health check (some Humanoids error on read).
local function isNPC(model)
    if not model then return false end
    if isNoobTeam(model) then return false end
    local h = humanoidOf(model)
    if not h then return false end
    local isPlayer = false
    pcall(function() isPlayer = Players:GetPlayerFromCharacter(model) ~= nil end)
    if isPlayer then return false end
    local alive = true
    pcall(function() alive = h.Health > 0 end)
    if not alive then return false end
    -- Fast path: in a known NPC storage folder
    if isInNpcStorage(model) then return true end
    -- Killer storage NPCs are also (hostile) NPCs
    if isInKillerStorage(model) then return true end
    return true
end

-- Internal: scan a single folder (and its descendants) for the nearest
-- matching target. Returns humanoid + distance.
-- v9.2.1: each model check is wrapped in pcall so one broken model
-- (Humanoid in invalid state, missing root part, etc.) doesn't abort
-- the entire scan.
local function scanFolderForNearest(folder, pos, excludeModel, range, filter)
    if not folder then return nil, range end
    local best, bestDist = nil, range
    for _, obj in ipairs(folder:GetDescendants()) do
        pcall(function()
            if obj:IsA("Model") and obj ~= excludeModel and not isNoobTeam(obj) then
                local h = humanoidOf(obj)
                local r = rootOf(obj)
                if h and r and (not filter or filter(obj, h)) then
                    local healthOk = true
                    pcall(function() healthOk = h.Health > 0 end)
                    if healthOk then
                        local d = (r.Position - pos).Magnitude
                        if d < bestDist then bestDist = d; best = h end
                    end
                end
            end
        end)
    end
    return best, bestDist
end

-- Scans for hostile/killer NPCs.
-- v9.2: Checks the killer-storage folder FIRST (fast, reliable), then
-- falls back to a full workspace descendant scan (catches killers that
-- were moved out of the folder or games without one).
-- v9.2.1: Each model check is pcalled to prevent crashes from invalid Humanoids.
local function findNearestKillerNPC(pos, excludeModel, range)
    range = range or 200
    local best, bestDist = nil, range

    -- FAST PATH: scan the killer-storage folder directly.
    local kf = getKillerStorage()
    if kf then
        local kBest, kDist = scanFolderForNearest(kf, pos, excludeModel, range)
        if kBest then
            best, bestDist = kBest, kDist
        end
    end

    -- SLOW PATH (fallback): scan all workspace descendants. This catches
    -- killers in games without a storage folder, OR killers that have
    -- been moved out of the folder by the game logic. We skip anything
    -- we already found in the fast path (bestDist shrinks the search
    -- radius automatically).
    for _, obj in ipairs(workspace:GetDescendants()) do
        pcall(function()
            if obj:IsA("Model") and obj ~= excludeModel and (not best or obj ~= best.Parent) then
                if isHostileNPC(obj) then
                    local h = humanoidOf(obj)
                    local r = rootOf(obj)
                    if h and r then
                        local healthOk = true
                        pcall(function() healthOk = h.Health > 0 end)
                        if healthOk then
                            local d = (r.Position - pos).Magnitude
                            if d < bestDist then bestDist = d; best = h end
                        end
                    end
                end
            end
        end)
    end
    return best, bestDist
end

-- Like findNearest but scans workspace descendants (catches nested NPC packs
-- that the old child-only scan missed). Also accepts a filter predicate.
-- v9.2: Also scans NPC-storage folders directly for speed.
-- v9.2.1: Each model check is pcalled for crash-resistance.
local function findNearestDeep(pos, excludeModel, range, filter)
    range = range or AGGRO_RANGE
    filter = filter or function() return true end
    local best, bestDist = nil, range

    -- FAST PATH: scan known NPC/killer storage folders first.
    local nf = getNpcStorage()
    if nf then
        local nBest, nDist = scanFolderForNearest(nf, pos, excludeModel, range, filter)
        if nBest then best, bestDist = nBest, nDist end
    end
    local kf = getKillerStorage()
    if kf and (not best or bestDist > 0) then
        local kBest, kDist = scanFolderForNearest(kf, pos, excludeModel, bestDist, filter)
        if kBest then best, bestDist = kBest, kDist end
    end

    -- SLOW PATH: full workspace descendant scan.
    for _, obj in ipairs(workspace:GetDescendants()) do
        pcall(function()
            if obj:IsA("Model") and obj ~= excludeModel and not isNoobTeam(obj) then
                local h = humanoidOf(obj)
                local r = rootOf(obj)
                if h and r then
                    local healthOk = true
                    pcall(function() healthOk = h.Health > 0 end)
                    if healthOk and filter(obj, h) then
                        local d = (r.Position - pos).Magnitude
                        if d < bestDist then bestDist = d; best = h end
                    end
                end
            end
        end)
    end
    return best, bestDist
end

-- Returns the nearest threat TO THE PLAYER (not to the noob). Used by
-- guardian noobs to intercept enemies before they reach the player.
local function findNearestThreatToPlayer(playerChar, range)
    range = range or 100
    if not playerChar then return nil, range end
    local pr = rootOf(playerChar)
    if not pr then return nil, range end
    return findNearestDeep(pr.Position, playerChar, range, function(obj, h)
        -- Only things that are actually hostile: killer NPCs OR other players
        return isHostileNPC(obj) or Players:GetPlayerFromCharacter(obj) ~= nil
    end)
end

-- Simple line-of-sight check between two positions.
local function hasLineOfSight(fromPos, toPos)
    local dir = toPos - fromPos
    local dist = dir.Magnitude
    if dist < 0.1 then return true end
    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Exclude
    params.FilterDescendantsInstances = {}
    local result = workspace:Raycast(fromPos, dir.Unit * (dist - 1), params)
    -- If we hit something solid that's NOT just the target's own part, no LOS
    if result and result.Instance then
        -- Hit terrain or a wall -> no LOS
        if result.Instance.Anchored then return false end
    end
    return true
end

-- Global alert network: when a killer NPC is spotted, every allied noob
-- within earshot converges on it. Cached position so we don't spam raycasts.
local KILLER_ALERT_CACHE = nil  -- {pos=Vector3, time=os.clock()}
local function alertAllAlliesOfKiller(killerPos)
    KILLER_ALERT_CACHE = { pos = killerPos, time = os.clock() }
    for _, m in ipairs(workspace:GetChildren()) do
        if m:IsA("Model") and isNoobTeam(m) then
            local mh = humanoidOf(m)
            local mr = rootOf(m)
            if mh and mr and (mr.Position - killerPos).Magnitude < 90 then
                -- Boost speed briefly so allies can respond fast
                mh.WalkSpeed = math.min(mh.WalkSpeed + 8, 60)
            end
        end
    end
end

-- Reads the most recent killer alert (or nil if stale > 8 seconds).
local function getActiveKillerAlert()
    if not KILLER_ALERT_CACHE then return nil end
    if os.clock() - KILLER_ALERT_CACHE.time > 8 then return nil end
    return KILLER_ALERT_CACHE.pos
end

-- ════════════════════════════════════════════════════════════
-- v9.1 PATHFINDING ENGINE
-- Real navigation around obstacles using PathfindingService.
-- Each noob gets its own pathfinder session so old paths are
-- automatically cancelled when a new destination is set.
-- Falls back to direct MoveTo if path computation fails.
-- ════════════════════════════════════════════════════════════
local function makePathfinder(humanoid, rootPart, options)
    options = options or {}
    local agentRadius   = options.agentRadius   or 2.0
    local agentHeight   = options.agentHeight   or 5.0
    local agentCanJump  = options.agentCanJump  ~= false  -- default true
    local agentCanClimb = options.agentCanClimb or false
    local waypointSpace = options.waypointSpacing or 4

    -- Per-noob session token: incrementing this invalidates any running path.
    local currentToken = 0

    -- The last destination we accepted. v9.2.2: used to suppress re-pathing
    -- when the AI loop calls pathTo() with essentially the same destination
    -- every iteration — this was the root cause of "noobs aren't moving".
    -- Without this, every iteration cancels the in-flight walk and starts
    -- a new path computation, so the noob never actually walks anywhere.
    local lastAcceptedDestination = nil
    local REPAT_THRESHOLD = 8  -- studs — don't re-path if dest moved less than this

    -- Track the noob's position for stuck detection
    local lastPosCheckTime = os.clock()
    local lastPosCheck     = rootPart and rootPart.Position or Vector3.new(0,0,0)
    local stuckTimer       = 0  -- seconds since last significant movement

    -- Cancels any in-flight pathfinding loop. Safe to call repeatedly.
    local function cancel()
        currentToken = currentToken + 1
    end

    -- Internal: walk a list of waypoints, returning true if completed.
    -- Stops early if the session token changes (cancelled) or humanoid dies.
    -- v9.2.2: per-waypoint timeout now scales with distance to next waypoint
    -- AND the noob's actual WalkSpeed. Slow noobs (zombie, tank) need more
    -- time per waypoint than fast noobs (sonic, speedster).
    local function walkWaypoints(waypoints, myToken)
        for i = 1, #waypoints do
            if myToken ~= currentToken then return false end
            if not humanoid or not humanoid.Parent or humanoid.Health <= 0 then return false end
            if not rootPart or not rootPart.Parent then return false end

            local wp = waypoints[i]
            local prevWp = waypoints[i-1]

            -- Jump if the path says we need to
            if wp.Action == Enum.PathWaypointAction.Jump then
                humanoid.Jump = true
            end

            -- Issue the per-waypoint MoveTo
            pcall(function() humanoid:MoveTo(wp.Position) end)

            -- Compute a generous per-waypoint timeout based on:
            --   - distance from current position to this waypoint
            --   - the noob's actual WalkSpeed (clamped to a min of 4)
            --   - a 2x safety margin (pathfinding is rarely straight-line)
            local startPos = rootPart.Position
            local distToWp = (startPos - wp.Position).Magnitude
            local walkSpeed = 16
            pcall(function() walkSpeed = math.max(humanoid.WalkSpeed or 16, 4) end)
            -- Time = distance / speed, with safety margin. Min 0.5s, max 4s.
            local maxWait = math.clamp((distToWp / walkSpeed) * 2.5 + 0.3, 0.5, 4.0)

            -- v9.2.2: relax arrival threshold to 5 studs (was 3.5). Tight
            -- thresholds caused noobs to oscillate around the waypoint
            -- without ever "arriving", which burnt the whole timeout.
            local arrivalThreshold = 5.0

            local startTime = os.clock()
            while os.clock() - startTime < maxWait do
                if myToken ~= currentToken then return false end
                if not humanoid or not humanoid.Parent or humanoid.Health <= 0 then return false end
                local currentPos = rootPart.Position
                local dist = (currentPos - wp.Position).Magnitude
                if dist < arrivalThreshold then break end
                task.wait(0.05)
            end
        end
        return true
    end

    -- Public: path to a target position. Fire-and-forget — runs in a
    -- background task so the AI loop can continue. Returns the token
    -- (which can be compared against currentToken later to check if
    -- the path is still active).
    --
    -- v9.2.2 SUPPRESSION: if the new target is within REPAT_THRESHOLD studs
    -- of the last accepted destination, we DO NOT re-path. The currently
    -- running walkWaypoints loop will keep walking toward the (slightly
    -- outdated) destination. This prevents the AI loop from cancelling
    -- the in-flight walk every iteration — which was causing noobs to
    -- never actually move.
    local function pathTo(targetPos)
        if not targetPos then return currentToken end
        if not humanoid or not humanoid.Parent or humanoid.Health <= 0 then return currentToken end
        if not rootPart or not rootPart.Parent then return currentToken end

        -- SUPPRESSION: don't re-path if we're already heading near here.
        -- This is the fix for "noobs aren't moving".
        if lastAcceptedDestination then
            local moved = (targetPos - lastAcceptedDestination).Magnitude
            if moved < REPAT_THRESHOLD then
                -- Already walking toward a nearby destination — let the
                -- existing walkWaypoints loop continue uninterrupted.
                return currentToken
            end
        end

        lastAcceptedDestination = targetPos
        cancel()  -- invalidate previous path
        local myToken = currentToken

        task.spawn(function()
            -- Build the path object fresh each call (cheap) and compute.
            local path
            local ok = pcall(function()
                path = PathfindingService:CreatePath({
                    AgentRadius    = agentRadius,
                    AgentHeight    = agentHeight,
                    AgentCanJump   = agentCanJump,
                    AgentCanClimb  = agentCanClimb,
                    WaypointSpacing= waypointSpace,
                })
                path:ComputePath(rootPart.Position, targetPos)
            end)

            -- If anything went wrong OR no path found, fall back to direct MoveTo.
            -- This keeps the noob at least TRYING to move on flat terrain.
            if not ok or not path or path.Status ~= Enum.PathStatus.Success then
                -- v9.2.2: debug print so user can see what's happening
                if _G.NOOB_TUBE_DEBUG then
                    print("[NoobTube] Path fail, direct MoveTo. ok=", ok, "status=", path and path.Status or "nil")
                end
                if myToken == currentToken and humanoid and humanoid.Parent then
                    pcall(function() humanoid:MoveTo(targetPos) end)
                end
                return
            end

            local waypoints = path:GetWaypoints()
            -- v9.2.2: debug print
            if _G.NOOB_TUBE_DEBUG then
                print("[NoobTube] Path computed: "..#waypoints.." waypoints, dist="..
                    string.format("%.1f", (rootPart.Position - targetPos).Magnitude).." studs")
            end
            -- If only 1 waypoint (already at destination), nothing to walk.
            if #waypoints < 2 then
                if myToken == currentToken and humanoid and humanoid.Parent then
                    pcall(function() humanoid:MoveTo(targetPos) end)
                end
                return
            end

            walkWaypoints(waypoints, myToken)
        end)

        return myToken
    end

    -- Direct MoveTo passthrough — used for very short moves (strafe, flank)
    -- where pathfinding overhead isn't worth it. Still cancels any in-flight
    -- path so the noob doesn't fight itself.
    -- v9.2.2: also clears lastAcceptedDestination so the next pathTo call
    -- will actually re-path (strafing changes position rapidly).
    local function directMoveTo(targetPos)
        cancel()
        lastAcceptedDestination = nil  -- force re-path on next pathTo
        if not humanoid or not humanoid.Parent then return end
        pcall(function() humanoid:MoveTo(targetPos) end)
    end

    -- Force a re-path on the next pathTo call. Useful when the AI detects
    -- the noob is stuck and wants to try a fresh path.
    local function forceRepath()
        lastAcceptedDestination = nil
        cancel()
    end

    -- v9.2.2 STUCK DETECTOR: call this every frame (or every AI iteration).
    -- If the noob hasn't moved more than 1.5 studs in 2 seconds, force a
    -- re-path. This catches cases where the pathfinder yielded a bad path
    -- or the noob clipped into geometry.
    local function checkStuck()
        if not rootPart or not rootPart.Parent then return end
        if not humanoid or not humanoid.Parent or humanoid.Health <= 0 then return end
        local now = os.clock()
        local currentPos = rootPart.Position
        local moved = (currentPos - lastPosCheck).Magnitude
        local dt = now - lastPosCheckTime
        if dt < 0.5 then return end  -- only check every 0.5s
        if moved < 1.5 then
            stuckTimer = stuckTimer + dt
            if stuckTimer >= 2.0 then
                -- Stuck for 2+ seconds — force a re-path
                forceRepath()
                stuckTimer = 0
                lastPosCheck = currentPos
                lastPosCheckTime = now
            end
        else
            -- Moving fine — reset
            stuckTimer = 0
            lastPosCheck = currentPos
            lastPosCheckTime = now
        end
    end

    return {
        pathTo        = pathTo,
        directMoveTo  = directMoveTo,
        cancel        = cancel,
        forceRepath   = forceRepath,
        checkStuck    = checkStuck,
        getLastDestination = function() return lastAcceptedDestination end,
        isMoving = function()
            return currentToken > 0  -- always true after first pathTo; placeholder
        end,
    }
end

local function colorModel(model, color, material)
    for _, p in pairs(model:GetDescendants()) do
        if p:IsA("BasePart") then
            p.Color = color
            if material then p.Material = material end
        end
    end
end

local function addEffect(model, effectClass, color)
    for _, p in pairs(model:GetDescendants()) do
        if p:IsA("BasePart") then
            local e = Instance.new(effectClass)
            if color and e:FindFirstChildOfClass("Color3Value") == nil then
                pcall(function() e.Color = color end)
            end
            e.Parent = p
        end
    end
end

local function makeBullet(origin, target, speed, size, color, damage, radius)
    local dir = (target - origin).Unit
    local b = Instance.new("Part")
    b.Size        = size or Vector3.new(0.4, 0.4, 1.5)
    b.Color       = color or Color3.fromRGB(255,200,0)
    b.Material    = Enum.Material.Neon
    b.CFrame      = CFrame.new(origin, origin + dir)
    b.CanCollide  = false
    b.Parent      = workspace
    local bv = Instance.new("BodyVelocity")
    bv.Velocity   = dir * (speed or 120)
    bv.MaxForce   = Vector3.new(1e4,1e4,1e4)
    bv.Parent     = b
    Debris:AddItem(b, 3)
    local bulletHit = false -- debounce: prevent multiple hits per bullet
    local function explodeBullet()
        if bulletHit then return end
        bulletHit = true
        if b and b.Parent then
            if radius then
                local exp = Instance.new("Explosion")
                exp.Position      = b.Position
                exp.BlastRadius   = radius
                exp.BlastPressure = 3e5
                exp.Parent        = workspace
            end
            b:Destroy()
        end
    end
    if damage then
        b.Touched:Connect(function(hit)
            if bulletHit then return end
            local hitModel = hit.Parent
            local h = hitModel and humanoidOf(hitModel)
            if h and not isNoobTeam(hitModel) then
                h:TakeDamage(damage)
                explodeBullet()
            elseif hit.Anchored and hit.Name ~= "HumanoidRootPart" then
                -- also explode on terrain/anchored parts if radius shot
                if radius then explodeBullet() end
            end
        end)
    end
    if radius then
        -- Fallback: explode at end of life if nothing was hit
        task.delay(2.8, explodeBullet)
    end
    return b
end

-- ── Standard Animation System (replaces IK Feet) ──────────
-- Plays standard Roblox R6 animations (idle/walk/run/jump/fall/swim/climb/sit)
-- using the Animator. Adapted from the user's Animate script.
-- Animation IDs from the provided script (includes custom jump = slash anim).
local function setupNoobAnims(model, humanoid, rootPart)
    -- Destroy default Animate script if present
    local animate = model:FindFirstChild("Animate")
    if animate then animate:Destroy() end

    -- Ensure Animator exists (required for loading animations)
    local animator = humanoid:FindFirstChildOfClass("Animator")
    if not animator then
        animator = Instance.new("Animator")
        animator.Parent = humanoid
    end

    -- Animation IDs (from the user's Animate script)
    local animIds = {
        idle = {
            "http://www.roblox.com/asset/?id=507766666",
            "http://www.roblox.com/asset/?id=507766951",
            "http://www.roblox.com/asset/?id=507766388",
        },
        walk = {
            "http://www.roblox.com/asset/?id=507777826",
        },
        run = {
            "http://www.roblox.com/asset/?id=507767714",
        },
        jump = {
            "http://www.roblox.com/asset/?id=849648317", -- Custom: slash animation as jump
        },
        fall = {
            "http://www.roblox.com/asset/?id=507767968",
        },
        swim = {
            "http://www.roblox.com/asset/?id=507784897",
        },
        swimidle = {
            "http://www.roblox.com/asset/?id=507785072",
        },
        climb = {
            "http://www.roblox.com/asset/?id=507765644",
        },
        sit = {
            "http://www.roblox.com/asset/?id=507768133",
        },
    }

    -- Cache loaded animation tracks
    local tracks = {}
    local currentTrack = nil
    local currentName = ""
    local isDead = false

    -- Load an animation by name (picks random from the list if multiple)
    local function loadAnim(name)
        if tracks[name] then return tracks[name] end
        local ids = animIds[name]
        if not ids or #ids == 0 then return nil end
        local id = ids[math.random(1, #ids)]
        local anim = Instance.new("Animation")
        anim.AnimationId = id
        local track
        local ok = pcall(function()
            track = animator:LoadAnimation(anim)
        end)
        anim:Destroy()
        if ok and track then
            tracks[name] = track
            return track
        end
        return nil
    end

    -- Play an animation by name with fade transition
    local function playAnim(name, fadeTime)
        fadeTime = fadeTime or 0.1
        if isDead then return end
        if currentName == name and currentTrack then return end
        -- Stop current
        if currentTrack then
            pcall(function() currentTrack:Stop(fadeTime) end)
        end
        -- Load and play new
        local track = loadAnim(name)
        if track then
            pcall(function()
                track:Play(fadeTime)
                -- Set up keyframe looping
                track.KeyframeReached:Connect(function(frameName)
                    if frameName == "End" and track and track.Parent then
                        if name == "walk" or name == "idle" or name == "run"
                           or name == "swim" or name == "swimidle"
                           or name == "climb" then
                            track.TimePosition = 0
                        end
                    end
                end)
            end)
            currentTrack = track
            currentName = name
        end
    end

    -- Connect humanoid state events (from the standard Animate script)
    humanoid.Running:Connect(function(speed)
        if speed > 0.1 then
            playAnim("walk", 0.1)
            -- Adjust animation speed based on WalkSpeed
            if currentTrack then
                pcall(function() currentTrack:AdjustSpeed(math.max(speed / 16, 0.5)) end)
            end
        else
            playAnim("idle", 0.1)
        end
    end)

    humanoid.Jumping:Connect(function()
        playAnim("jump", 0.1)
    end)

    humanoid.FreeFalling:Connect(function()
        playAnim("fall", 0.2)
    end)

    humanoid.Seated:Connect(function()
        playAnim("sit", 0.5)
    end)

    humanoid.Swimming:Connect(function(speed)
        if speed > 1 then
            playAnim("swim", 0.4)
            if currentTrack then
                pcall(function() currentTrack:AdjustSpeed(speed / 10) end)
            end
        else
            playAnim("swimidle", 0.4)
        end
    end)

    humanoid.Climbing:Connect(function(speed)
        playAnim("climb", 0.1)
        if currentTrack then
            pcall(function() currentTrack:AdjustSpeed(speed / 5) end)
        end
    end)

    humanoid.Died:Connect(function()
        isDead = true
        if currentTrack then
            pcall(function() currentTrack:Stop() end)
        end
    end)

    -- Start with idle animation
    playAnim("idle", 0.1)
end

-- ── Classic Animation System ───────────────────────────────
-- Uses Motor6D SetDesiredAngle (old-school R6 animation style).
-- Adapted from the user's "classic" animation script.
-- This uses sine-wave limb oscillation instead of animation tracks.
local function setupClassicAnims(model, humanoid, rootPart)
    -- Destroy default Animate script if present
    local animate = model:FindFirstChild("Animate")
    if animate then animate:Destroy() end

    local torso = model:FindFirstChild("Torso")
    if not torso then return end

    local RightShoulder = torso:FindFirstChild("Right Shoulder")
    local LeftShoulder = torso:FindFirstChild("Left Shoulder")
    local RightHip = torso:FindFirstChild("Right Hip")
    local LeftHip = torso:FindFirstChild("Left Hip")
    local Neck = torso:FindFirstChild("Neck")

    if not RightShoulder or not LeftShoulder or not RightHip or not LeftHip then return end

    local pose = "Standing"
    local toolAnim = "None"
    local toolAnimTime = 0
    local jumpMaxLimbVelocity = 0.75
    local isDead = false

    -- State handlers
    humanoid.Running:Connect(function(speed)
        if speed > 0.1 then pose = "Running" else pose = "Standing" end
    end)
    humanoid.Died:Connect(function() pose = "Dead"; isDead = true end)
    humanoid.Jumping:Connect(function() pose = "Jumping" end)
    humanoid.Climbing:Connect(function() pose = "Climbing" end)
    humanoid.GettingUp:Connect(function() pose = "GettingUp" end)
    humanoid.FreeFalling:Connect(function() pose = "FreeFall" end)
    humanoid.FallingDown:Connect(function() pose = "FallingDown" end)
    humanoid.Seated:Connect(function() pose = "Seated" end)
    humanoid.PlatformStanding:Connect(function() pose = "PlatformStanding" end)
    humanoid.Swimming:Connect(function(speed)
        if speed > 0 then pose = "Running" else pose = "Standing" end
    end)

    -- Jump pose: arms up
    local function moveJump()
        pcall(function() RightShoulder.MaxVelocity = jumpMaxLimbVelocity end)
        pcall(function() LeftShoulder.MaxVelocity = jumpMaxLimbVelocity end)
        pcall(function() RightShoulder:SetDesiredAngle(3.14) end)
        pcall(function() LeftShoulder:SetDesiredAngle(-3.14) end)
        pcall(function() RightHip:SetDesiredAngle(0) end)
        pcall(function() LeftHip:SetDesiredAngle(0) end)
    end

    -- FreeFall pose: same as jump
    local function moveFreeFall()
        pcall(function() RightShoulder.MaxVelocity = jumpMaxLimbVelocity end)
        pcall(function() LeftShoulder.MaxVelocity = jumpMaxLimbVelocity end)
        pcall(function() RightShoulder:SetDesiredAngle(3.14) end)
        pcall(function() LeftShoulder:SetDesiredAngle(-3.14) end)
        pcall(function() RightHip:SetDesiredAngle(0) end)
        pcall(function() LeftHip:SetDesiredAngle(0) end)
    end

    -- Sit pose
    local function moveSit()
        pcall(function() RightShoulder.MaxVelocity = 0.15 end)
        pcall(function() LeftShoulder.MaxVelocity = 0.15 end)
        pcall(function() RightShoulder:SetDesiredAngle(3.14 / 2) end)
        pcall(function() LeftShoulder:SetDesiredAngle(-3.14 / 2) end)
        pcall(function() RightHip:SetDesiredAngle(3.14 / 2) end)
        pcall(function() LeftHip:SetDesiredAngle(-3.14 / 2) end)
    end

    -- Main move loop (sine-wave limb oscillation)
    task.spawn(function()
        local startTime = os.clock()
        while isAlive(humanoid) and model and model.Parent do
            if isDead then break end
            local time = os.clock() - startTime

            if pose == "Jumping" then
                moveJump()
                task.wait(0.1)
            elseif pose == "FreeFall" then
                moveFreeFall()
                task.wait(0.1)
            elseif pose == "Seated" then
                moveSit()
                task.wait(0.1)
            else
                local amplitude, frequency, climbFudge = 0.1, 1, 0

                if pose == "Running" then
                    pcall(function()
                        if RightShoulder.CurrentAngle > 1.5 or RightShoulder.CurrentAngle < -1.5 then
                            RightShoulder.MaxVelocity = jumpMaxLimbVelocity
                        else
                            RightShoulder.MaxVelocity = 0.15
                        end
                    end)
                    pcall(function()
                        if LeftShoulder.CurrentAngle > 1.5 or LeftShoulder.CurrentAngle < -1.5 then
                            LeftShoulder.MaxVelocity = jumpMaxLimbVelocity
                        else
                            LeftShoulder.MaxVelocity = 0.15
                        end
                    end)
                    amplitude = 1
                    frequency = 9
                elseif pose == "Climbing" then
                    pcall(function() RightShoulder.MaxVelocity = 0.5 end)
                    pcall(function() LeftShoulder.MaxVelocity = 0.5 end)
                    amplitude = 1
                    frequency = 9
                    climbFudge = 3.14
                end

                local desiredAngle = amplitude * math.sin(time * frequency)

                pcall(function() RightShoulder:SetDesiredAngle(desiredAngle + climbFudge) end)
                pcall(function() LeftShoulder:SetDesiredAngle(desiredAngle - climbFudge) end)
                pcall(function() RightHip:SetDesiredAngle(-desiredAngle) end)
                pcall(function() LeftHip:SetDesiredAngle(-desiredAngle) end)

                task.wait(0.1)
            end
        end
    end)
end

-- ── Spawn Core ──────────────────────────────────────────────
local function spawnNoob(characterType, _depth)
    _depth = _depth or 0

    -- Global cap
    if #activeNoobs >= MAX_NOOBS then return end

    local character = player.Character
    if not character then return end
    local playerRoot = rootOf(character)
    if not playerRoot then return end

    -- Build model from classic noob description
    local ok, model
    ok, model = pcall(function()
        local d = Players:GetHumanoidDescriptionFromUserId(1)
        return Players:CreateHumanoidModelFromDescription(d, Enum.HumanoidRigType.R6)
    end)
    if not ok or not model then return end

    local h   = humanoidOf(model)
    local rp  = rootOf(model)
    local head = model:FindFirstChild("Head")
    if not h or not rp then model:Destroy(); return end

    model.Name          = characterType.."_"..math.random(1000,9999)
    model.PrimaryPart   = rp
    h.DisplayName       = rndName()

    -- ── Team assignment: BoolValue tag + real Roblox Team object ──
    -- BoolValue tag: fast lookup used by our targeting/bullet code
    local teamTag = Instance.new("BoolValue")
    teamTag.Name   = "IsNoobTeam"
    teamTag.Value  = true
    teamTag.Parent = model
    -- Real Roblox Team: Humanoid.Team prevents native friendly-fire,
    -- shows team colour on the leaderboard, and works with any other
    -- game systems that respect the Teams service.
    if noobTeam then
        pcall(function()
            h.Team      = noobTeam
            h.TeamColor = NOOB_TEAM_COLOR  -- bright yellow = unmistakable
        end)
    end

    -- Anchor → parent → position → unanchor (prevents fall-through on spawn)
    for _, p in pairs(model:GetDescendants()) do
        if p:IsA("BasePart") then p.Anchored = true end
    end
    model.Parent = workspace
    local spawnCF = playerRoot.CFrame * CFrame.new(0,0,-6)
    model:SetPrimaryPartCFrame(spawnCF)
    for _, p in pairs(model:GetDescendants()) do
        if p:IsA("BasePart") then p.Anchored = false end
    end

    -- ── Apply Anims + Ragdoll Arms ─────────────────────────
    -- v9.3.2: 30% chance to use classic (Motor6D SetDesiredAngle) anims,
    -- 70% chance to use standard (Animator-based) anims.
    if math.random() < 0.3 then
        setupClassicAnims(model, h, rp)
    else
        setupNoobAnims(model, h, rp)
    end

    -- ── v9.1 Pathfinding: every noob gets its own pathfinder ──
    -- `pathTo(targetPos)` — long-distance navigation around obstacles.
    -- `directMoveTo(targetPos)` — short-range strafe/flank (no pathfinding overhead).
    local _pf = makePathfinder(h, rp)
    local pathTo       = _pf.pathTo
    local directMoveTo = _pf.directMoveTo
    local cancelPath   = _pf.cancel
    local checkStuck   = _pf.checkStuck

    -- v9.2.2: Background stuck-detector. Runs in parallel with the AI
    -- loop and forces a re-path if the noob hasn't moved in 2 seconds.
    -- This catches cases where pathfinding yielded a bad path or the
    -- noob clipped into geometry. Without this, a stuck noob would
    -- sit forever because the AI loop's pathTo() call would be suppressed.
    task.spawn(function()
        while isAlive(h) and rp.Parent do
            checkStuck()
            task.wait(0.5)
        end
    end)

    -- Track and auto-cleanup
    table.insert(activeNoobs, model)
    Debris:AddItem(model, NOOB_LIFETIME)
    model.AncestryChanged:Connect(function()
        for i, m in ipairs(activeNoobs) do
            if m == model then table.remove(activeNoobs, i); break end
        end
        cancelPath()  -- stop pathfinding when the noob is removed
    end)

    -- ── AI helper: patrol if no target ──────────────────────
    -- Uses pathfinding so the noob actually wanders around instead of
    -- getting stuck on the first wall it bumps into.
    -- v9.2.2: PATROL DESTINATION PERSISTENCE. The old patrol() picked a
    -- NEW random destination every iteration, which defeated the pathfinder's
    -- suppression (new random dest is always >8 studs from the last). Now
    -- patrol remembers its destination and only picks a new one when the
    -- noob gets within 12 studs of it (or after a 15s timeout).
    local _patrolDest = nil
    local _patrolTime = 0
    local function patrol()
        if not isAlive(h) or not rp.Parent then return end
        local now = os.clock()
        -- Pick a new destination if:
        --   - we don't have one yet
        --   - we've reached the current one (within 12 studs)
        --   - we've been walking for >15s (timeout — probably stuck)
        local needNewDest = true
        if _patrolDest then
            local dist = (rp.Position - _patrolDest).Magnitude
            if dist > 12 and (now - _patrolTime) < 15 then
                needNewDest = false
            end
        end
        if needNewDest then
            _patrolDest = rp.Position + Vector3.new(math.random(-60,60),0,math.random(-60,60))
            _patrolTime = now
        end
        pathTo(_patrolDest)
    end

    -- ── AI helper: chase & act ───────────────────────────────
    -- Long-distance chase uses pathfinding; close-range still works because
    -- pathfinding's per-waypoint MoveTo is essentially the same call.
    local function chaseAndAct(range, closeDist, onClose)
        local target, dist = findNearest(rp.Position, model, range)
        if target then
            local tp = posOf(target.Parent)
            if tp then
                pathTo(tp)
                if dist < closeDist and onClose then onClose(target, dist) end
            end
            return true
        end
        patrol()
        return false
    end

    -- ── AI helper: strafe around target at a set orbit radius ─
    -- Strafe uses directMoveTo (short-range, no pathfinding overhead) so the
    -- orbit stays smooth. The pathfinder would re-path every frame here which
    -- would cause stuttering.
    local function strafeAround(targetPos, orbitRadius, angleOffset)
        angleOffset = angleOffset or 0
        local angle = math.atan2(rp.Position.Z - targetPos.Z, rp.Position.X - targetPos.X) + angleOffset
        local dest  = targetPos + Vector3.new(math.cos(angle)*orbitRadius, 0, math.sin(angle)*orbitRadius)
        directMoveTo(dest)
    end

    -- ── AI helper: flank from a side angle ──────────────────
    -- Flank uses directMoveTo for the same reason as strafe (short tactical move).
    local function flankTarget(targetPos, flankDist)
        local perpAngle = math.atan2(rp.Position.Z - targetPos.Z, rp.Position.X - targetPos.X) + math.pi/2
        local dest = targetPos + Vector3.new(math.cos(perpAngle)*flankDist, 0, math.sin(perpAngle)*flankDist)
        directMoveTo(dest)
    end

    -- ── AI helper: alert nearby noob allies ─────────────────
    local function alertNearbyAllies(alertRange, speedBoost)
        for _, m in pairs(workspace:GetChildren()) do
            if m:IsA("Model") and m ~= model and isNoobTeam(m) then
                local mr = rootOf(m)
                if mr and (mr.Position - rp.Position).Magnitude < alertRange then
                    local mh = humanoidOf(m)
                    if mh then mh.WalkSpeed = math.min(mh.WalkSpeed + speedBoost, 60) end
                end
            end
        end
    end

    -- ═══════════════════════════════════════════════════════════
    -- v9.0 GUARDIAN AI HELPERS
    -- Used by defensive noobs (bodyguard, shieldmaiden, tank_escort, etc.)
    -- and as a fallback by every noob when no enemy is near them.
    -- ═══════════════════════════════════════════════════════════

    -- Returns the player's current character (or nil if dead/loading).
    local function getPlayerChar()
        local char = player.Character
        if char and char.Parent then return char end
        return nil
    end

    -- Returns the player's root position, or nil if unavailable.
    local function getPlayerPos()
        local c = getPlayerChar()
        local r = c and rootOf(c)
        return r and r.Position or nil
    end

    -- If the noob strays too far from the player, walk back toward them.
    -- Returns true if it is currently returning to the player.
    -- Uses pathfinding so the noob can navigate back through walls/corridors.
    local function returnToPlayer(maxDistance)
        maxDistance = maxDistance or 35
        if not isAlive(h) or not rp.Parent then return false end
        local ppos = getPlayerPos()
        if not ppos then return false end
        local d = (ppos - rp.Position).Magnitude
        if d > maxDistance then
            pathTo(ppos + Vector3.new(math.random(-4,4), 0, math.random(-4,4)))
            return true
        end
        return false
    end

    -- Find the nearest threat that is approaching the PLAYER (within `range`
    -- studs of the player). Returns humanoid + distance.
    local function findThreatToPlayer(range)
        range = range or 80
        local c = getPlayerChar()
        return findNearestThreatToPlayer(c, range)
    end

    -- Intercept behavior: move to a position BETWEEN the threat and the player,
    -- then attack the threat when in range. Returns true if currently intercepting.
    -- Uses pathfinding for the intercept move so body-blocks actually work
    -- even when the player is inside a building.
    local function interceptThreatToPlayer(range, attackRange, attackFn)
        range        = range or 80
        attackRange  = attackRange or 8
        local ppos = getPlayerPos()
        if not ppos then return false end
        local threat, tdist = findThreatToPlayer(range)
        if not threat then return false end
        local tRoot = rootOf(threat.Parent)
        if not tRoot then return false end
        local tp = tRoot.Position
        -- Position halfway between player and threat (body-block)
        local interceptPos = (ppos + tp) / 2
        local myDist = (tp - rp.Position).Magnitude
        if myDist > attackRange then
            pathTo(interceptPos)
        else
            -- In attack range: strike the threat (close-range, direct MoveTo)
            directMoveTo(tp)
            if attackFn then attackFn(threat, myDist) end
        end
        return true
    end

    -- Broadcasts a killer-NPC alert to every allied noob.
    local function alertKillerNearby(killerPos)
        alertAllAlliesOfKiller(killerPos)
    end

    -- Convenience: returns true if a killer NPC is currently within `range`
    -- of the noob (uses cached + fresh check). Also alerts allies when found.
    local function scanForKillers(range)
        range = range or 150
        local k, kd = findNearestKillerNPC(rp.Position, model, range)
        if k then
            local kRoot = rootOf(k.Parent)
            if kRoot then
                alertKillerNearby(kRoot.Position)
                safeChat(head, "KILLER DETECTED! Engaging!", Enum.ChatColor.Red)
            end
        end
        return k, kd
    end

    -- ════════════════════════════════════════════════════════
    --  NOOB BEHAVIOURS
    -- ════════════════════════════════════════════════════════

    -- SONIC NOOB ──────────────────────────────────────────────
    if characterType == "sonic_noob" then
        h.WalkSpeed = 110; h.JumpPower = 120
        colorModel(model, Color3.fromRGB(0,100,255), Enum.Material.Neon)
        local trail = Instance.new("Trail")
        local a0 = Instance.new("Attachment",rp)
        local a1 = Instance.new("Attachment",rp); a1.Position = Vector3.new(0,-2,0)
        trail.Attachment0 = a0; trail.Attachment1 = a1
        trail.Color = ColorSequence.new(Color3.fromRGB(0,150,255))
        trail.Lifetime = 0.4; trail.Parent = rp
        local phrases = {"Gotta go fast!","You're too slow!","Speed is key!","Sonic speed!","I'm outta here!","SUPERSONIC!","Catch me if you can!"}
        local orbitAngle = 0
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local target, dist = findNearest(rp.Position, model, 120)
                if target then
                    local tp = posOf(target.Parent)
                    if tp then
                        if dist > 40 then
                            -- Dash straight in at insane speed
                            safeChat(head, "DASH!", Enum.ChatColor.Cyan)
                            pathTo(tp)
                        else
                            -- Orbital circling with increasing speed
                            orbitAngle = orbitAngle + 0.4
                            strafeAround(tp, 20, orbitAngle)
                            if dist < 8 then
                                target:TakeDamage(10) -- spin-dash hit
                                safeChat(head, phrases[math.random(1,#phrases)], Enum.ChatColor.Cyan)
                            end
                        end
                    end
                else
                    safeChat(head, phrases[math.random(1,#phrases)], Enum.ChatColor.Cyan)
                    patrol()
                end
                task.wait(0.15)
            end
        end)

    -- FLYING NOOB ─────────────────────────────────────────────
    elseif characterType == "flying_noob" then
        h.WalkSpeed = 0
        colorModel(model, Color3.fromRGB(255,255,200))
        local bv = Instance.new("BodyVelocity"); bv.MaxForce = Vector3.new(4e3,4e3,4e3); bv.Parent = rp
        local bg = Instance.new("BodyGyro");    bg.MaxTorque = Vector3.new(4e3,4e3,4e3); bg.Parent = rp
        local msgs = {"Look at me fly!","Up here!","The sky is mine!","Wheeeee!"}
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                safeChat(head, msgs[math.random(1,#msgs)], Enum.ChatColor.Yellow)
                local target = findNearest(rp.Position, model, 80)
                local dest
                if target then
                    local tp = posOf(target.Parent)
                    dest = tp and (tp + Vector3.new(0,35,0))
                end
                dest = dest or (rp.Position + Vector3.new(math.random(-80,80),math.random(20,70),math.random(-80,80)))
                local dir = (dest - rp.Position).Unit
                bv.Velocity = dir * 28
                bg.CFrame   = CFrame.new(rp.Position, dest)
                task.wait(2.5)
            end
        end)

    -- ZOMBIE (Enhanced v3) ─────────────────────────────────────
    elseif characterType == "zombie" then
        h.WalkSpeed = 8; h.MaxHealth = 180; h.Health = 180
        -- Rotten green-brown coloration
        for _, p in pairs(model:GetDescendants()) do
            if p:IsA("BasePart") then
                -- Randomize each limb slightly for a rotten look
                local r = math.random(-15,15)
                p.Color = Color3.fromRGB(75+r, 115+r, 55+r)
                p.Material = Enum.Material.Slate
            end
        end
        -- Add drippy smoke aura
        local zombieSmoke = Instance.new("Smoke")
        zombieSmoke.Color = Color3.fromRGB(80,120,60)
        zombieSmoke.Opacity = 0.3
        zombieSmoke.RiseVelocity = 0.5
        zombieSmoke.Size = 6
        zombieSmoke.Parent = rp
        -- Glowing red eyes
        if head then
            local eyeGlow = Instance.new("PointLight")
            eyeGlow.Color = Color3.fromRGB(255,0,0)
            eyeGlow.Brightness = 2
            eyeGlow.Range = 8
            eyeGlow.Parent = head
        end
        -- Zombie state: idle, roaming, alerted, enraged
        local zState = "idle"
        local alertTimer = 0
        local infectionCount = 0
        local brainPhrases = {
            "Braaaains...","Must... eat...","Urrghhhh...","Hungry...","Brains!",
            "Grrrr...","Raaauugh...","Flesh...","So... hungry...","Join... us...",
            "More... brains...","Cannot... stop...","Infection... spreads..."
        }
        local alertPhrases = {
            "RAAAAGH!","THERE!","FRESH MEAT!","I SEE YOU!","BRAAAAINS!",
            "ALIVE!","COMING!","CATCH!","HUNT!"
        }
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local target, dist = findNearest(rp.Position, model, 60)
                -- State machine
                if target then
                    local tp = posOf(target.Parent)
                    if tp then
                        -- Shambling pursuit with occasional lunge
                        if zState ~= "enraged" and dist < 60 and dist > 30 then
                            zState = "alerted"
                            alertTimer = 8
                            safeChat(head, alertPhrases[math.random(1,#alertPhrases)], Enum.ChatColor.Red)
                            -- Agro chain: alert nearby zombies
                            for _, m in pairs(workspace:GetChildren()) do
                                if m:IsA("Model") and m ~= model and m.Name:find("zombie") then
                                    local mh = humanoidOf(m); local mr = rootOf(m)
                                    if mh and mr and (mr.Position - rp.Position).Magnitude < 40 then
                                        mh.WalkSpeed = math.min(mh.WalkSpeed + 6, 22)
                                    end
                                end
                            end
                        end
                        -- Close range: lunge attack with knockback
                        if dist < 10 then
                            zState = "enraged"
                            h.WalkSpeed = 22
                            pathTo(tp)
                            task.wait(0.3)
                            if isAlive(h) and rp.Parent and dist < 8 then
                                target:TakeDamage(8)
                                safeChat(head, "GRAAAH!", Enum.ChatColor.Red)
                                -- Infection: chance to spawn a new zombie from victim
                                infectionCount = infectionCount + 1
                                if infectionCount >= 3 and _depth < 1 then -- only depth-0 zombies can infect (spawn depth-1)
                                    infectionCount = 0
                                    safeChat(head, "Join... us...", Enum.ChatColor.Green)
                                    task.wait(0.5)
                                    spawnNoob("zombie", _depth + 1)
                                end
                            end
                            task.wait(1)
                            h.WalkSpeed = 8
                            zState = "alerted"
                        elseif dist < 30 then
                            zState = "alerted"
                            h.WalkSpeed = 14
                            pathTo(tp)
                            -- Groaning while chasing
                            safeChat(head, brainPhrases[math.random(1,#brainPhrases)], Enum.ChatColor.Green)
                        else
                            -- Far away: shambling approach
                            zState = "roaming"
                            h.WalkSpeed = 8
                            pathTo(tp)
                            safeChat(head, brainPhrases[math.random(1,#brainPhrases)], Enum.ChatColor.Green)
                        end
                    end
                else
                    -- No target: idle wander
                    if alertTimer > 0 then
                        alertTimer = alertTimer - 1
                        zState = "alerted"
                        h.WalkSpeed = 12
                    else
                        zState = "idle"
                        h.WalkSpeed = 6
                    end
                    -- Occasional idle groan
                    if math.random() > 0.6 then
                        safeChat(head, brainPhrases[math.random(1,#brainPhrases)], Enum.ChatColor.Green)
                    end
                    patrol()
                end
                -- Feign death: play dead when low health, then reanimate
                if h.Health < h.MaxHealth * 0.15 and h.Health > 0 and math.random() > 0.7 then
                    safeChat(head, "...", Enum.ChatColor.Green)
                    h.WalkSpeed = 0
                    for _, p in pairs(model:GetDescendants()) do
                        if p:IsA("BasePart") then p.Transparency = 0.4 end
                    end
                    task.wait(math.random(3,6))
                    if isAlive(h) then
                        h.Health = math.min(h.Health + 40, h.MaxHealth * 0.5)
                        h.WalkSpeed = 16
                        safeChat(head, "RRAAAUGH!", Enum.ChatColor.Red)
                        for _, p in pairs(model:GetDescendants()) do
                            if p:IsA("BasePart") then p.Transparency = 0 end
                        end
                    end
                end
                task.wait(1.2)
            end
        end)

    -- KNIGHT ───────────────────────────────────────────────────
    elseif characterType == "knight" then
        h.WalkSpeed = 18; h.MaxHealth = 200; h.Health = 200
        colorModel(model, Color3.fromRGB(180,180,180), Enum.Material.Metal)
        local state = "patrol"
        local chargeReady = true
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local target, dist = findNearest(rp.Position, model, 60)
                if target and dist < 60 then
                    local tp = posOf(target.Parent)
                    if tp then
                        state = "combat"
                        if dist > 25 and chargeReady then
                            -- Charge: sprint in for big hit
                            chargeReady = false
                            h.WalkSpeed = 40
                            safeChat(head, "FOR THE KING! ⚔️", Enum.ChatColor.Red)
                            pathTo(tp)
                            task.wait(0.6)
                            h.WalkSpeed = 18
                            local _, recheckDist = findNearest(rp.Position, model, 10)
                            if recheckDist and recheckDist < 10 then
                                target:TakeDamage(25)
                            end
                            task.delay(8, function() chargeReady = true end)
                        elseif dist < 10 then
                            target:TakeDamage(12)
                            safeChat(head, "En garde!", Enum.ChatColor.Red)
                        elseif dist < 20 then
                            -- Flank to attack from the side
                            flankTarget(tp, 12)
                            safeChat(head, "Guarding...", Enum.ChatColor.Gray)
                        else
                            pathTo(tp)
                        end
                    end
                else
                    state = "patrol"
                    safeChat(head, "Guarding...", Enum.ChatColor.Gray)
                    patrol()
                end
                task.wait(1.5)
            end
        end)

    -- FAKE PLAYER ──────────────────────────────────────────────
    elseif characterType == "fake_player" then
        local phrases   = {"Just passing by!","What a beautiful day!","I love this game!","Nice weather!","Anyone want to be friends?","So much fun!","GG everyone!","This game is so good!","wait for me guys","lol noob"}
        local threatened = {"AHHH RUN!","omg omg omg","wait WHAT","bruh","not cool bro!","help!!","nope nope nope","ABORT MISSION"}
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local target, dist = findNearest(rp.Position, model, 40)
                if target and dist < 35 then
