        -- Camera shake helper (client-side since this is a LocalScript)
        local function shakeCamera(intensity, duration)
            local camera = workspace.CurrentCamera
            local elapsed = 0
            local conn
            conn = RunService.RenderStepped:Connect(function(dt)
                elapsed = elapsed + dt
                if elapsed >= duration then conn:Disconnect(); return end
                local fade = 1 - (elapsed / duration)
                camera.CFrame = camera.CFrame * CFrame.Angles(
                    math.rad(math.random(-intensity, intensity) * fade),
                    math.rad(math.random(-intensity, intensity) * fade),
                    math.rad(math.random(-intensity, intensity) * fade)
                )
            end)
        end
        -- Screen flash helper
        local function screenFlash(color, duration)
            local playerGui = player:FindFirstChildOfClass("PlayerGui")
            if not playerGui then return end
            local screenGui = Instance.new("ScreenGui")
            screenGui.IgnoreGuiInset = true
            screenGui.Parent = playerGui
            local frame = Instance.new("Frame")
            frame.Size = UDim2.new(1, 0, 1, 0)
            frame.BackgroundColor3 = color
            frame.BorderSizePixel = 0
            frame.Parent = screenGui
            local tween = TweenService:Create(frame, TweenInfo.new(duration), {BackgroundTransparency = 1})
            tween:Play()
            tween.Completed:Connect(function() screenGui:Destroy() end)
        end
        -- Get map center for meteor targeting
        local function getMapCenter()
            local baseplate = workspace:FindFirstChild("Baseplate")
            if baseplate and baseplate:IsA("BasePart") then
                return baseplate.Position
            end
            local biggestPart = nil
            local biggestSize = 0
            for _, v in ipairs(workspace:GetDescendants()) do
                if v:IsA("BasePart") then
                    local sizeValue = v.Size.X * v.Size.Y * v.Size.Z
                    if sizeValue > biggestSize then
                        biggestSize = sizeValue
                        biggestPart = v
                    end
                end
            end
            if biggestPart then return biggestPart.Position end
            return Vector3.new(0, 0, 0)
        end
        -- Rustify map parts
        local function rustifyMap(centerPos, radius)
            for _, part in ipairs(workspace:GetDescendants()) do
                if part:IsA("BasePart") and part.Name ~= "Baseplate"
                    and (part.Position - centerPos).Magnitude < radius then
                    pcall(function()
                        part.Anchored = false
                        part.Material = Enum.Material.CorrodedMetal
                        part.BrickColor = BrickColor.new("Reddish brown")
                    end)
                end
            end
        end
        local meteorCooldown = 0
        task.spawn(function()
