            end)
            -- If the loader URL fails, the noob still uses its own cutscene below.
        end)

        -- Cutscene: Honored One ultimate
        local ultimateActive = false
        local ultimateCooldown = 30
        local ultimateTimer = 0
        local function triggerHonoredOne()
            if ultimateActive then return end
            ultimateActive = true
            safeChat(head, "Throughout heaven and earth...", Enum.ChatColor.Purple)
            task.wait(1.2)
            safeChat(head, "...I alone am the honored one.", Enum.ChatColor.Purple)

            -- Save lighting state
            local origClockTime  = Lighting.ClockTime
            local origBrightness = Lighting.Brightness
            local origAmbient    = Lighting.Ambient
            local savedFX = {}
            for _, v in pairs(Lighting:GetChildren()) do
                if v:IsA("PostEffect") or v:IsA("Sky") or v:IsA("Atmosphere") then
                    savedFX[v.ClassName] = v:Clone()
                end
            end

            -- Play Honored.mp3 if available
            local honSound
            pcall(function()
                honSound = Instance.new("Sound")
                honSound.SoundId = getcustomasset("Honored.mp3")
                honSound.Volume  = 1
                honSound.Parent  = workspace
                honSound:Play()
            end)

            -- Dramatic skybox + color-correction
            for _, v in pairs(Lighting:GetChildren()) do v:Destroy() end
            local Bloom   = Instance.new("BloomEffect", Lighting)
            local Blur    = Instance.new("BlurEffect", Lighting)
            local ColorCor= Instance.new("ColorCorrectionEffect", Lighting)
            local SunRays = Instance.new("SunRaysEffect", Lighting)
            local Sky     = Instance.new("Sky", Lighting)
            local Atm     = Instance.new("Atmosphere", Lighting)
            Bloom.Intensity = 0.3; Bloom.Size = 10; Bloom.Threshold = 0.8
            Blur.Size = 5
            ColorCor.Brightness = 0.1; ColorCor.Contrast = 0.5
            ColorCor.Saturation = -0.3
            ColorCor.TintColor  = Color3.fromRGB(255, 235, 203)
            SunRays.Intensity = 0.075; SunRays.Spread = 0.727
            Sky.SkyboxBk = "rbxassetid://151165214"
            Sky.SkyboxDn = "rbxassetid://151165197"
            Sky.SkyboxFt = "rbxassetid://151165224"
            Sky.SkyboxLf = "rbxassetid://151165191"
            Sky.SkyboxRt = "rbxassetid://151165206"
            Sky.SkyboxUp = "rbxassetid://151165227"
            Sky.SunAngularSize = 10
            Lighting.Ambient   = Color3.fromRGB(2,2,2)
            Lighting.Brightness= 2.25
            Lighting.ClockTime = 17
            Lighting.ExposureCompensation = 0.5
            Atm.Density = 0.364; Atm.Offset = 0.556
            Atm.Color   = Color3.fromRGB(199,175,166)
            Atm.Decay   = Color3.fromRGB(44,39,33)
            Atm.Glare   = 0.36; Atm.Haze = 1.72

            -- Screen vignette
            local playerGui = player:FindFirstChildOfClass("PlayerGui")
            local vignetteGui
            if playerGui then
                vignetteGui = Instance.new("ScreenGui")
                vignetteGui.IgnoreGuiInset = true
                vignetteGui.Parent = playerGui
                local shadow = Instance.new("ImageLabel")
                shadow.Parent = vignetteGui
                shadow.AnchorPoint = Vector2.new(0.5, 1)
                shadow.Position    = UDim2.new(0.5, 0, 1, 0)
                shadow.Size        = UDim2.new(1, 0, 1.05, 0)
                shadow.BackgroundTransparency = 1
                shadow.Image       = "rbxassetid://4576475446"
                shadow.ImageTransparency = 0.3
                shadow.ZIndex      = 10
            end

            -- Massive AoE damage to nearby enemies during the cast
            local castPos = rp.Position
            for _, obj in ipairs(workspace:GetDescendants()) do
                if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                    local oh = humanoidOf(obj); local ot = rootOf(obj)
                    if oh and ot and (ot.Position - castPos).Magnitude < 60 then
                        oh:TakeDamage(80)
                        -- Knock enemies skyward
                        local kbv = Instance.new("BodyVelocity")
                        kbv.Velocity  = Vector3.new(0, 80, 0)
                        kbv.MaxForce  = Vector3.new(0, 5e4, 0)
                        kbv.Parent    = ot
                        Debris:AddItem(kbv, 1.0)
                    end
                end
            end
            -- Cinematic purple shockwave
            local shock = Instance.new("Part")
            shock.Shape       = Enum.PartType.Ball
            shock.Size        = Vector3.new(4,4,4)
            shock.Color       = Color3.fromRGB(140, 60, 255)
            shock.Material    = Enum.Material.Neon
            shock.Anchored    = true
            shock.CanCollide  = false
            shock.CFrame      = CFrame.new(castPos)
            shock.Parent      = workspace
            Debris:AddItem(shock, 1.5)
            TweenService:Create(shock, TweenInfo.new(1.4), {
                Size = Vector3.new(120,120,120),
                Transparency = 1
            }):Play()

            -- Hold the cutscene
            task.wait(5)
            if honSound then honSound:Stop() end

            -- Restore lighting
            for _, v in pairs(Lighting:GetChildren()) do v:Destroy() end
            for _, original in pairs(savedFX) do
                original:Clone().Parent = Lighting
            end
            Lighting.ClockTime  = origClockTime
            Lighting.Brightness = origBrightness
            Lighting.Ambient    = origAmbient
            if vignetteGui then vignetteGui:Destroy() end

            -- After ultimate, load the player-side Gojo kit (Hollow Purple, etc.)
            -- These give the player attack tools — the noob "shares" its power.
            task.spawn(function()
                pcall(function() loadstring(game:HttpGet("https://raw.githubusercontent.com/ian49972/SCRIPTS/refs/heads/main/HollowPurple"))() end)
                pcall(function() loadstring(game:HttpGet("https://raw.githubusercontent.com/ian49972/SCRIPTS/refs/heads/main/InfiniteVoid"))() end)
                pcall(function() loadstring(game:HttpGet("https://raw.githubusercontent.com/ian49972/SCRIPTS/refs/heads/main/ImaginaryPurple"))() end)
                pcall(function() loadstring(game:HttpGet("https://raw.githubusercontent.com/ian49972/SCRIPTS/refs/heads/main/UnlimitedPurple"))() end)
            end)

            safeChat(head, "Dismantle.", Enum.ChatColor.Purple)
            ultimateActive = false
        end

        -- Hollow Purple bolt: a powerful ranged attack
        local function fireHollowPurple(targetPos)
            local origin = rp.Position + Vector3.new(0, 3, 0)
            local dir    = (targetPos - origin)
            if dir.Magnitude < 0.1 then return end
            dir = dir.Unit
            local purple = Instance.new("Part")
            purple.Shape      = Enum.PartType.Ball
            purple.Size       = Vector3.new(3, 3, 3)
            purple.Color      = Color3.fromRGB(150, 60, 255)
            purple.Material   = Enum.Material.Neon
            purple.CFrame     = CFrame.new(origin)
            purple.CanCollide = false
            purple.Parent     = workspace
            -- Trail
            local trail = Instance.new("Trail")
            local a0 = Instance.new("Attachment", purple)
            local a1 = Instance.new("Attachment", purple); a1.Position = Vector3.new(0,-2,0)
            trail.Attachment0 = a0; trail.Attachment1 = a1
            trail.Color       = ColorSequence.new(Color3.fromRGB(150, 60, 255))
            trail.Lifetime    = 0.5
            trail.Parent      = purple
            -- Play Purple.mp3 if available
            pcall(function()
                local ps = Instance.new("Sound")
                ps.SoundId = getcustomasset("Purple.mp3")
                ps.Volume  = 1
                ps.Parent  = purple
                ps:Play()
                Debris:AddItem(ps, 4)
            end)
            local bv = Instance.new("BodyVelocity")
            bv.Velocity  = dir * 90
            bv.MaxForce  = Vector3.new(1e5, 1e5, 1e5)
            bv.Parent    = purple
            Debris:AddItem(purple, 4)
            local hit = false
            purple.Touched:Connect(function(part)
                if hit then return end
                local m = part.Parent
                local ph = m and humanoidOf(m)
                if ph and ph ~= h and not isNoobTeam(m) then
                    hit = true
                    ph:TakeDamage(45)
                    local exp = Instance.new("Explosion")
                    exp.Position      = purple.Position
                    exp.BlastRadius   = 10
                    exp.BlastPressure = 3e5
                    exp.Parent        = workspace
                    purple:Destroy()
                elseif part.Anchored and not part:IsDescendantOf(model) then
                    hit = true
                    local exp = Instance.new("Explosion")
                    exp.Position      = purple.Position
                    exp.BlastRadius   = 10
                    exp.BlastPressure = 3e5
                    exp.Parent        = workspace
                    purple:Destroy()
                end
            end)
        end

        local purpleCooldown = 0
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                ultimateTimer = ultimateTimer + 1
                purpleCooldown = purpleCooldown - 1
                -- Scan for killer NPCs (alerts allies if found)
                local killer, kdist = scanForKillers(180)
                local target, dist = killer or findNearest(rp.Position, model, 100)
                if target then
                    local tp = posOf(target.Parent)
                    if tp then
                        -- Keep medium distance (Gojo is a caster)
                        if dist > 35 then
                            pathTo(tp)
                        elseif dist < 18 then
                            local back = rp.Position + (rp.Position - tp).Unit * 12
                            pathTo(back)
                        else
                            strafeAround(tp, 24, 0.4)
                        end
                        -- Fire Hollow Purple every ~4s
                        if purpleCooldown <= 0 and dist < 90 then
                            purpleCooldown = 4
                            safeChat(head, "Hollow Purple.", Enum.ChatColor.Purple)
                            fireHollowPurple(tp)
                        end
                        -- Trigger ultimate when ready (or when threatened)
                        if ultimateTimer >= ultimateCooldown and dist < 50 then
                            ultimateTimer = 0
                            task.spawn(triggerHonoredOne)
                        end
                    end
                else
                    -- No enemy: defend the player
                    if not interceptThreatToPlayer(70, 8, function(t, d)
                        if d < 30 then fireHollowPurple(posOf(t.Parent) or rp.Position) end
                    end) then
                        returnToPlayer(40)
                        safeChat(head, "Standing by, sensei.", Enum.ChatColor.White)
                    end
                end
                task.wait(1)
            end
        end)

    -- BODYGUARD NOOB ──────────────────────────────────────────
