                            if tr then
                                local kbv = Instance.new("BodyVelocity")
                                kbv.Velocity = (tr.Position - rp.Position).Unit * 40 + Vector3.new(0, 10, 0)
                                kbv.MaxForce = Vector3.new(1e5, 1e5, 1e5)
                                kbv.Parent = tr
                                Debris:AddItem(kbv, 0.3)
                            end
                        end
                        didSomething = true
                    end
                end
                -- v9.2.3: proactively seek out killers
                if not didSomething then
                    local killer, kdist = scanForKillers(180)
                    if killer then
                        local tp = posOf(killer.Parent)
                        if tp then
                            pathTo(tp)
                            if kdist < 12 then killer:TakeDamage(30) end
                            didSomething = true
                        end
                    end
                end
                -- v9.2.3: seek out ANY enemy if no killers
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 120)
                    if enemy and edist > 15 then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            pathTo(tp)
                            didSomething = true
                        end
                    elseif enemy and edist < 12 then
                        enemy:TakeDamage(25)
                        didSomething = true
                    end
                end
                -- Ground Slam: fires every 6s
                slamCooldown = slamCooldown + 1
                if slamCooldown >= 4 then  -- 4 * 1.5s = 6s
                    slamCooldown = 0
                    pcall(groundSlam)
                end
                -- Otherwise stay near player
                if not didSomething then
                    if ppos then
                        local d = (ppos - rp.Position).Magnitude
                        if d > 12 then
                            pathTo(ppos)
                        end
                    end
                    if math.random() > 0.8 then
                        safeChat(head, "Standing guard.", Enum.ChatColor.Gray)
                    end
                end
                task.wait(1.5)
            end
        end)

