                overchargeCooldown = overchargeCooldown + 1
                -- v9.2.3: Find threats to the player, near self, or ANY enemy/killer
                local target, dist = findNearestThreatToPlayer(getPlayerChar(), 80)
                if not target then
                    target, dist = findNearestKillerNPC(rp.Position, model, 200)
                end
                if not target then
                    target, dist = findNearest(rp.Position, model, 150)
                end
                if target then
                    local tp = posOf(target.Parent)
                    if tp then
                        -- Aim barrel
                        turretBarrel.CFrame = CFrame.new(turretBarrel.Position, tp)
                        rp.CFrame = CFrame.new(rp.Position, tp)
                        if fireTimer >= 2 then
                            fireTimer = 0
                            makeBullet(turretBarrel.Position + turretBarrel.CFrame.LookVector * 2,
                                tp, 120, Vector3.new(0.2,0.2,1), Color3.fromRGB(255,200,0), 12)
                            if math.random() > 0.8 then
                                safeChat(head, "Targeting.", Enum.ChatColor.Gray)
                            end
                        end
                        -- v9.2.3: OVERCHARGE — every 15s (≈37 iterations @ 0.4s),
                        -- fire a rapid burst of 6 shots
                        if overchargeCooldown >= 37 then
                            overchargeCooldown = 0
                            safeChat(head, "OVERCHARGE!", Enum.ChatColor.Red)
                            task.spawn(function()
                                for i = 1, 6 do
                                    if not isAlive(h) or not rp.Parent then break end
                                    local tp2 = posOf(target.Parent)
                                    if tp2 then
                                        makeBullet(turretBarrel.Position + turretBarrel.CFrame.LookVector * 2,
                                            tp2, 150, Vector3.new(0.25,0.25,1.5),
                                            Color3.fromRGB(255,100,0), 15)
                                    end
                                    task.wait(0.1)
                                end
                            end)
                        end
                    end
                else
                    -- Slowly rotate scanning
                    rp.CFrame = rp.CFrame * CFrame.Angles(0, 0.05, 0)
                end
                task.wait(0.4)
            end
        end)

    -- SNIPER TOWER NOOB ───────────────────────────────────────
    -- Finds high ground near the player, snipes enemies from afar.
    elseif characterType == "sniper_tower_noob" then
        h.WalkSpeed = 14; h.MaxHealth = 130; h.Health = 130
        colorModel(model, Color3.fromRGB(40, 50, 40))
        -- Find highest point near the player and stay there
        local function findHighGround(centerPos)
            local bestPos = centerPos
            local bestY   = -math.huge
            for _, obj in ipairs(workspace:GetDescendants()) do
                if obj:IsA("BasePart") and obj.Anchored then
                    local topY = obj.Position.Y + obj.Size.Y / 2
                    if topY > bestY and (obj.Position - centerPos).Magnitude < 80 then
                        bestY = topY
                        bestPos = obj.Position + Vector3.new(0, 5, 0)
                    end
                end
            end
            return bestPos
        end
        local deployed = false
        local fireCooldown = 0
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                fireCooldown = fireCooldown - 1
                if not deployed then
                    -- Move to high ground near player
                    local ppos = getPlayerPos()
                    if ppos then
                        local hg = findHighGround(ppos)
                        pathTo(hg)
                        if (hg - rp.Position).Magnitude < 6 then
                            deployed = true
                            safeChat(head, "In position. Watching.", Enum.ChatColor.Red)
                        end
                    end
                else
                    -- Snipe threats (priority: killers, then threats to player, then any enemy)
                    local target, dist = findNearestKillerNPC(rp.Position, model, 300)
                    if not target then
                        target, dist = findNearestThreatToPlayer(getPlayerChar(), 150)
                    end
                    if not target then
                        target, dist = findNearest(rp.Position, model, 200)
                    end
                    if target then
                        local tp = posOf(target.Parent)
                        if tp and hasLineOfSight(rp.Position, tp) then
                            -- Aim
                            rp.CFrame = CFrame.new(rp.Position, tp)
                            if fireCooldown <= 0 then
                                fireCooldown = 2
                                safeChat(head, "Bang.", Enum.ChatColor.Red)
                                makeBullet(rp.Position + Vector3.new(0,2,0), tp, 250,
                                    Vector3.new(0.15,0.15,4), Color3.fromRGB(255,0,0), 40)
                            end
                        else
                            -- No LOS: reposition
                            deployed = false
                        end
                    else
                        safeChat(head, "No targets in sight.", Enum.ChatColor.Gray)
                    end
                    -- Re-deploy if player moved far
                    local ppos = getPlayerPos()
                    if ppos and (ppos - rp.Position).Magnitude > 100 then
                        deployed = false
                    end
                end
                task.wait(1)
            end
        end)

