                    local defenderCount = 0
                    for _, m in ipairs(workspace:GetChildren()) do
                        if m:IsA("Model") and isNoobTeam(m) then defenderCount = defenderCount + 1 end
                    end
                    if defenderCount < MAX_NOOBS - 5 then
                        local pick = defensiveSummons[math.random(1, #defensiveSummons)]
                        safeChat(head, "Summoning: "..pick, Enum.ChatColor.Purple)
                        -- Summon near the player, not the summoner
                        local ppos = getPlayerPos()
                        if ppos then
                            local oldCF = rp.CFrame
