                            spawnNoob(pick, _depth + 1)
                            rp.CFrame = oldCF
                        else
                            spawnNoob(pick, _depth + 1)
                        end
                    else
                        safeChat(head, "Army at full strength.", Enum.ChatColor.Purple)
                    end
                end
                -- Summoner stays close to player
                if not returnToPlayer(25) then
                    if math.random() > 0.7 then
                        safeChat(head, "Defending the summoner.", Enum.ChatColor.Purple)
                    end
                end
                task.wait(2)
            end
