                            exp.BlastRadius   = 25
                            exp.BlastPressure = 8e5
                            exp.Parent        = workspace
                            -- Extra damage to nearby enemies (the explosion itself
                            -- respects Team, so we manually hit non-noobs in radius)
                            for _, obj in ipairs(workspace:GetDescendants()) do
