    -- NECROMANCER NOOB ─────────────────────────────────────────
    -- Distinct from the existing "necromancer" type. This one focuses on
    -- raising dead killer NPCs as temporary allies, cursing live enemies
    -- with a damage-over-time debuff, and unleashing bone nova AoE.
    elseif characterType == "necromancer_noob" then
        h.WalkSpeed = 11
        h.MaxHealth = 220; h.Health = 220
        -- Bone-white with dark purple robe trim
        colorModel(model, Color3.fromRGB(230, 230, 220))
        for _, p in pairs(model:GetDescendants()) do
            if p:IsA("BasePart") and (p.Name == "Torso" or p.Name == "HumanoidRootPart") then
                p.Color = Color3.fromRGB(60, 0, 90)
            end
        end
        -- Dark aura particles
