        necroLight.Brightness = 4
        necroLight.Range = 18
        necroLight.Parent = rp
        -- Skull staff
        if head then
            local staff = Instance.new("Part")
            staff.Size = Vector3.new(0.3, 3.5, 0.3)
            staff.Color = Color3.fromRGB(50, 50, 50)
            staff.Material = Enum.Material.Slate
            staff.CanCollide = false
            staff.Parent = model
            local sw = Instance.new("WeldConstraint")
            sw.Part0 = head; sw.Part1 = staff; sw.Parent = head
            local skull = Instance.new("Part")
            skull.Shape = Enum.PartType.Ball
            skull.Size = Vector3.new(1, 1, 1)
            skull.Color = Color3.fromRGB(230, 230, 200)
            skull.Material = Enum.Material.Slate
            skull.CanCollide = false
            skull.Parent = model
