            skullGlow.Brightness = 4
            skullGlow.Range = 12
            skullGlow.Parent = skull
        end
        local necroPhrases = {
            "Rise... rise from the grave!","Your soul is mine!",
            "The dead obey me!","Death is only the beginning.",
            "Bow to the lord of death!","Feel the cold embrace...",
        }
        -- v9.2.4 BONE NOVA — periodic AoE damage around the necromancer
        local boneNovaCooldown = 0
        local function boneNova()
            safeChat(head, "BONE NOVA!", Enum.ChatColor.Purple)
            -- Visual: expanding bone ring
            local ring = Instance.new("Part")
            ring.Shape = Enum.PartType.Cylinder
            ring.Size = Vector3.new(0.3, 4, 4)
            ring.Color = Color3.fromRGB(230, 230, 220)
            ring.Material = Enum.Material.Neon
            ring.Anchored = true
            ring.CanCollide = false
            ring.CFrame = CFrame.new(rp.Position) * CFrame.Angles(0, 0, math.pi/2)
            ring.Parent = workspace
            Debris:AddItem(ring, 0.6)
            TweenService:Create(ring, TweenInfo.new(0.5), {
                Size = Vector3.new(0.3, 35, 35),
                Transparency = 1
            }):Play()
            -- Bone shards (visual)
            for i = 1, 8 do
                task.spawn(function()
                    local shard = Instance.new("Part")
                    shard.Size = Vector3.new(0.3, 2, 0.3)
                    shard.Color = Color3.fromRGB(230, 230, 220)
                    shard.Material = Enum.Material.Slate
                    shard.CanCollide = false
                    shard.CFrame = CFrame.new(rp.Position)
                    shard.Parent = workspace
                    Debris:AddItem(shard, 1.0)
                    local angle = (i / 8) * math.pi * 2
                    local bv = Instance.new("BodyVelocity")
                    bv.Velocity = Vector3.new(math.cos(angle) * 60, 15, math.sin(angle) * 60)
                    bv.MaxForce = Vector3.new(1e5, 1e5, 1e5)
                    bv.Parent = shard
                end)
            end
            -- Damage + curse all enemies in radius
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and (ot.Position - rp.Position).Magnitude < 25 then
                            oh:TakeDamage(30)
                            -- Curse: slow + DoT
                            oh.WalkSpeed = math.max(oh.WalkSpeed - 8, 1)
                            task.spawn(function()
                                for i = 1, 5 do
                                    if oh and oh.Parent and oh.Health > 0 then
                                        oh:TakeDamage(5)
                                        task.wait(1)
                                    end
                                end
                            end)
                        end
                    end
                end)
            end
        end
        -- v9.2.4 RAISE DEAD — reanimates a dead killer NPC as a temporary ally
        local raiseCooldown = 0
        local raisedAllies = 0
        local function raiseDead()
            -- Find a recently-dead killer NPC near us
            local bestDead = nil
            local bestDist = 60
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and oh.Health <= 0 then
                            local d = (ot.Position - rp.Position).Magnitude
                            if d < bestDist then
                                bestDist = d; bestDead = obj
                            end
                        end
                    end
                end)
            end
            if not bestDead then return false end
            safeChat(head, "RISE FROM THE GRAVE!", Enum.ChatColor.Purple)
            -- Resurrection visual
            local resEffect = Instance.new("Part")
            resEffect.Shape = Enum.PartType.Ball
            resEffect.Size = Vector3.new(2, 2, 2)
            resEffect.Color = Color3.fromRGB(150, 0, 220)
            resEffect.Material = Enum.Material.Neon
            resEffect.Anchored = true
            resEffect.CanCollide = false
            resEffect.CFrame = CFrame.new(bestDead.PrimaryPart and bestDead.PrimaryPart.Position or bestDead:GetPivot().Position)
            resEffect.Parent = workspace
            Debris:AddItem(resEffect, 1.0)
            TweenService:Create(resEffect, TweenInfo.new(0.8), {
                Size = Vector3.new(15, 15, 15),
                Transparency = 1
            }):Play()
            -- Heal the dead NPC back to half health and tag it as a noob ally
            local oh = humanoidOf(bestDead)
            if oh then
                oh.Health = oh.MaxHealth * 0.5
                -- Tag it as noob team so our other noobs don't attack it
                local teamTag = Instance.new("BoolValue")
                teamTag.Name = "IsNoobTeam"
                teamTag.Value = true
                teamTag.Parent = bestDead
                pcall(function()
                    oh.Team = noobTeam
                    oh.TeamColor = NOOB_TEAM_COLOR
                end)
                -- Visual: recolor it dark purple
                for _, p in pairs(bestDead:GetDescendants()) do
                    if p:IsA("BasePart") then
                        p.Color = Color3.fromRGB(100, 50, 150)
                        p.Material = Enum.Material.Slate
                    end
                end
                -- Decay: it dies after 20s
                Debris:AddItem(bestDead, 20)
                raisedAllies = raisedAllies + 1
                safeChat(head, "Serve me, slave!", Enum.ChatColor.Purple)
                return true
            end
            return false
        end
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- First priority: intercept threats to the player
                if interceptThreatToPlayer(70, 8, function(t, d)
                    if d < 8 then
                        t:TakeDamage(15)
                        -- Curse: slow
                        t.WalkSpeed = math.max(t.WalkSpeed - 4, 1)
                    end
                end) then
                    didSomething = true
                end
                -- Second priority: hunt killers
                local killer, kdist = scanForKillers(180)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        -- Keep medium distance (necromancer is ranged)
                        if kdist > 30 then
                            pathTo(tp)
                        elseif kdist < 15 then
                            local back = rp.Position + (rp.Position - tp).Unit * 12
                            pathTo(back)
                        else
                            strafeAround(tp, 22, 0.3)
                        end
                        -- Fire bone bolt
                        if kdist < 80 then
                            makeBullet(rp.Position + Vector3.new(0, 3, 0), tp, 90,
                                Vector3.new(0.3, 0.3, 2), Color3.fromRGB(180, 0, 255), 18)
                        end
                        if kdist < 8 then killer:TakeDamage(20) end
                        didSomething = true
                    end
                end
                -- Third priority: hunt any enemy
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 100)
                    if enemy and edist > 25 then
                        local tp = posOf(enemy.Parent)
                        if tp then pathTo(tp); didSomething = true end
                    elseif enemy and edist < 8 then
                        enemy:TakeDamage(15); didSomething = true
                    end
                end
                -- Bone Nova: every 7s
                boneNovaCooldown = boneNovaCooldown + 1
                if boneNovaCooldown >= 7 then
                    boneNovaCooldown = 0
                    pcall(boneNova)
                end
                -- Raise Dead: every 15s, if there are dead enemies nearby
                raiseCooldown = raiseCooldown + 1
                if raiseCooldown >= 15 and raisedAllies < 3 then
                    if pcall(raiseDead) then
                        raiseCooldown = 0
                    end
                end
                -- Otherwise return to player
                if not didSomething then
                    returnToPlayer(30)
                    if math.random() > 0.7 then
                        safeChat(head, necroPhrases[math.random(1,#necroPhrases)], Enum.ChatColor.Purple)
                    end
                end
                task.wait(1)
            end
        end)

