            trident.Material = Enum.Material.Metal
            trident.CanCollide = false
            trident.CFrame = rArm.CFrame * CFrame.new(0, -3, 0)
            trident.Parent = model
            local tw = Instance.new("WeldConstraint")
            tw.Part0 = rArm; tw.Part1 = trident; tw.Parent = rArm
            -- Trident prongs (3 spikes at top)
            for i = -1, 1 do
                local prong = Instance.new("Part")
                prong.Size = Vector3.new(0.2, 1.5, 0.2)
                prong.Color = Color3.fromRGB(255, 215, 0)
                prong.Material = Enum.Material.Metal
                prong.CanCollide = false
                prong.CFrame = trident.CFrame * CFrame.new(i * 0.5, 3.5, 0)
