        -- Theme music
        local deterSound = nil
        local minationSound = nil
        pcall(function()
            -- Download audio
            if not isfile("Deter.mp3") then
                writefile("Deter.mp3", game:HttpGet("https://github.com/ian49972/smth/raw/refs/heads/main/Deter.mp3"))
            end
