                writefile("mination.mp3", game:HttpGet("https://github.com/ian49972/smth/raw/refs/heads/main/mination.mp3"))
            end
            deterSound = Instance.new("Sound")
            deterSound.SoundId = getcustomasset("Deter.mp3")
