            deterSound.Looped = false
            deterSound.Parent = rp
            minationSound = Instance.new("Sound")
            minationSound.SoundId = getcustomasset("mination.mp3")
            minationSound.Volume = 0.4
            minationSound.Looped = true
            minationSound.Parent = rp
            -- Loop the two tracks
            task.spawn(function()
                while isAlive(h) and rp.Parent do
                    deterSound:Play()
                    deterSound.Ended:Wait()
                    if not isAlive(h) then break end
                    minationSound:Play()
                    minationSound.Ended:Wait()
                    if not isAlive(h) then break end
