        kingAura.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0,0.4), NumberSequenceKeypoint.new(1,1)})
        kingAura.Lifetime = NumberRange.new(0.4, 1.0)
        kingAura.Rate = 25
        kingAura.Speed = NumberRange.new(1, 3)
        kingAura.Parent = rp
        local kingPhrases = {
            "All I need is one more soul.","Why are you getting in my way?",
