        }
        -- v9.2.4 ABILITY 1: TRIDENT SLAM — close-range AoE + knockback
        local slamCooldown = 0
        local function tridentSlam(targetPos)
            safeChat(head, "TRIDENT SLAM!", Enum.ChatColor.Red)
            -- Visual: red shockwave
            local wave = Instance.new("Part")
            wave.Shape = Enum.PartType.Cylinder
            wave.Size = Vector3.new(0.4, 4, 4)
            wave.Color = Color3.fromRGB(255, 0, 0)
            wave.Material = Enum.Material.Neon
            wave.Anchored = true
            wave.CanCollide = false
            wave.CFrame = CFrame.new(targetPos) * CFrame.Angles(0, 0, math.pi/2)
            wave.Parent = workspace
            Debris:AddItem(wave, 0.6)
            TweenService:Create(wave, TweenInfo.new(0.5), {
                Size = Vector3.new(0.4, 30, 30),
                Transparency = 1
            }):Play()
            -- Damage + knockback all enemies in radius
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and (ot.Position - targetPos).Magnitude < 18 then
                            oh:TakeDamage(40)
                            local kbv = Instance.new("BodyVelocity")
                            kbv.Velocity = (ot.Position - targetPos).Unit * 55 + Vector3.new(0, 25, 0)
                            kbv.MaxForce = Vector3.new(1e5, 1e5, 1e5)
                            kbv.Parent = ot
                            Debris:AddItem(kbv, 0.4)
                        end
                    end
                end)
            end
            -- Camera shake
            local camera = workspace.CurrentCamera
            if camera then
                task.spawn(function()
                    local t0 = os.clock()
                    while os.clock() - t0 < 0.3 do
                        camera.CFrame = camera.CFrame * CFrame.Angles(
                            math.rad(math.random(-2,2)),
                            math.rad(math.random(-2,2)),
                            math.rad(math.random(-2,2))
                        )
                        task.wait()
                    end
                end)
            end
        end
        -- v9.2.4 ABILITY 2: FIREBALL BARRAGE — spread of homing-ish fireballs
        local barrageCooldown = 0
        local function fireballBarrage(targetPos)
            safeChat(head, "FIREBALL BARRAGE!", Enum.ChatColor.Red)
            local origin = rp.Position + Vector3.new(0, 3, 0)
            local baseDir = (targetPos - origin)
            if baseDir.Magnitude < 0.1 then return end
            baseDir = baseDir.Unit
            -- Fire 5 fireballs in a spread
            for i = -2, 2 do
                task.spawn(function()
                    local spreadAngle = i * 0.2  -- radians
                    local dir = (baseDir * math.cos(spreadAngle))
                        + (rp.CFrame.RightVector * math.sin(spreadAngle) * i)
                    if dir.Magnitude < 0.01 then dir = baseDir end
                    dir = dir.Unit
                    local fb = Instance.new("Part")
                    fb.Shape = Enum.PartType.Ball
                    fb.Size = Vector3.new(2.5, 2.5, 2.5)
                    fb.Color = Color3.fromRGB(255, 100, 0)
                    fb.Material = Enum.Material.Neon
                    fb.CFrame = CFrame.new(origin)
                    fb.CanCollide = false
                    fb.Parent = workspace
                    -- Fire trail
                    local fire = Instance.new("Fire")
                    fire.Color = Color3.fromRGB(255, 100, 0)
                    fire.Size = 5
                    fire.Parent = fb
                    local trail = Instance.new("Trail")
                    local a0 = Instance.new("Attachment", fb)
                    local a1 = Instance.new("Attachment", fb); a1.Position = Vector3.new(0,-1,0)
                    trail.Attachment0 = a0; trail.Attachment1 = a1
                    trail.Color = ColorSequence.new(Color3.fromRGB(255, 100, 0))
                    trail.Lifetime = 0.4
                    trail.Parent = fb
                    local bv = Instance.new("BodyVelocity")
                    bv.Velocity = dir * 80
                    bv.MaxForce = Vector3.new(1e5, 1e5, 1e5)
                    bv.Parent = fb
                    Debris:AddItem(fb, 4)
                    local hit = false
                    fb.Touched:Connect(function(part)
                        if hit then return end
                        local m = part.Parent
                        local ph = m and humanoidOf(m)
                        if ph and ph ~= h and not isNoobTeam(m) then
                            hit = true
                            ph:TakeDamage(30)
                            local exp = Instance.new("Explosion")
                            exp.Position = fb.Position
                            exp.BlastRadius = 8
                            exp.BlastPressure = 2e5
                            exp.Parent = workspace
                            fb:Destroy()
                        elseif part.Anchored and not part:IsDescendantOf(model) then
                            hit = true
                            local exp = Instance.new("Explosion")
                            exp.Position = fb.Position
                            exp.BlastRadius = 8
                            exp.BlastPressure = 2e5
                            exp.Parent = workspace
                            fb:Destroy()
                        end
                    end)
                end)
            end
        end
        -- v9.2.4 ABILITY 3: EARTHQUAKE — massive AoE + camera shake + debris
        local earthquakeCooldown = 0
        local function kingEarthquake()
            safeChat(head, "Feel the wrath of earth!", Enum.ChatColor.Red)
            task.wait(1)
            safeChat(head, "EARTHQUAKE!", Enum.ChatColor.Red)
            -- Camera shake (escalating)
            local camera = workspace.CurrentCamera
            if camera then
                task.spawn(function()
                    for intensity = 2, 12, 2 do
                        local t0 = os.clock()
                        while os.clock() - t0 < 0.3 do
                            camera.CFrame = camera.CFrame * CFrame.Angles(
                                math.rad(math.random(-intensity, intensity) * 0.3),
                                math.rad(math.random(-intensity, intensity) * 0.3),
                                math.rad(math.random(-intensity, intensity) * 0.3)
                            )
                            task.wait()
                        end
                    end
                end)
            end
            -- Visual: expanding earth ring
            local ring = Instance.new("Part")
            ring.Shape = Enum.PartType.Cylinder
            ring.Size = Vector3.new(0.5, 8, 8)
            ring.Color = Color3.fromRGB(140, 80, 30)
            ring.Material = Enum.Material.Slate
            ring.Anchored = true
            ring.CanCollide = false
            ring.CFrame = CFrame.new(rp.Position) * CFrame.Angles(0, 0, math.pi/2)
            ring.Parent = workspace
            Debris:AddItem(ring, 1.0)
            TweenService:Create(ring, TweenInfo.new(0.8), {
                Size = Vector3.new(0.5, 60, 60),
                Transparency = 1
            }):Play()
            -- Spawn debris parts
            for i = 1, 15 do
                task.spawn(function()
                    local debris = Instance.new("Part")
                    debris.Size = Vector3.new(2 + math.random()*3, 2 + math.random()*3, 2 + math.random()*3)
                    debris.Color = Color3.fromRGB(120 + math.random(-20,20), 70 + math.random(-10,10), 30)
                    debris.Material = Enum.Material.Slate
                    debris.CanCollide = false
                    debris.Position = rp.Position + Vector3.new(math.random(-30,30), -2, math.random(-30,30))
                    debris.Parent = workspace
                    local bv = Instance.new("BodyVelocity")
                    bv.Velocity = Vector3.new(math.random(-100,100), 150, math.random(-100,100))
                    bv.MaxForce = Vector3.new(1e5, 1e5, 1e5)
                    bv.Parent = debris
                    debris.RotVelocity = Vector3.new(math.random(-50,50), math.random(-50,50), math.random(-50,50))
                    Debris:AddItem(debris, 4)
                end)
            end
            -- Massive AoE damage + knockback all enemies in big radius
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and (ot.Position - rp.Position).Magnitude < 40 then
                            oh:TakeDamage(60)
                            local kbv = Instance.new("BodyVelocity")
                            kbv.Velocity = (ot.Position - rp.Position).Unit * 70 + Vector3.new(0, 40, 0)
                            kbv.MaxForce = Vector3.new(1e5, 1e5, 1e5)
                            kbv.Parent = ot
                            Debris:AddItem(kbv, 0.5)
                        end
                    end
                end)
            end
            safeChat(head, "Your world crumbles!", Enum.ChatColor.Red)
        end
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Priority 1: intercept threats to player
                if interceptThreatToPlayer(80, 8, function(t, d)
                    if d < 10 then
                        t:TakeDamage(20)
                        -- Knockback
                        local tr = rootOf(t.Parent)
                        if tr then
                            local kbv = Instance.new("BodyVelocity")
                            kbv.Velocity = (tr.Position - rp.Position).Unit * 35 + Vector3.new(0, 15, 0)
                            kbv.MaxForce = Vector3.new(1e4, 1e4, 1e4)
                            kbv.Parent = tr
                            Debris:AddItem(kbv, 0.3)
                        end
                    end
                end) then
                    didSomething = true
                end
                -- Priority 2: hunt killers (long range — king is powerful)
                local killer, kdist = scanForKillers(250)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist > 25 then
                            pathTo(tp)
                        elseif kdist < 8 then
                            -- Close range: TRIDENT SLAM
                            slamCooldown = slamCooldown + 1
                            if slamCooldown >= 4 then
                                slamCooldown = 0
                                pcall(function() tridentSlam(tp) end)
                            end
                            killer:TakeDamage(25)
                        else
                            -- Medium range: keep approaching
                            pathTo(tp)
                            -- Fireball barrage every 8s
                            barrageCooldown = barrageCooldown + 1
                            if barrageCooldown >= 8 then
                                barrageCooldown = 0
                                pcall(function() fireballBarrage(tp) end)
                            end
                        end
                        didSomething = true
                    end
                end
                -- Priority 3: hunt any enemy
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 150)
                    if enemy and edist > 25 then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            pathTo(tp)
                            if edist < 80 then
                                pcall(function() fireballBarrage(tp) end)
                            end
                            didSomething = true
                        end
                    elseif enemy and edist < 8 then
                        enemy:TakeDamage(25)
                        didSomething = true
                    end
                end
                -- Earthquake: every 25s (rare big ability)
                earthquakeCooldown = earthquakeCooldown + 1
                if earthquakeCooldown >= 25 then
                    earthquakeCooldown = 0
                    pcall(kingEarthquake)
                end
                -- Otherwise return to player
                if not didSomething then
                    returnToPlayer(30)
                    if math.random() > 0.7 then
                        safeChat(head, kingPhrases[math.random(1,#kingPhrases)], Enum.ChatColor.Red)
                    end
                end
                task.wait(1)
            end
            -- Cleanup sounds on death
            if deterSound then pcall(function() deterSound:Stop() deterSound:Destroy() end) end
            if minationSound then pcall(function() minationSound:Stop() minationSound:Destroy() end) end
        end)

