            sukunaAssetsReady = true
        end)

        -- Helper: play a sound from a downloaded asset
        local function playSukunaSound(assetName, volume, parent)
            pcall(function()
                local s = Instance.new("Sound")
                s.SoundId = getcustomasset(assetName)
                s.Volume = volume or 1
                s.Parent = parent or workspace
                s:Play()
                Debris:AddItem(s, 15)
            end)
        end

        -- State
        local awakened = false
        local domainCooldown = 0
        local furnaceCooldown = 0
        local slashCooldown = 0
        local rushCooldown = 0

        -- AWAKEN: one-time transformation
        local function awaken()
            if awakened then return end
            awakened = true
            safeChat(head, "Heh... you dare challenge me?", Enum.ChatColor.Red)
            playSukunaSound("LAUGH.mp3", 1, workspace)
            -- Slow during awakening
            local origSpeed = h.WalkSpeed
            h.WalkSpeed = 0
            task.wait(2)
            -- Strip shirt (visual)
            pcall(function()
                local shirt = model:FindFirstChildOfClass("Shirt")
                if shirt then shirt:Destroy() end
            end)
            -- Recolor to Sukuna's dark red
            colorModel(model, Color3.fromRGB(80, 0, 0))
            h.WalkSpeed = origSpeed
            safeChat(head, "I am the King of Curses!", Enum.ChatColor.Red)
        end

        -- MALEVOLENT SHRINE (Domain Expansion)
        local function malevolentShrine(targetPos)
            safeChat(head, "Domain Expansion: Malevolent Shrine!", Enum.ChatColor.Red)
            playSukunaSound("SUKUNA.mp3", 1, workspace)
            -- Darken sky
            local origClockTime = Lighting.ClockTime
            local origBrightness = Lighting.Brightness
            local savedFX = {}
            for _, v in pairs(Lighting:GetChildren()) do
                if v:IsA("PostEffect") or v:IsA("Sky") or v:IsA("Atmosphere") then
                    savedFX[v.ClassName] = v:Clone()
                end
            end
            TweenService:Create(Lighting, TweenInfo.new(2), {ClockTime = 0, Brightness = 0}):Play()
            -- Summon shrine visual (a dark demonic structure behind the noob)
            local shrine = Instance.new("Part")
            shrine.Shape = Enum.PartType.Ball
            shrine.Size = Vector3.new(40, 40, 40)
            shrine.Color = Color3.fromRGB(20, 0, 0)
            shrine.Material = Enum.Material.Neon
            shrine.Anchored = true
            shrine.CanCollide = false
            shrine.CFrame = CFrame.new(targetPos)
            shrine.Transparency = 1
            shrine.Parent = workspace
            Debris:AddItem(shrine, 10)
            -- Make it visible
            TweenService:Create(shrine, TweenInfo.new(1), {Transparency = 0.4}):Play()
            -- Continuous cleave damage for 8 seconds
            task.spawn(function()
                local startTime = os.clock()
                while os.clock() - startTime < 8 do
                    if not isAlive(h) then break end
                    -- Cleave: damage everything in radius
                    for _, obj in ipairs(workspace:GetDescendants()) do
                        pcall(function()
                            if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                                local oh = humanoidOf(obj); local ot = rootOf(obj)
                                if oh and ot and (ot.Position - targetPos).Magnitude < 50 then
                                    oh:TakeDamage(25)
                                    -- Random knockback direction
                                    local kbv = Instance.new("BodyVelocity")
                                    kbv.Velocity = (ot.Position - targetPos).Unit * 40 + Vector3.new(0, 20, 0)
                                    kbv.MaxForce = Vector3.new(1e5, 1e5, 1e5)
                                    kbv.Parent = ot
                                    Debris:AddItem(kbv, 0.3)
                                end
                            end
                        end)
                    end
                    -- Cleave visual: red slash lines
                    for i = 1, 5 do
                        task.spawn(function()
                            local slash = Instance.new("Part")
                            slash.Size = Vector3.new(0.2, 0.2, 30)
                            slash.Color = Color3.fromRGB(255, 0, 0)
                            slash.Material = Enum.Material.Neon
                            slash.Anchored = true
                            slash.CanCollide = false
                            local angle = math.random() * math.pi * 2
                            slash.CFrame = CFrame.new(targetPos) * CFrame.Angles(0, angle, math.rad(math.random(-30, 30)))
                            slash.Parent = workspace
                            Debris:AddItem(slash, 0.3)
                            TweenService:Create(slash, TweenInfo.new(0.3), {Transparency = 1, Size = Vector3.new(0.2, 0.2, 50)}):Play()
                        end)
                    end
                    task.wait(0.4)
                end
            end)
            -- Camera shake
            local camera = workspace.CurrentCamera
            if camera then
                task.spawn(function()
                    local t0 = os.clock()
                    while os.clock() - t0 < 6 do
                        camera.CFrame = camera.CFrame * CFrame.Angles(
                            math.rad(math.random(-3, 3) * 0.3),
                            math.rad(math.random(-3, 3) * 0.3),
                            math.rad(math.random(-3, 3) * 0.3)
                        )
                        task.wait()
                    end
                end)
            end
            task.wait(8)
            -- Restore lighting
            TweenService:Create(Lighting, TweenInfo.new(2), {ClockTime = origClockTime, Brightness = origBrightness}):Play()
            for _, v in pairs(Lighting:GetChildren()) do v:Destroy() end
            for _, original in pairs(savedFX) do
                original:Clone().Parent = Lighting
            end
            safeChat(head, "Cleave.", Enum.ChatColor.Red)
        end

        -- FURNACE: homing fire arrow
        local function furnaceArrow(targetPos)
            safeChat(head, "Furnace!", Enum.ChatColor.Red)
            playSukunaSound("Furnance.mp3", 1, workspace)
            local origin = rp.Position + Vector3.new(0, 3, 0)
            local dir = (targetPos - origin)
            if dir.Magnitude < 0.1 then return end
            dir = dir.Unit
            -- Fire arrow
            local arrow = Instance.new("Part")
            arrow.Shape = Enum.PartType.Cylinder
            arrow.Size = Vector3.new(0.5, 0.5, 4)
            arrow.Color = Color3.fromRGB(255, 100, 0)
            arrow.Material = Enum.Material.Neon
            arrow.CFrame = CFrame.new(origin, origin + dir) * CFrame.Angles(0, 0, math.pi/2)
            arrow.CanCollide = false
            arrow.Parent = workspace
            -- Fire trail
            local fire = Instance.new("Fire")
            fire.Color = Color3.fromRGB(255, 100, 0)
            fire.Size = 6
            fire.Parent = arrow
            local trail = Instance.new("Trail")
            local a0 = Instance.new("Attachment", arrow)
            local a1 = Instance.new("Attachment", arrow); a1.Position = Vector3.new(0, -2, 0)
            trail.Attachment0 = a0; trail.Attachment1 = a1
            trail.Color = ColorSequence.new(Color3.fromRGB(255, 100, 0))
            trail.Lifetime = 0.5
            trail.Parent = arrow
            local bv = Instance.new("BodyVelocity")
            bv.Velocity = dir * 120
            bv.MaxForce = Vector3.new(1e5, 1e5, 1e5)
            bv.Parent = arrow
            Debris:AddItem(arrow, 5)
            local hit = false
            arrow.Touched:Connect(function(part)
                if hit then return end
                local m = part.Parent
                local ph = m and humanoidOf(m)
                if ph and ph ~= h and not isNoobTeam(m) then
                    hit = true
                    ph:TakeDamage(50)
                    playSukunaSound("ArrowExplode.mp3", 1, workspace)
                    -- Big explosion
                    local exp = Instance.new("Explosion")
                    exp.Position = arrow.Position
                    exp.BlastRadius = 15
                    exp.BlastPressure = 5e5
                    exp.Parent = workspace
                    -- Damage all enemies in explosion radius
                    for _, obj in ipairs(workspace:GetDescendants()) do
                        pcall(function()
                            if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                                local oh = humanoidOf(obj); local ot = rootOf(obj)
                                if oh and ot and (ot.Position - arrow.Position).Magnitude < 20 then
                                    oh:TakeDamage(30)
                                    local kbv = Instance.new("BodyVelocity")
                                    kbv.Velocity = (ot.Position - arrow.Position).Unit * 50 + Vector3.new(0, 30, 0)
                                    kbv.MaxForce = Vector3.new(1e5, 1e5, 1e5)
                                    kbv.Parent = ot
                                    Debris:AddItem(kbv, 0.4)
                                end
                            end
                        end)
                    end
                    arrow:Destroy()
                elseif part.Anchored and not part:IsDescendantOf(model) then
                    hit = true
                    playSukunaSound("ArrowExplode.mp3", 1, workspace)
                    local exp = Instance.new("Explosion")
                    exp.Position = arrow.Position
                    exp.BlastRadius = 15
                    exp.BlastPressure = 5e5
                    exp.Parent = workspace
                    arrow:Destroy()
                end
            end)
        end

        -- WORLD-CUTTING SLASH: fast piercing projectile
        local function worldCuttingSlash(targetPos)
            safeChat(head, "World-Cutting Slash!", Enum.ChatColor.Red)
            playSukunaSound("SLASH.mp3", 1, workspace)
            local origin = rp.Position + Vector3.new(0, 3, 0)
            local dir = (targetPos - origin)
            if dir.Magnitude < 0.1 then return end
            dir = dir.Unit
            local slash = Instance.new("Part")
            slash.Size = Vector3.new(0.3, 8, 0.3)
            slash.Color = Color3.fromRGB(200, 0, 0)
            slash.Material = Enum.Material.Neon
            slash.CFrame = CFrame.new(origin, origin + dir) * CFrame.Angles(math.rad(90), 0, 0)
            slash.CanCollide = false
            slash.Parent = workspace
            local bv = Instance.new("BodyVelocity")
            bv.Velocity = dir * 250
            bv.MaxForce = Vector3.new(1e5, 1e5, 1e5)
            bv.Parent = slash
            Debris:AddItem(slash, 3)
            -- Hit detection: damage everything the slash passes through
            local hitSet = {}
            slash.Touched:Connect(function(part)
                local m = part.Parent
                if m and not hitSet[m] and m ~= model and not isNoobTeam(m) then
                    local ph = humanoidOf(m)
                    if ph and ph ~= h then
                        hitSet[m] = true
                        ph:TakeDamage(35)
                        -- Knockback along slash direction
                        local tr = rootOf(m)
                        if tr then
                            local kbv = Instance.new("BodyVelocity")
                            kbv.Velocity = dir * 60 + Vector3.new(0, 20, 0)
                            kbv.MaxForce = Vector3.new(1e5, 1e5, 1e5)
                            kbv.Parent = tr
                            Debris:AddItem(kbv, 0.3)
                        end
                    end
                end
            end)
        end

        -- RUSH BEATDOWN: sprint at target and combo
        local function rushBeatdown(targetHum, targetPos)
            safeChat(head, "HAHAHA!", Enum.ChatColor.Red)
            playSukunaSound("HAHAHA.mp3", 1, workspace)
            local origSpeed = h.WalkSpeed
            h.WalkSpeed = 60
            local startTime = os.clock()
            -- Rush + combo for 4 seconds
            task.spawn(function()
                while os.clock() - startTime < 4 do
                    if not isAlive(h) or not targetHum or not targetHum.Parent or targetHum.Health <= 0 then break end
                    local tp = posOf(targetHum.Parent)
                    if tp then
                        pathTo(tp)
                        local d = (tp - rp.Position).Magnitude
                        if d < 8 then
                            targetHum:TakeDamage(15)
                            -- Slash visual
                            local slash = Instance.new("Part")
                            slash.Size = Vector3.new(0.2, 6, 6)
                            slash.Color = Color3.fromRGB(255, 0, 0)
                            slash.Material = Enum.Material.Neon
                            slash.Anchored = true
                            slash.CanCollide = false
                            slash.CFrame = rp.CFrame * CFrame.Angles(math.rad(math.random(0, 360)), math.rad(math.random(0, 360)), math.rad(math.random(0, 360)))
                            slash.Parent = workspace
                            Debris:AddItem(slash, 0.2)
                        end
                    end
                    task.wait(0.2)
                end
                h.WalkSpeed = origSpeed
            end)
        end

        task.spawn(function()
            -- Awaken after 3 seconds
            task.wait(3)
            pcall(awaken)
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Priority 1: intercept threats to player
                if interceptThreatToPlayer(80, 8, function(t, d)
                    if d < 8 then t:TakeDamage(20) end
                end) then
                    didSomething = true
                end
                -- Priority 2: hunt killers (long range)
                local killer, kdist = scanForKillers(300)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist > 30 then
                            pathTo(tp)
                            -- Fire world-cutting slash at long range
                            slashCooldown = slashCooldown + 1
                            if slashCooldown >= 5 then
                                slashCooldown = 0
                                pcall(function() worldCuttingSlash(tp) end)
                            end
                        elseif kdist < 12 then
                            -- Close range: rush beatdown
                            rushCooldown = rushCooldown + 1
                            if rushCooldown >= 10 then
                                rushCooldown = 0
                                pcall(function() rushBeatdown(killer, tp) end)
                            else
                                killer:TakeDamage(25)
                            end
                        else
                            -- Medium range: furnace arrow
                            furnaceCooldown = furnaceCooldown + 1
                            if furnaceCooldown >= 12 then
                                furnaceCooldown = 0
                                pcall(function() furnaceArrow(tp) end)
                            else
                                pathTo(tp)
                            end
                        end
                        didSomething = true
                    end
                end
                -- Priority 3: hunt any enemy
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 200)
                    if enemy and edist > 30 then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            pathTo(tp)
                            slashCooldown = slashCooldown + 1
                            if slashCooldown >= 5 then
                                slashCooldown = 0
                                pcall(function() worldCuttingSlash(tp) end)
                            end
                            didSomething = true
                        end
                    elseif enemy and edist < 8 then
                        enemy:TakeDamage(25)
                        didSomething = true
                    end
                end
                -- Domain Expansion: every 60s (rare big ability)
                domainCooldown = domainCooldown + 1
                if domainCooldown >= 60 then
                    domainCooldown = 0
                    -- Use nearest enemy/killer/player position as domain center
                    local ppos = getPlayerPos()
                    local killer, kdist = scanForKillers(80)
                    local domainPos = ppos
                    if killer then
                        local kpos = posOf(killer.Parent)
                        if kpos then domainPos = (ppos + kpos) / 2 end
                    end
                    task.spawn(function() pcall(malevolentShrine, domainPos) end)
                end
                -- Otherwise return to player
                if not didSomething then
                    returnToPlayer(30)
                    if math.random() > 0.7 then
                        safeChat(head, "Stand aside.", Enum.ChatColor.Red)
                    end
                end
                task.wait(1)
            end
        end)

    -- COMEDIC NOOB (v9.2.5 — UPGRADED WITH COMEDIC CHAOS ABILITIES)
    -- Inspired by the Comedic Chaos script. Now has 4 active abilities:
    --   1. CHAIR SWING — melee bonk with rainbow chair, ragdolls + flings
    --   2. SODA BOMB — throws a soda can that explodes (AoE + ragdoll)
    --   3. ROCKET LAUNCHER — fires a guided rainbow rocket
    --   4. COMEDIC JOKES — puns that slow enemies (existing ability)
    -- All damage adapted to respect isNoobTeam (no friendly fire on player).
    elseif characterType == "comedian_noob" then
        h.WalkSpeed = 16
        h.MaxHealth = 200; h.Health = 200
        colorModel(model, Color3.fromRGB(255, 220, 100))
        -- Top hat visual
        if head then
            local hat = Instance.new("Part")
            hat.Size = Vector3.new(1.4, 1.2, 1.4)
            hat.Color = Color3.fromRGB(30, 30, 30)
            hat.Material = Enum.Material.SmoothPlastic
            hat.CanCollide = false
            hat.CFrame = head.CFrame * CFrame.new(0, 1.2, 0)
            hat.Parent = model
            local hw = Instance.new("WeldConstraint")
            hw.Part0 = head; hw.Part1 = hat; hw.Parent = head
        end
        local jokes = {
            "Why did the noob cross the road?","To get to the respawn!","Knock knock!",
            "Who's there? A noob!","Why don't noobs get sunburned?",
            "They always stay in the shade!","I'm on a seafood diet...","I see food and eat it!",
            "What do you call a noob in a suit?","A business noob!","Why are you so SLOW?",
            "Heard you like respawning!","Is that a low frame rate or are you just scared?",
        }
        -- Helper: ragdoll a target character (simplified for NPC use)
        local function ragdollEnemy(char)
            pcall(function()
                local human = char:FindFirstChildWhichIsA("Humanoid")
                if human then human.PlatformStand = true end
                for _, obj in pairs(char:GetChildren()) do
                    if obj:IsA("BasePart") then
                        for _, joint in pairs(obj:GetChildren()) do
                            if joint:IsA("Motor6D") then
                                local a0 = Instance.new("Attachment", joint.Part0)
                                a0.Name = "RagdollAttachment0"
                                a0.CFrame = joint.C0
                                local a1 = Instance.new("Attachment", joint.Part1)
                                a1.Name = "RagdollAttachment1"
                                a1.CFrame = joint.C1
                                local socket = Instance.new("BallSocketConstraint", joint.Part0)
                                socket.Attachment0 = a0
                                socket.Attachment1 = a1
                                socket.LimitsEnabled = true
                                socket.TwistLimitsEnabled = true
                                joint.Enabled = false
                            end
                        end
                    end
                end
            end)
        end
        -- Helper: rainbowify a part (cycles through colors)
        local function rainbowify(part)
            task.spawn(function()
                while part and part.Parent do
                    for hue = 0, 1, 0.06 do
                        if not part or not part.Parent then return end
                        pcall(function() part.Color = Color3.fromHSV(hue, 1, 1) end)
                        task.wait(0.05)
                    end
                end
            end)
        end
        -- ABILITY 1: CHAIR SWING — melee bonk with rainbow chair
        local chairCooldown = 0
        local function chairSwing(targetHum)
            if not targetHum or not targetHum.Parent then return end
            local targetChar = targetHum.Parent
            local targetRoot = rootOf(targetChar)
            if not targetRoot then return end
            safeChat(head, "BONK!", Enum.ChatColor.Yellow)
            -- Spawn rainbow chair welded to right arm
            local rArm = model:FindFirstChild("Right Arm")
            if not rArm then return end
            local chair = Instance.new("Part")
