            chair.Transparency = 1
            chair.CanCollide = false
            chair.CFrame = rArm.CFrame * CFrame.new(-1.5, -3.5, -1)
            chair.Parent = workspace
            local mesh = Instance.new("SpecialMesh", chair)
            mesh.MeshId = "rbxassetid://5784453173"
            mesh.TextureId = "rbxassetid://5784453259"
