            -- Fade in
            TweenService:Create(chair, TweenInfo.new(0.2), {Transparency = 0}):Play()
            task.wait(0.25)
            -- Damage + ragdoll + fling the target
            pcall(function()
                targetHum:TakeDamage(40)
                ragdollEnemy(targetChar)
                local bv = Instance.new("BodyVelocity", targetRoot)
