                Debris:AddItem(bv, 0.2)
            end)
            -- "BONK!" billboard on target's head
            pcall(function()
                local targetHead = targetChar:FindFirstChild("Head")
                if targetHead then
                    local bb = Instance.new("BillboardGui")
                    bb.AlwaysOnTop = true
                    bb.StudsOffset = Vector3.new(0, 2, 0)
