                    Debris:AddItem(bb, 2)
                    TweenService:Create(bb, TweenInfo.new(1.5), {StudsOffset = Vector3.new(0, 4, 0), Size = UDim2.fromScale(4, 4)}):Play()
                    TweenService:Create(img, TweenInfo.new(2), {ImageTransparency = 1}):Play()
                end
            end)
            task.wait(0.3)
            chair:Destroy()
