        -- ABILITY 2: SODA BOMB — throws a soda can that explodes after 2s
        local sodaCooldown = 0
        local function sodaBomb(targetPos)
            safeChat(head, "Taste the fizz!", Enum.ChatColor.Yellow)
            local rArm = model:FindFirstChild("Right Arm")
            if not rArm then return end
            local soda = Instance.new("Part")
            soda.Size = Vector3.new(0.5, 1, 0.5)
            soda.Color = Color3.fromRGB(99, 95, 98)
            soda.Material = Enum.Material.SmoothPlastic
            soda.CanCollide = false
            soda.CFrame = rArm.CFrame * CFrame.new(-0.25, -1, 0) * CFrame.Angles(math.rad(-90), 0, 0)
            soda.Parent = workspace
            local mesh = Instance.new("SpecialMesh", soda)
            mesh.MeshId = "rbxassetid://1032879482"
            mesh.TextureId = "rbxassetid://1032879491"
            mesh.Scale = Vector3.new(0.2, 0.2, 0.2)
            rainbowify(soda)
            -- Launch toward target
            local bv = Instance.new("BodyVelocity", soda)
            bv.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
            bv.Velocity = (targetPos - soda.Position).Unit * 80
            Debris:AddItem(bv, 0.15)
            soda.RotVelocity = Vector3.new(100, 0, 0)
            Debris:AddItem(soda, 5)
            -- Trail
            local a0 = Instance.new("Attachment", soda); a0.Position = Vector3.new(0, 0.25, 0)
            local a1 = Instance.new("Attachment", soda); a1.Position = Vector3.new(0, -0.25, 0)
            local trail = Instance.new("Trail", soda)
            trail.FaceCamera = true
            trail.Lifetime = 0.4
            trail.Attachment0 = a0; trail.Attachment1 = a1
            -- Explode after 2 seconds
            task.delay(2, function()
                if not soda or not soda.Parent then return end
                local pos = soda.Position
                -- Visual explosion
                for i = 1, 15 do
                    task.spawn(function()
                        local p = Instance.new("Part")
                        p.Anchored = true
                        p.CanCollide = false
                        p.Color = Color3.fromRGB(255, 150, 0)
                        p.Material = Enum.Material.Neon
                        p.CFrame = CFrame.new(pos) * CFrame.Angles(math.rad(math.random(0, 360)), math.rad(math.random(0, 360)), math.rad(math.random(0, 360)))
                        p.Size = Vector3.new(math.random(5, 15), math.random(5, 15), math.random(10, 30))
                        p.Parent = workspace
                        TweenService:Create(p, TweenInfo.new(0.5), {Size = Vector3.new(0, 0, 0), Transparency = 1}):Play()
                        Debris:AddItem(p, 0.6)
                    end)
                end
                local exp = Instance.new("Explosion")
                exp.Position = pos
                exp.BlastRadius = 20
                exp.BlastPressure = 3e5
                exp.Parent = workspace
                -- Damage + ragdoll all enemies in radius
                for _, obj in ipairs(workspace:GetDescendants()) do
                    pcall(function()
                        if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                            local oh = humanoidOf(obj); local ot = rootOf(obj)
                            if oh and ot and (ot.Position - pos).Magnitude < 25 then
                                oh:TakeDamage(50)
                                ragdollEnemy(obj)
                                local bv2 = Instance.new("BodyVelocity", ot)
                                bv2.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
                                bv2.Velocity = (ot.Position - pos).Unit * 100 + Vector3.new(0, 50, 0)
                                Debris:AddItem(bv2, 0.15)
                            end
                        end
                    end)
                end
                soda:Destroy()
            end)
        end
        -- ABILITY 3: ROCKET LAUNCHER — fires a guided rainbow rocket
        local rocketCooldown = 0
