            Debris:AddItem(rocket, 8)
            -- Guided: adjust velocity toward target
            task.spawn(function()
                while rocket and rocket.Parent do
                    pcall(function()
                        bv.Velocity = (targetPos - rocket.Position).Unit * 200
                        rocket.CFrame = CFrame.new(rocket.Position, targetPos)
                    end)
                    task.wait(0.1)
                end
            end)
            local hit = false
            rocket.Touched:Connect(function(part)
                if hit then return end
                local m = part.Parent
                if m and m ~= model and not isNoobTeam(m) and not part:IsDescendantOf(model) then
                    hit = true
                    local pos = rocket.Position
                    local exp = Instance.new("Explosion")
                    exp.Position = pos
                    exp.BlastRadius = 15
                    exp.BlastPressure = 5e5
                    exp.Parent = workspace
                    -- Damage + ragdoll all enemies in radius
                    for _, obj in ipairs(workspace:GetDescendants()) do
                        pcall(function()
                            if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                                local oh = humanoidOf(obj); local ot = rootOf(obj)
                                if oh and ot and (ot.Position - pos).Magnitude < 20 then
                                    oh:TakeDamage(60)
                                    ragdollEnemy(obj)
                                    local bv2 = Instance.new("BodyVelocity", ot)
                                    bv2.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
                                    bv2.Velocity = (ot.Position - pos).Unit * 150 + Vector3.new(0, 50, 0)
                                    Debris:AddItem(bv2, 0.15)
                                end
                            end
                        end)
                    end
                    rocket:Destroy()
                end
            end)
        end
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Find nearest enemy/killer (priority: killers, then any enemy)
                local killer, kdist = scanForKillers(150)
                local enemy, edist = killer or findNearest(rp.Position, model, 120), kdist or edist
                if not enemy then
                    enemy, edist = findNearest(rp.Position, model, 120)
                end
                if enemy then
                    local tp = posOf(enemy.Parent)
                    if tp then
                        if edist > 30 then
                            -- Long range: rocket launcher
                            rocketCooldown = rocketCooldown + 1
                            if rocketCooldown >= 12 then
                                rocketCooldown = 0
                                pcall(function() rocketLauncher(tp) end)
                            else
                                pathTo(tp)
                            end
                        elseif edist > 15 then
                            -- Medium range: soda bomb
                            sodaCooldown = sodaCooldown + 1
                            if sodaCooldown >= 8 then
                                sodaCooldown = 0
                                pcall(function() sodaBomb(tp) end)
                            else
                                pathTo(tp)
                            end
                        else
                            -- Close range: chair swing
                            chairCooldown = chairCooldown + 1
                            if chairCooldown >= 4 then
                                chairCooldown = 0
                                pcall(function() chairSwing(enemy) end)
                            else
                                enemy:TakeDamage(15)
                                safeChat(head, jokes[math.random(1,#jokes)], Enum.ChatColor.Yellow)
                            end
                        end
                        didSomething = true
                    end
                end
                -- Defensive: intercept threats to player
                if not didSomething and interceptThreatToPlayer(70, 8, function(t, d)
                    if d < 8 then
                        chairCooldown = chairCooldown + 1
                        if chairCooldown >= 4 then
                            chairCooldown = 0
                            pcall(function() chairSwing(t) end)
                        else
                            t:TakeDamage(15)
                        end
                    end
                end) then
                    didSomething = true
                end
                -- Otherwise return to player
                if not didSomething then
                    returnToPlayer(35)
                    if math.random() > 0.7 then
                        safeChat(head, jokes[math.random(1,#jokes)], Enum.ChatColor.Yellow)
                    end
                end
                task.wait(1)
            end
        end)

