    -- BUFF NOOB (Big Daddy-inspired) ──────────────────────────
    -- A massive tanky supporter. 800 HP (like Big Daddy's MaxHealth=800).
    -- Periodically emits a BUFF AURA that heals nearby allies, boosts
    -- their MaxHealth, and increases their WalkSpeed. Also taunts
    -- enemies to draw aggro and body-blocks for the player.
    elseif characterType == "buff_noob" then
        h.WalkSpeed = 14
        h.MaxHealth = 800; h.Health = 800  -- Big Daddy's MaxHealth = 800
        -- Big beefy appearance: dark metal with gold trim
        colorModel(model, Color3.fromRGB(80, 80, 90), Enum.Material.Metal)
        for _, p in pairs(model:GetDescendants()) do
            if p:IsA("BasePart") and p.Name ~= "HumanoidRootPart" then
                p.Size = p.Size * 1.8  -- bigger than normal
            end
        end
        -- Golden aura light
        local buffLight = Instance.new("PointLight")
        buffLight.Color = Color3.fromRGB(255, 215, 0)
        buffLight.Brightness = 5
        buffLight.Range = 25
        buffLight.Parent = rp
        -- Golden aura particles
        local buffAura = Instance.new("ParticleEmitter")
        buffAura.Color = ColorSequence.new(Color3.fromRGB(255, 215, 0))
        buffAura.Size = NumberSequence.new({NumberSequenceKeypoint.new(0,1.5), NumberSequenceKeypoint.new(1,0)})
        buffAura.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0,0.3), NumberSequenceKeypoint.new(1,1)})
        buffAura.Lifetime = NumberRange.new(0.5, 1.0)
        buffAura.Rate = 20
        buffAura.Speed = NumberRange.new(1, 3)
        buffAura.Parent = rp
        -- Visible ForceField (invincible-looking)
        local ff = Instance.new("ForceField")
        ff.Visible = true
        ff.Parent = model
        Debris:AddItem(ff, NOOB_LIFETIME)
        local buffPhrases = {
            "Big Daddy is here!","I'll protect you all!","Stand behind me!",
            "Feel my buff!","None shall pass!","I am the wall!",
        }
        -- v9.2.6 BUFF AURA: heals + boosts all nearby allies (including player)
        local buffCooldown = 0
        local function buffAuraPulse()
            safeChat(head, "BUFF AURA!", Enum.ChatColor.Yellow)
            -- Visual: expanding golden ring
            local ring = Instance.new("Part")
            ring.Shape = Enum.PartType.Cylinder
            ring.Size = Vector3.new(0.3, 6, 6)
            ring.Color = Color3.fromRGB(255, 215, 0)
            ring.Material = Enum.Material.Neon
            ring.Anchored = true
            ring.CanCollide = false
            ring.CFrame = CFrame.new(rp.Position) * CFrame.Angles(0, 0, math.pi/2)
            ring.Parent = workspace
            Debris:AddItem(ring, 0.6)
            TweenService:Create(ring, TweenInfo.new(0.5), {
                Size = Vector3.new(0.3, 40, 40),
                Transparency = 1
            }):Play()
            -- Buff all allies in radius (including local player)
            local buffedCount = 0
            -- Buff the local player
            local pchar = getPlayerChar()
            if pchar then
                local ph = humanoidOf(pchar)
                if ph and ph.Health > 0 then
                    pcall(function()
                        ph.MaxHealth = math.max(ph.MaxHealth, 200)
                        ph.Health = math.min(ph.Health + 30, ph.MaxHealth)
                        ph.WalkSpeed = math.min(ph.WalkSpeed + 4, 40)
                    end)
                    buffedCount = buffedCount + 1
                end
            end
            -- Buff all noob allies
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and (ot.Position - rp.Position).Magnitude < 35 then
                            oh.MaxHealth = math.max(oh.MaxHealth, 200)
                            oh.Health = math.min(oh.Health + 25, oh.MaxHealth)
                            oh.WalkSpeed = math.min(oh.WalkSpeed + 4, 50)
                            buffedCount = buffedCount + 1
                            -- Visual: golden sparkles on buffed ally
                            local spark = Instance.new("Sparkles")
                            spark.Color = Color3.fromRGB(255, 215, 0)
                            spark.Parent = ot
                            Debris:AddItem(spark, 2)
                        end
                    end
                end)
            end
            if buffedCount > 0 then
                safeChat(head, "Buffed "..buffedCount.." allies!", Enum.ChatColor.Yellow)
            end
        end
        -- v9.2.6 TAUNT: draws nearby enemies toward the buff noob
        local tauntCooldown = 0
        local function taunt()
            safeChat(head, "COME FIGHT ME!", Enum.ChatColor.Yellow)
            -- Visual: red shockwave
            local wave = Instance.new("Part")
            wave.Shape = Enum.PartType.Cylinder
            wave.Size = Vector3.new(0.2, 4, 4)
            wave.Color = Color3.fromRGB(255, 50, 50)
            wave.Material = Enum.Material.Neon
            wave.Anchored = true
            wave.CanCollide = false
            wave.CFrame = CFrame.new(rp.Position) * CFrame.Angles(0, 0, math.pi/2)
            wave.Parent = workspace
            Debris:AddItem(wave, 0.5)
            TweenService:Create(wave, TweenInfo.new(0.4), {
                Size = Vector3.new(0.2, 25, 25),
                Transparency = 1
            }):Play()
            -- Force all nearby enemies to target the buff noob (move toward it)
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and (ot.Position - rp.Position).Magnitude < 30 then
                            -- Slow them (they're "stunned" by the taunt)
                            oh.WalkSpeed = math.max(oh.WalkSpeed - 6, 1)
                            -- Damage them slightly
                            oh:TakeDamage(10)
                        end
                    end
                end)
            end
        end
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Priority 1: intercept threats to the player (body-block)
                local ppos = getPlayerPos()
                local threat, tdist = findThreatToPlayer(80)
                if threat and ppos then
                    local tp = posOf(threat.Parent)
                    if tp then
                        -- Stand between player and threat
                        local interceptPos = (ppos + tp) / 2
                        pathTo(interceptPos)
                        local myDist = (tp - rp.Position).Magnitude
                        if myDist < 10 then
                            threat:TakeDamage(30)
                            -- Knockback
                            local tr = rootOf(threat.Parent)
                            if tr then
                                local kbv = Instance.new("BodyVelocity")
                                kbv.Velocity = (tr.Position - rp.Position).Unit * 45 + Vector3.new(0, 15, 0)
                                kbv.MaxForce = Vector3.new(1e5, 1e5, 1e5)
                                kbv.Parent = tr
                                Debris:AddItem(kbv, 0.3)
                            end
                        end
                        didSomething = true
                    end
                end
                -- Priority 2: hunt killers
                if not didSomething then
                    local killer, kdist = scanForKillers(150)
                    if killer then
                        local tp = posOf(killer.Parent)
                        if tp then
                            pathTo(tp)
                            if kdist < 10 then killer:TakeDamage(35) end
                            didSomething = true
                        end
                    end
                end
                -- Priority 3: hunt any enemy
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 100)
                    if enemy and edist > 15 then
                        local tp = posOf(enemy.Parent)
                        if tp then pathTo(tp); didSomething = true end
                    elseif enemy and edist < 10 then
                        enemy:TakeDamage(30)
                        didSomething = true
                    end
                end
                -- Buff Aura: every 8 seconds
                buffCooldown = buffCooldown + 1
                if buffCooldown >= 8 then
                    buffCooldown = 0
                    pcall(buffAuraPulse)
                end
                -- Taunt: every 12 seconds
                tauntCooldown = tauntCooldown + 1
                if tauntCooldown >= 12 then
                    tauntCooldown = 0
                    pcall(taunt)
                end
                -- Otherwise stay near player
                if not didSomething then
                    returnToPlayer(25)
                    if math.random() > 0.7 then
                        safeChat(head, buffPhrases[math.random(1,#buffPhrases)], Enum.ChatColor.Yellow)
                    end
                end
                task.wait(1)
            end
        end)

    -- MASK NOOB (Mask script-inspired) ────────────────────────
    -- Downloads Mask.mp3. One-time MASK TRANSFORMATION that plays the
    -- song, changes appearance (hooded/masked), and grants new abilities.
    -- Abilities: GROUND STRIKE (AoE + spikes), NECKSNAP (ragdoll + kill
    -- a nearby enemy), WARP (teleport to nearest enemy).
    -- Creepy chat messages from the original script.
    elseif characterType == "mask_noob" then
        h.WalkSpeed = 16
        h.MaxHealth = 400; h.Health = 400
        -- Start normal-looking
        colorModel(model, Color3.fromRGB(100, 100, 100))
        -- Download Mask.mp3
        local maskSound = nil
        pcall(function()
            if not isfile("Mask.mp3") then
                writefile("Mask.mp3", game:HttpGet("https://github.com/ian49972/smth/raw/refs/heads/main/Mask.mp3"))
            end
            maskSound = Instance.new("Sound")
            maskSound.SoundId = getcustomasset("Mask.mp3")
            maskSound.Volume = 0.8
            maskSound.Looped = true
            maskSound.Parent = rp
        end)
        local maskPhrases = {
            "It burns.","It's gone.","Something...Is missing.","Why is this happening?",
            "I've been poisoned.","I Feel sick.","...","Taste the blood","Its murder,",
            "Was it worth it?","This is your fault,","You chose this path.",
        }
        local transformed = false
        local groundStrikeCooldown = 0
        local necksnapCooldown = 0
        local warpCooldown = 0
        -- v9.2.6 MASK TRANSFORMATION: one-time transformation
        local function transform()
            if transformed then return end
            transformed = true
            safeChat(head, "...", Enum.ChatColor.White)
            task.wait(1)
            safeChat(head, "Taste the blood", Enum.ChatColor.Red)
            -- Play Mask.mp3
            if maskSound then
                pcall(function()
                    maskSound.TimePosition = 35.5  -- skip intro (from original script)
                    maskSound:Play()
                end)
            end
            -- Visual transformation: recolor to dark red and black
            colorModel(model, Color3.fromRGB(30, 0, 0))
            -- Add a hood/mask visual (dark part over the head)
            if head then
                local hood = Instance.new("Part")
                hood.Size = Vector3.new(1.4, 1.6, 1.4)
                hood.Color = Color3.fromRGB(15, 0, 0)
                hood.Material = Enum.Material.SmoothPlastic
                hood.CanCollide = false
                hood.CFrame = head.CFrame * CFrame.new(0, 0.3, 0)
                hood.Parent = model
                local hw = Instance.new("WeldConstraint")
                hw.Part0 = head; hw.Part1 = hood; hw.Parent = head
                -- Red glowing eyes
                local eyeLight = Instance.new("PointLight")
                eyeLight.Color = Color3.fromRGB(255, 0, 0)
                eyeLight.Brightness = 5
                eyeLight.Range = 15
                eyeLight.Parent = head
                -- Change face to red
                local faceDecal = head:FindFirstChildOfClass("Decal")
                if not faceDecal then
                    faceDecal = Instance.new("Decal")
                    faceDecal.Name = "face"
                    faceDecal.Parent = head
                end
                pcall(function() faceDecal.Texture = "rbxassetid://0" end)  -- blank face
            end
            -- Dark aura
            local darkSmoke = Instance.new("Smoke")
            darkSmoke.Color = Color3.fromRGB(50, 0, 0)
            darkSmoke.Opacity = 0.5
            darkSmoke.RiseVelocity = 1.5
            darkSmoke.Size = 6
            darkSmoke.Parent = rp
            -- Transformation visual: red shockwave
            local wave = Instance.new("Part")
            wave.Shape = Enum.PartType.Cylinder
            wave.Size = Vector3.new(0.3, 4, 4)
            wave.Color = Color3.fromRGB(255, 0, 0)
            wave.Material = Enum.Material.Neon
            wave.Anchored = true
            wave.CanCollide = false
            wave.CFrame = CFrame.new(rp.Position) * CFrame.Angles(0, 0, math.pi/2)
            wave.Parent = workspace
            Debris:AddItem(wave, 0.8)
            TweenService:Create(wave, TweenInfo.new(0.7), {
                Size = Vector3.new(0.3, 50, 50),
                Transparency = 1
            }):Play()
            -- Camera shake during transformation
            local camera = workspace.CurrentCamera
            if camera then
                task.spawn(function()
                    local t0 = os.clock()
                    while os.clock() - t0 < 2 do
                        camera.CFrame = camera.CFrame * CFrame.Angles(
                            math.rad(math.random(-2, 2) * 0.4),
                            math.rad(math.random(-2, 2) * 0.4),
                            math.rad(math.random(-2, 2) * 0.4)
                        )
                        task.wait()
                    end
                end)
            end
            safeChat(head, "Its murder,", Enum.ChatColor.Red)
            task.wait(2)
            safeChat(head, "Was it worth it?", Enum.ChatColor.Red)
        end
        -- v9.2.6 GROUND STRIKE: AoE damage + spikes (from original script)
        local function groundStrike()
            safeChat(head, "GROUND STRIKE!", Enum.ChatColor.Red)
            -- Visual: expanding red shockwave
            local wave = Instance.new("Part")
            wave.Shape = Enum.PartType.Cylinder
            wave.Size = Vector3.new(0.4, 6, 6)
            wave.Color = Color3.fromRGB(255, 0, 0)
            wave.Material = Enum.Material.Neon
            wave.Anchored = true
            wave.CanCollide = false
            wave.CFrame = CFrame.new(rp.Position) * CFrame.Angles(0, 0, math.pi/2)
            wave.Parent = workspace
            Debris:AddItem(wave, 0.8)
            TweenService:Create(wave, TweenInfo.new(0.6), {
                Size = Vector3.new(0.4, 35, 35),
                Transparency = 1
            }):Play()
            -- Spawn red spikes from the ground
            for i = 1, 10 do
                task.spawn(function()
                    local spike = Instance.new("Part")
                    spike.Size = Vector3.new(1, math.random(10, 20), 1)
                    spike.Color = Color3.fromRGB(math.random(100, 255), 0, 0)
                    spike.Material = Enum.Material.Plastic
                    spike.Anchored = true
                    spike.CanCollide = false
                    local offset = Vector3.new(math.random(-15, 15), 0, math.random(-15, 15))
                    spike.CFrame = CFrame.new(rp.Position + offset) * CFrame.Angles(math.rad(math.random(-20, 20)), math.rad(math.random(0, 360)), math.rad(math.random(-20, 20)))
                    spike.Parent = workspace
                    Debris:AddItem(spike, 2)
                    TweenService:Create(spike, TweenInfo.new(1), {Transparency = 1}):Play()
                end)
            end
            -- Damage + fling all enemies in radius (INSTAKILL like the original)
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and (ot.Position - rp.Position).Magnitude < 25 then
                            oh:TakeDamage(80)
                            local kbv = Instance.new("BodyVelocity")
                            kbv.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
                            kbv.Velocity = (ot.Position - rp.Position).Unit * 200 + Vector3.new(0, 50, 0)
                            kbv.Parent = ot
                            Debris:AddItem(kbv, 0.1)
                        end
                    end
                end)
            end
            -- Camera shake
            local camera = workspace.CurrentCamera
            if camera then
                task.spawn(function()
                    local t0 = os.clock()
                    while os.clock() - t0 < 0.5 do
                        camera.CFrame = camera.CFrame * CFrame.Angles(
                            math.rad(math.random(-3, 3) * 0.3),
                            math.rad(math.random(-3, 3) * 0.3),
                            math.rad(math.random(-3, 3) * 0.3)
                        )
                        task.wait()
                    end
                end)
            end
        end
        -- v9.2.6 NECKSNAP: grab + ragdoll + instakill a nearby enemy
        local function necksnap(targetHum)
            if not targetHum or not targetHum.Parent then return end
            local targetChar = targetHum.Parent
            local targetRoot = rootOf(targetChar)
            if not targetRoot then return end
            safeChat(head, "Neck snap.", Enum.ChatColor.Red)
            -- Teleport behind the target
            local tp = targetRoot.Position
            rp.CFrame = CFrame.new(tp + (tp - rp.Position).Unit * 2, tp)
            task.wait(0.3)
            -- Ragdoll the target
            pcall(function()
                targetHum.PlatformStand = true
                for _, obj in pairs(targetChar:GetChildren()) do
                    if obj:IsA("BasePart") then
                        for _, joint in pairs(obj:GetChildren()) do
                            if joint:IsA("Motor6D") then
                                local a0 = Instance.new("Attachment", joint.Part0)
                                a0.CFrame = joint.C0
                                local a1 = Instance.new("Attachment", joint.Part1)
                                a1.CFrame = joint.C1
                                local socket = Instance.new("BallSocketConstraint", joint.Part0)
                                socket.Attachment0 = a0
                                socket.Attachment1 = a1
                                socket.LimitsEnabled = true
                                socket.TwistLimitsEnabled = true
                                joint.Enabled = false
                            end
                        end
                    end
                end
            end)
            -- Instakill
            targetHum:TakeDamage(200)
            -- Visual: red slash effect at target
            local slash = Instance.new("Part")
            slash.Size = Vector3.new(0.2, 8, 8)
            slash.Color = Color3.fromRGB(255, 0, 0)
            slash.Material = Enum.Material.Neon
            slash.Anchored = true
            slash.CanCollide = false
            slash.CFrame = CFrame.new(tp) * CFrame.Angles(math.rad(math.random(0, 360)), math.rad(math.random(0, 360)), math.rad(math.random(0, 360)))
            slash.Parent = workspace
            Debris:AddItem(slash, 0.3)
            -- Fling the target
            local kbv = Instance.new("BodyVelocity")
            kbv.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
            kbv.Velocity = Vector3.new(0, 100, 0)
            kbv.Parent = targetRoot
            Debris:AddItem(kbv, 0.2)
            safeChat(head, "Was it worth it?", Enum.ChatColor.Red)
        end
        -- v9.2.6 WARP: teleport to a target position (from original script's Warp function)
        local function warp(targetPos)
            safeChat(head, "Warp.", Enum.ChatColor.White)
            -- Visual at origin
            local originPart = Instance.new("Part")
            originPart.Shape = Enum.PartType.Ball
            originPart.Size = Vector3.new(2, 2, 2)
            originPart.Color = Color3.fromRGB(100, 0, 0)
            originPart.Material = Enum.Material.Neon
            originPart.Anchored = true
            originPart.CanCollide = false
            originPart.CFrame = CFrame.new(rp.Position)
            originPart.Parent = workspace
            Debris:AddItem(originPart, 0.5)
            TweenService:Create(originPart, TweenInfo.new(0.4), {Size = Vector3.new(0, 0, 0), Transparency = 1}):Play()
            -- Teleport
            rp.CFrame = CFrame.new(targetPos)
            -- Visual at destination
            local destPart = Instance.new("Part")
            destPart.Shape = Enum.PartType.Ball
            destPart.Size = Vector3.new(0, 0, 0)
            destPart.Color = Color3.fromRGB(255, 0, 0)
            destPart.Material = Enum.Material.Neon
            destPart.Anchored = true
            destPart.CanCollide = false
            destPart.CFrame = CFrame.new(targetPos)
            destPart.Parent = workspace
            Debris:AddItem(destPart, 0.5)
            TweenService:Create(destPart, TweenInfo.new(0.4), {Size = Vector3.new(4, 4, 4), Transparency = 1}):Play()
        end
        task.spawn(function()
            -- Transform after 3 seconds
            task.wait(3)
            pcall(transform)
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Priority 1: intercept threats to player
                if interceptThreatToPlayer(70, 8, function(t, d)
                    if d < 8 then
                        -- Necksnap if off cooldown
                        necksnapCooldown = necksnapCooldown + 1
                        if necksnapCooldown >= 10 then
                            necksnapCooldown = 0
                            pcall(function() necksnap(t) end)
                        else
                            t:TakeDamage(25)
                        end
                    end
                end) then
                    didSomething = true
                end
                -- Priority 2: hunt killers (long range — warp to them)
                local killer, kdist = scanForKillers(200)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist > 40 then
                            -- Warp to the killer
                            warpCooldown = warpCooldown + 1
                            if warpCooldown >= 8 then
                                warpCooldown = 0
                                pcall(function() warp(tp) end)
                            else
                                pathTo(tp)
                            end
                        elseif kdist < 12 then
                            -- Close range: ground strike or necksnap
                            groundStrikeCooldown = groundStrikeCooldown + 1
                            if groundStrikeCooldown >= 8 then
                                groundStrikeCooldown = 0
                                pcall(groundStrike)
                            else
                                necksnapCooldown = necksnapCooldown + 1
                                if necksnapCooldown >= 10 then
                                    necksnapCooldown = 0
                                    pcall(function() necksnap(killer) end)
                                else
                                    killer:TakeDamage(30)
                                end
                            end
                        else
                            pathTo(tp)
                        end
                        didSomething = true
                    end
                end
                -- Priority 3: hunt any enemy
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 150)
                    if enemy and edist > 40 then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            warpCooldown = warpCooldown + 1
                            if warpCooldown >= 8 then
                                warpCooldown = 0
                                pcall(function() warp(tp) end)
                            else
                                pathTo(tp)
                            end
                            didSomething = true
                        end
                    elseif enemy and edist < 12 then
                        groundStrikeCooldown = groundStrikeCooldown + 1
                        if groundStrikeCooldown >= 8 then
                            groundStrikeCooldown = 0
                            pcall(groundStrike)
                        else
                            enemy:TakeDamage(30)
                        end
                        didSomething = true
                    end
                end
                -- Otherwise return to player
                if not didSomething then
                    returnToPlayer(30)
                    if math.random() > 0.7 then
                        safeChat(head, maskPhrases[math.random(1,#maskPhrases)], Enum.ChatColor.White)
                    end
                end
                task.wait(1)
            end
            -- Cleanup sound on death
            if maskSound then pcall(function() maskSound:Stop() maskSound:Destroy() end) end
        end)

