    -- GONER NOOB ───────────────────────────────────────────────
    -- A creepy horror executioner adapted from the Goner script
    -- (rbxassetid://4513235536). 3000 HP (matches the original's
    -- MaxHealth=3000). Wields a sword. All 5 abilities from the
    -- original script, adapted for NPC use:
    --   1. SLASH — melee decapitation (Ragdoll + Dismember Head)
    --   2. EXECUTE — grab + dismember (head rip / leg cut / arm tear)
    --   3. SHRIEK — AoE scream that decapitates all enemies in 45 studs
    --   4. SUBMERGE — sink into ground, move to target, emerge to execute
    --   5. TV STATIC — applies static visual + sound to targets
    -- Plays BGM music (rbxassetid://2598782592) and uses all the
    -- original audio IDs for slash/snap/shriek/speak sounds.
    elseif characterType == "goner_noob" then
        h.WalkSpeed = 14
        h.MaxHealth = 3000; h.Health = 3000  -- Goner's MaxHealth = 3000
        -- Creepy dark appearance
        colorModel(model, Color3.fromRGB(20, 20, 25))
        for _, p in pairs(model:GetDescendants()) do
            if p:IsA("BasePart") then
                p.Material = Enum.Material.Slate
            end
        end
        -- Hide the original head's face (blank like Goner)
        if head then
            local faceDecal = head:FindFirstChildOfClass("Decal")
            if faceDecal then faceDecal.Transparency = 1 end
            -- Red glowing eyes
            local eyeLight = Instance.new("PointLight")
            eyeLight.Color = Color3.fromRGB(255, 255, 255)
            eyeLight.Brightness = 3
            eyeLight.Range = 12
            eyeLight.Parent = head
        end
        -- Dark smoke aura (Goner leaks black goo)
        local gonerSmoke = Instance.new("Smoke")
        gonerSmoke.Color = Color3.fromRGB(15, 15, 15)
        gonerSmoke.Opacity = 0.6
        gonerSmoke.RiseVelocity = 0.5
        gonerSmoke.Size = 5
        gonerSmoke.Parent = rp

        -- Sword visual (welded to right arm)
        local rArm = model:FindFirstChild("Right Arm")
        local sword = nil
        if rArm then
