        -- Helper: play a sound by ID (from the Goner script's NewSound)
        local function playGonerSound(soundId, volume, pitch, parent)
            pcall(function()
                local s = Instance.new("Sound")
                s.SoundId = "rbxassetid://" .. tostring(soundId)
                s.Volume = volume or 1
                s.Pitch = pitch or 1
                s.Parent = parent or workspace
                s:Play()
                Debris:AddItem(s, 10)
