        -- Helper: ragdoll + dismember a target (simplified from Goner's Dismember)
        local function dismember(targetChar, what)
            pcall(function()
                local hum = targetChar:FindFirstChildOfClass("Humanoid")
                if hum then
                    hum.PlatformStand = true
                    hum.Health = 0
                end
                -- Ragdoll: replace Motor6Ds with BallSocketConstraints
                for _, obj in pairs(targetChar:GetChildren()) do
                    if obj:IsA("BasePart") then
                        for _, joint in pairs(obj:GetChildren()) do
                            if joint:IsA("Motor6D") then
                                local a0 = Instance.new("Attachment", joint.Part0)
                                a0.CFrame = joint.C0
                                local a1 = Instance.new("Attachment", joint.Part1)
                                a1.CFrame = joint.C1
                                local socket = Instance.new("BallSocketConstraint", joint.Part0)
                                socket.Attachment0 = a0
                                socket.Attachment1 = a1
                                socket.LimitsEnabled = true
                                socket.TwistLimitsEnabled = true
                                joint.Enabled = false
                            end
                        end
                    end
                end
                -- Dismember specific parts
                if what == "Head" then
                    local hd = targetChar:FindFirstChild("Head")
                    if hd then hd:BreakJoints() end
                elseif what == "Legs" then
                    local t = targetChar:FindFirstChild("Torso") or targetChar:FindFirstChild("UpperTorso")
                    if t then
                        for _, c in pairs(targetChar:GetChildren()) do
                            if c.Name:find("Leg") or c.Name:find("leg") then
                                c:BreakJoints()
                            end
                        end
                    end
                elseif what == "LeftArm" then
                    local arm = targetChar:FindFirstChild("Left Arm") or targetChar:FindFirstChild("LeftUpperArm")
                    if arm then arm:BreakJoints() end
                elseif what == "RightArm" then
                    local arm = targetChar:FindFirstChild("Right Arm") or targetChar:FindFirstChild("RightUpperArm")
                    if arm then arm:BreakJoints() end
                end
            end)
        end

        -- Helper: blood particle burst (from Goner's OofOuchBlood)
        local function bloodBurst(position, amount)
            pcall(function()
                local p = Instance.new("Part")
                p.Size = Vector3.new(0.1, 0.1, 0.1)
                p.Transparency = 1
                p.Anchored = true
                p.CanCollide = false
                p.CFrame = CFrame.new(position)
                p.Parent = workspace
                Debris:AddItem(p, 2)
                local emit = Instance.new("ParticleEmitter")
                emit.Color = ColorSequence.new(Color3.fromRGB(120, 0, 0))
                emit.Size = NumberSequence.new({NumberSequenceKeypoint.new(0, 1), NumberSequenceKeypoint.new(1, 0)})
                emit.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0, 0), NumberSequenceKeypoint.new(1, 1)})
                emit.Lifetime = NumberRange.new(0.5, 1.5)
                emit.Speed = NumberRange.new(5, 15)
                emit.Rate = 0
                emit.Parent = p
                emit:Emit(amount or 30)
            end)
        end

