        -- Helper: apply TV static effect to a target (from Goner's GonerStatic)
        local function applyStatic(targetChar)
            pcall(function()
                -- Static sound
                local staticSound = Instance.new("Sound")
                staticSound.SoundId = "rbxassetid://2737898305"
                staticSound.Volume = 1
                staticSound.Looped = true
                staticSound.Parent = targetChar
                staticSound:Play()
                Debris:AddItem(staticSound, 5)
                -- Visual: flicker the target's parts
                task.spawn(function()
                    for i = 1, 20 do
                        for _, p in pairs(targetChar:GetDescendants()) do
                            if p:IsA("BasePart") then
                                pcall(function()
                                    if math.random() > 0.5 then
                                        p.Color = Color3.fromRGB(math.random(0, 255), math.random(0, 255), math.random(0, 255))
                                    end
                                end)
                            end
                        end
                        task.wait(0.1)
                    end
                end)
            end)
        end

        -- Helper: camera shake (from Goner's CameraShake)
        local function cameraShake(duration, intensity)
            local camera = workspace.CurrentCamera
            if not camera then return end
            task.spawn(function()
                local t0 = os.clock()
                while os.clock() - t0 < duration do
                    camera.CFrame = camera.CFrame * CFrame.Angles(
                        math.rad(math.random(-intensity, intensity) * 0.3),
                        math.rad(math.random(-intensity, intensity) * 0.3),
                        math.rad(math.random(-intensity, intensity) * 0.3)
                    )
                    task.wait()
                end
            end)
        end

        -- v9.2.7 ABILITY 1: SLASH — melee decapitation
        -- From Goner's Slash() function. Decapitates nearby enemies.
        local slashCooldown = 0
        local function gonerSlash()
            safeChat(head, "...", Enum.ChatColor.White)
            -- Sword trail on
            if sword and sword:FindFirstChild("Trail") then
                sword.Trail.Enabled = true
            end
            -- Slash sound (211059653)
            playGonerSound(211059653, 1, 0.7, sword)
            -- Check all enemies in melee range (4.5 studs in front)
            local hitPos = rp.CFrame * CFrame.new(0, 0, -2.5)
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and oh.Health > 0 then
                            if (ot.Position - hitPos.Position).Magnitude < 6 then
                                -- Change face to dead face (145854465)
                                local hd = obj:FindFirstChild("Head")
                                if hd then
                                    local face = hd:FindFirstChildOfClass("Decal")
                                    if face then
                                        pcall(function() face.Texture = "http://www.roblox.com/asset/?id=145854465" end)
                                        face.Transparency = 0.5
                                    end
                                end
                                -- Ragdoll + dismember head
                                dismember(obj, "Ragdoll")
                                dismember(obj, "Head")
                                -- Snap sound (264486467 + 150315649)
                                playGonerSound(264486467, 1, 0.7, ot)
                                playGonerSound(150315649, 2, 1, ot)
                                -- Blood
                                for i = 1, 7 do
                                    bloodBurst(ot.Position, 45)
                                end
                                -- Puddles
                                task.spawn(function()
                                    for i = 1, 10 do
                                        spawnPuddle(ot.Position)
                                        task.wait(0.1)
                                    end
                                end)
                            end
                        end
                    end
                end)
            end
            task.wait(0.3)
            if sword and sword:FindFirstChild("Trail") then
                sword.Trail.Enabled = false
            end
        end

        -- v9.2.7 ABILITY 2: EXECUTE — grab + dismember (head rip variant)
        -- From Goner's Execute("z") function. Grabs nearest enemy, rips head off.
        local executeCooldown = 0
        local function execute(targetHum)
            if not targetHum or not targetHum.Parent then return end
            local targetChar = targetHum.Parent
            local targetRoot = rootOf(targetChar)
            if not targetRoot then return end
            safeChat(head, "...", Enum.ChatColor.White)
            -- Apply TV static
            applyStatic(targetChar)
            -- Teleport to target
            rp.CFrame = CFrame.new(targetRoot.Position + (targetRoot.Position - rp.Position).Unit * 3, targetRoot.Position)
            -- Anchor during execute
            local origAnchored = rp.Anchored
            rp.Anchored = true
            task.wait(0.3)
            -- Sword trail on
            if sword and sword:FindFirstChild("Trail") then
                sword.Trail.Enabled = true
            end
            -- Slash sound
            playGonerSound(211059653, 1, 0.7, sword)
            task.wait(0.2)
            -- Camera shake
            cameraShake(0.5, 15)
            -- Ragdoll + dismember head
            dismember(targetChar, "Ragdoll")
            dismember(targetChar, "Head")
            -- Dead face
            local hd = targetChar:FindFirstChild("Head")
            if hd then
                local face = hd:FindFirstChildOfClass("Decal")
                if face then
                    pcall(function() face.Texture = "http://www.roblox.com/asset/?id=145854465" end)
                    face.Transparency = 0.5
                end
            end
            -- Snap sound
            playGonerSound(264486467, 1, 0.7, targetRoot)
            playGonerSound(150315649, 2, 1, targetRoot)
            -- Blood
            for i = 1, 7 do
                bloodBurst(targetRoot.Position, 45)
            end
            -- Puddles
            task.spawn(function()
                for i = 1, 15 do
                    spawnPuddle(targetRoot.Position)
                    task.wait(0.1)
                end
            end)
            -- Speak sound (2291326656 — the "speak" sound after execute)
            playGonerSound(2291326656, 2, 1, head)
            task.wait(0.5)
            if sword and sword:FindFirstChild("Trail") then
                sword.Trail.Enabled = false
            end
            rp.Anchored = origAnchored
        end

        -- v9.2.7 ABILITY 3: SHRIEK — AoE decapitation scream
        -- From Goner's Shriek() function. Decapitates all enemies in 45 studs.
        local shriekCooldown = 0
        local function shriek()
            safeChat(head, "...", Enum.ChatColor.White)
            -- Speak sound (2466752906 — the shriek sound)
            playGonerSound(2466752906, 3, 1, head)
            -- Camera shake (heavy)
