        -- v9.2.7 ABILITY 4: SUBMERGE — sink into ground, move, emerge
        -- From Goner's Submerge logic. Sinks into the ground, moves toward
        -- a target, then emerges to execute them.
        local submergeCooldown = 0
        local submerged = false
        local function submergeAndEmerge(targetPos)
            safeChat(head, "...", Enum.ChatColor.White)
            submerged = true
            -- Sink into ground (visual: lower the noob + dark puddle)
            local puddle = Instance.new("Part")
            puddle.Size = Vector3.new(6, 0.1, 6)
            puddle.Color = Color3.fromRGB(15, 15, 15)
            puddle.Material = Enum.Material.Slate
            puddle.Anchored = true
            puddle.CanCollide = false
            puddle.CFrame = CFrame.new(rp.Position)
            puddle.Parent = workspace
            Debris:AddItem(puddle, 10)
            -- Lower the noob into the ground
            local origCF = rp.CFrame
            TweenService:Create(rp, TweenInfo.new(1), {CFrame = origCF * CFrame.new(0, -4, 0)}):Play()
            -- Make noob invisible while submerged
            for _, p in pairs(model:GetDescendants()) do
                if p:IsA("BasePart") and p.Name ~= "HumanoidRootPart" then
                    p.Transparency = 1
                end
            end
            task.wait(1)
            -- Move puddle toward target
            TweenService:Create(puddle, TweenInfo.new(1.5), {CFrame = CFrame.new(targetPos)}):Play()
            task.wait(1.5)
            -- Emerge at target
            rp.CFrame = CFrame.new(targetPos)
            TweenService:Create(rp, TweenInfo.new(0.8), {CFrame = CFrame.new(targetPos)}):Play()
            -- Make visible again
            for _, p in pairs(model:GetDescendants()) do
                if p:IsA("BasePart") and p.Name ~= "HumanoidRootPart" then
                    p.Transparency = 0
                end
            end
            -- Spawn puddles at emergence point
            for i = 1, 5 do
                spawnPuddle(targetPos)
                task.wait(0.1)
            end
            -- Snap sound on emerge
            playGonerSound(150315649, 2, 1, rp)
            cameraShake(0.3, 10)
            submerged = false
        end

        -- Main AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Priority 1: intercept threats to player
                if interceptThreatToPlayer(70, 6, function(t, d)
                    if d < 6 then
                        -- Execute if off cooldown, else slash
                        executeCooldown = executeCooldown + 1
                        if executeCooldown >= 8 then
                            executeCooldown = 0
                            pcall(function() execute(t) end)
                        else
                            t:TakeDamage(40)
                        end
                    end
                end) then
                    didSomething = true
                end
                -- Priority 2: hunt killers (long range — submerge to them)
                local killer, kdist = scanForKillers(250)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist > 50 then
                            -- Submerge to the killer
                            submergeCooldown = submergeCooldown + 1
                            if submergeCooldown >= 15 then
                                submergeCooldown = 0
                                pcall(function() submergeAndEmerge(tp) end)
                            else
                                pathTo(tp)
                            end
                        elseif kdist < 8 then
                            -- Execute or slash
                            executeCooldown = executeCooldown + 1
                            if executeCooldown >= 8 then
                                executeCooldown = 0
                                pcall(function() execute(killer) end)
                            else
                                slashCooldown = slashCooldown + 1
                                if slashCooldown >= 3 then
                                    slashCooldown = 0
                                    pcall(gonerSlash)
                                else
                                    killer:TakeDamage(50)
                                end
                            end
                        else
                            pathTo(tp)
                            -- Slash if in range
                            slashCooldown = slashCooldown + 1
                            if slashCooldown >= 3 and kdist < 8 then
                                slashCooldown = 0
                                pcall(gonerSlash)
                            end
                        end
                        didSomething = true
                    end
                end
                -- Priority 3: hunt any enemy
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 150)
                    if enemy and edist > 50 then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            submergeCooldown = submergeCooldown + 1
                            if submergeCooldown >= 15 then
                                submergeCooldown = 0
                                pcall(function() submergeAndEmerge(tp) end)
                            else
                                pathTo(tp)
                            end
                            didSomething = true
                        end
                    elseif enemy and edist < 8 then
                        slashCooldown = slashCooldown + 1
                        if slashCooldown >= 3 then
                            slashCooldown = 0
                            pcall(gonerSlash)
                        else
                            enemy:TakeDamage(50)
                        end
                        didSomething = true
                    end
                end
                -- Shriek: every 20s (rare AoE nuke)
                shriekCooldown = shriekCooldown + 1
                if shriekCooldown >= 20 then
                    -- Only shriek if there are 2+ enemies nearby
                    local nearbyCount = 0
                    for _, obj in ipairs(workspace:GetDescendants()) do
                        pcall(function()
                            if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                                local oh = humanoidOf(obj); local ot = rootOf(obj)
                                if oh and ot and oh.Health > 0 and (ot.Position - rp.Position).Magnitude < 45 then
                                    nearbyCount = nearbyCount + 1
                                end
                            end
                        end)
                    end
                    if nearbyCount >= 2 then
                        shriekCooldown = 0
                        pcall(shriek)
                    end
                end
                -- Otherwise return to player
                if not didSomething then
                    returnToPlayer(30)
                    if math.random() > 0.8 then
                        safeChat(head, "...", Enum.ChatColor.White)
                    end
                end
                task.wait(1)
            end
            -- Cleanup BGM on death
            if bgm then pcall(function() bgm:Stop() bgm:Destroy() end) end
        end)

