        -- Helper: cast warp outlines (cyan clone effect from Banisher)
        local function castWarpOutlines(targetChar)
            pcall(function()
                for _, child in pairs(targetChar:GetChildren()) do
                    if child:IsA("BasePart") then
                        local clone = child:Clone()
                        clone.Parent = workspace
                        clone.Anchored = true
                        clone.CanCollide = false
                        clone:ClearAllChildren()
                        clone.CFrame = child.CFrame
                        clone.Color = Color3.fromRGB(0, 255, 255)
                        clone.Material = Enum.Material.Neon
                        Debris:AddItem(clone, 1)
                        TweenService:Create(clone, TweenInfo.new(1), {
                            Transparency = 1,
                            Size = clone.Size + Vector3.new(0.001, 0.001, 0.001)
                        }):Play()
                    end
                end
            end)
        end
