        -- v9.2.8 ABILITY 1: BANISHER BULLET — cyan laser that banishes
        local bulletCooldown = 0
        local function banisherBullet(targetPos)
            if not gunPoint then return end
            playBanisherSound(131205975, 2, 1, gunPoint)
            magicSphere(gunPoint.CFrame, Color3.fromRGB(0, 255, 255), Vector3.new(0.2, 0.2, 0.2), 0.5)
            -- Cast ray from gun to target
            local origin = gunPoint.Position
            local direction = (targetPos - origin)
            local distance = direction.Magnitude
            if distance < 0.1 then return end
            direction = direction.Unit
            -- Visual: cyan laser
            local laser = Instance.new("Part")
            laser.Size = Vector3.new(0.15, 0.15, distance)
            laser.Color = Color3.fromRGB(0, 255, 255)
            laser.Material = Enum.Material.Neon
            laser.Anchored = true
            laser.CanCollide = false
            laser.CFrame = CFrame.new(origin, targetPos) * CFrame.new(0, 0, -distance / 2)
            laser.Parent = workspace
            Debris:AddItem(laser, 0.3)
            TweenService:Create(laser, TweenInfo.new(0.3), {Transparency = 1}):Play()
            -- Impact effect
            magicSphere(CFrame.new(targetPos), Color3.fromRGB(0, 255, 255), Vector3.new(2, 2, 2), 0.5)
            -- Banish all enemies near the impact point
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and (ot.Position - targetPos).Magnitude < 8 then
                            oh:TakeDamage(100)
                            -- If dead, banish (destroy)
                            if oh.Health <= 0 then
                                task.wait(0.1)
                                banish(obj)
                            end
                        end
                    end
                end)
            end
        end
        -- v9.2.8 ABILITY 2: BANISHING RAMPAGE — continuous beam
        local rampageCooldown = 0
        local function banishingRampage(targetPos)
            if not gunPoint then return end
            safeChat(head, "Be gone...", Enum.ChatColor.Cyan)
            playBanisherSound(131205975, 3, 1, gunPoint)
            playBanisherSound(415700134, 3, 1.6, workspace)
            -- Continuous beam for 3 seconds, sweeping toward target
            task.spawn(function()
                local startTime = os.clock()
                while os.clock() - startTime < 3 do
                    if not isAlive(h) then break end
                    local origin = gunPoint.Position
                    -- Sweep: aim at target with slight random spread
                    local aimPos = targetPos + Vector3.new(math.random(-10, 10), math.random(-5, 5), math.random(-10, 10))
                    local direction = (aimPos - origin)
                    local distance = math.min(direction.Magnitude, 200)
                    if distance > 0.1 then
                        direction = direction.Unit
                        -- Visual beam
                        local laser = Instance.new("Part")
                        laser.Size = Vector3.new(0.2, 0.2, distance)
                        laser.Color = Color3.fromRGB(0, 255, 255)
                        laser.Material = Enum.Material.Neon
                        laser.Anchored = true
                        laser.CanCollide = false
                        laser.CFrame = CFrame.new(origin, aimPos) * CFrame.new(0, 0, -distance / 2)
                        laser.Parent = workspace
                        Debris:AddItem(laser, 0.15)
                        -- Banish all enemies along the beam path
                        for _, obj in ipairs(workspace:GetDescendants()) do
                            pcall(function()
                                if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                                    local oh = humanoidOf(obj); local ot = rootOf(obj)
                                    if oh and ot then
                                        -- Check if enemy is near the beam line
                                        local toEnemy = ot.Position - origin
                                        local projection = toEnemy:Dot(direction)
                                        if projection > 0 and projection < distance then
                                            local closestPoint = origin + direction * projection
                                            local distFromBeam = (ot.Position - closestPoint).Magnitude
                                            if distFromBeam < 6 then
                                                oh:TakeDamage(50)
                                                if oh.Health <= 0 then
                                                    banish(obj)
                                                end
                                            end
                                        end
                                    end
                                end
                            end)
                        end
                    end
                    task.wait(0.1)
                end
            end)
        end
        -- v9.2.8 ABILITY 3: WARP VECTOR — teleport
        local warpCooldown = 0
        local function warpVector(targetPos)
            safeChat(head, "Warp.", Enum.ChatColor.Cyan)
            -- Visual at origin
            magicSphere(CFrame.new(rp.Position), Color3.fromRGB(0, 255, 255), Vector3.new(5, 5, 5), 0.5)
