        -- v9.2.8 ABILITY 4: SPECTRAL BANISH — AoE banish all nearby
        local spectralCooldown = 0
        local function spectralBanish()
            safeChat(head, "If you desire to be a ghost... Then move on to the afterlife!", Enum.ChatColor.Cyan)
            playBanisherSound(131205975, 3, 1, gunPoint or rp)
            -- Color correction effect (red tint)
            local colorCorr = Instance.new("ColorCorrectionEffect")
            colorCorr.TintColor = Color3.fromRGB(255, 127, 127)
            colorCorr.Parent = Lighting
            TweenService:Create(colorCorr, TweenInfo.new(0.5), {TintColor = Color3.fromRGB(255, 127, 127)}):Play()
            task.delay(2, function()
                TweenService:Create(colorCorr, TweenInfo.new(1), {TintColor = Color3.fromRGB(255, 255, 255)}):Play()
                task.wait(1)
                colorCorr:Destroy()
            end)
            -- Upward laser visual
            if gunPoint then
                local laser = Instance.new("Part")
                laser.Size = Vector3.new(0.15, 0.15, 500)
                laser.Color = Color3.fromRGB(0, 255, 255)
                laser.Material = Enum.Material.Neon
                laser.Anchored = true
                laser.CanCollide = false
                laser.CFrame = CFrame.new(gunPoint.Position, gunPoint.Position + Vector3.new(0, 1, 0)) * CFrame.new(0, 0, -250)
                laser.Parent = workspace
                Debris:AddItem(laser, 1)
            end
            -- Banish all enemies within 30 studs after a delay
            task.wait(0.5)
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and (ot.Position - rp.Position).Magnitude < 30 then
                            oh:TakeDamage(200)
                            if oh.Health <= 0 then
                                banish(obj)
                            end
                        end
                    end
                end)
            end
        end
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Priority 1: intercept threats to player
                if interceptThreatToPlayer(80, 8, function(t, d)
                    if d < 30 then
                        local tp = posOf(t.Parent)
                        if tp then
                            bulletCooldown = bulletCooldown + 1
                            if bulletCooldown >= 3 then
                                bulletCooldown = 0
                                pcall(function() banisherBullet(tp) end)
                            else
                                t:TakeDamage(30)
                            end
                        end
                    end
                end) then
                    didSomething = true
                end
                -- Priority 2: hunt killers
                local killer, kdist = scanForKillers(250)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist > 60 then
                            -- Warp to distant killer
                            warpCooldown = warpCooldown + 1
                            if warpCooldown >= 10 then
                                warpCooldown = 0
                                pcall(function() warpVector(tp) end)
                            else
                                pathTo(tp)
                            end
                        elseif kdist < 50 then
                            -- Banisher bullet
                            bulletCooldown = bulletCooldown + 1
                            if bulletCooldown >= 3 then
                                bulletCooldown = 0
                                pcall(function() banisherBullet(tp) end)
                            end
                            -- Rampage if close enough
                            rampageCooldown = rampageCooldown + 1
                            if rampageCooldown >= 15 then
                                rampageCooldown = 0
                                pcall(function() banishingRampage(tp) end)
                            end
                        else
                            pathTo(tp)
                        end
                        didSomething = true
                    end
                end
                -- Priority 3: hunt any enemy
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 150)
                    if enemy and edist > 60 then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            warpCooldown = warpCooldown + 1
                            if warpCooldown >= 10 then
                                warpCooldown = 0
                                pcall(function() warpVector(tp) end)
                            else
                                pathTo(tp)
                            end
                            didSomething = true
                        end
                    elseif enemy and edist < 50 then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            bulletCooldown = bulletCooldown + 1
                            if bulletCooldown >= 3 then
                                bulletCooldown = 0
                                pcall(function() banisherBullet(tp) end)
                            else
                                enemy:TakeDamage(30)
                            end
                        end
                        didSomething = true
                    end
                end
                -- Spectral Banish: every 30s if surrounded
                spectralCooldown = spectralCooldown + 1
                if spectralCooldown >= 30 then
                    local nearbyCount = 0
                    for _, obj in ipairs(workspace:GetDescendants()) do
                        pcall(function()
                            if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                                local oh = humanoidOf(obj); local ot = rootOf(obj)
                                if oh and ot and oh.Health > 0 and (ot.Position - rp.Position).Magnitude < 30 then
                                    nearbyCount = nearbyCount + 1
                                end
                            end
                        end)
                    end
                    if nearbyCount >= 3 then
                        spectralCooldown = 0
                        pcall(spectralBanish)
                    end
                end
                -- Otherwise return to player
                if not didSomething then
                    returnToPlayer(30)
                    if math.random() > 0.8 then
                        safeChat(head, "...", Enum.ChatColor.Cyan)
                    end
                end
                task.wait(1)
            end
            if bgm then pcall(function() bgm:Stop() bgm:Destroy() end) end
        end)

