        -- Helper: soul steal effect (from Chara's SoulSteal)
        local function soulStealEffect(targetChar, isPlayer)
            pcall(function()
                local torso = rootOf(targetChar)
                if not torso then return end
                -- Create soul visual
                local soulModel = Instance.new("Model")
                soulModel.Name = targetChar.Name .. "'s Soul"
                soulModel.Parent = workspace
                local soul = Instance.new("Part")
                soul.Shape = Enum.PartType.Ball
                soul.Size = Vector3.new(1, 1, 1)
                soul.Color = isPlayer and Color3.fromRGB(255, 0, 0) or Color3.fromRGB(255, 255, 255)
                soul.Material = Enum.Material.Glass
                soul.CanCollide = false
                soul.Anchored = true
                soul.CFrame = CFrame.new(torso.Position)
                soul.Parent = soulModel
                local soulMesh = Instance.new("SpecialMesh")
                soulMesh.MeshType = Enum.MeshType.Sphere
                soulMesh.Parent = soul
                local soulLight = Instance.new("PointLight")
                soulLight.Color = soul.Color
                soulLight.Range = 10
                soulLight.Brightness = isPlayer and 3 or 0.5
                soulLight.Parent = soul
                -- Trail
                local at0 = Instance.new("Attachment", soul)
                at0.Position = Vector3.new(0, 0.5, 0)
                local at1 = Instance.new("Attachment", soul)
                at1.Position = Vector3.new(0, -0.5, 0)
                local trail = Instance.new("Trail")
                trail.Attachment0 = at0
                trail.Attachment1 = at1
                trail.Color = ColorSequence.new(soul.Color)
                trail.Lifetime = 0.5
                trail.Parent = soul
                -- Move soul toward the chara noob
                task.spawn(function()
                    local distance = math.huge
                    while soul and soul.Parent and isAlive(h) and rp and rp.Parent do
                        soul.CFrame = CFrame.new(soul.Position, rp.Position) * CFrame.new(0, 0, -1)
                        distance = (soul.Position - rp.Position).Magnitude
                        if distance <= 1.5 then break end
                        task.wait()
                    end
                    if soul and soul.Parent then
                        -- Absorb soul
                        magicSphere(CFrame.new(rp.Position), soul.Color, Vector3.new(3, 3, 3), 0.5)
                        playCharaSound(444667859, 2, 1, rp)
                        souls = souls + (isPlayer and 1 or 0.1)
                        -- Heal
                        h.Health = math.min(h.Health + 20, h.MaxHealth)
                        showDamage(rp.Position, "+20 HP", Color3.fromRGB(0, 255, 0))
                        soulModel:Destroy()
                    end
                end)
            end)
