        -- Helper: kill an enemy (with soul steal)
        local function charaKill(targetChar)
            pcall(function()
                local isPlayer = Players:GetPlayerFromCharacter(targetChar) ~= nil
                local oh = humanoidOf(targetChar)
                if oh then oh.Health = 0 end
                targetChar:BreakJoints()
                -- Dust effect on all parts
                for _, v in pairs(targetChar:GetChildren()) do
                    if v:IsA("BasePart") then
                        v.Parent = workspace
                        v:ClearAllChildren()
                        v.Anchored = true
                        v.CanCollide = false
                        v.Transparency = 1
                        local dust = Instance.new("ParticleEmitter")
                        dust.Color = ColorSequence.new(Color3.fromRGB(255, 255, 255))
                        dust.Size = NumberSequence.new({NumberSequenceKeypoint.new(0, 1), NumberSequenceKeypoint.new(1, 0)})
                        dust.Texture = "rbxassetid://284205403"
                        dust.Transparency = NumberSequence.new({NumberSequenceKeypoint.new(0, 0), NumberSequenceKeypoint.new(1, 1)})
                        dust.Lifetime = NumberRange.new(1)
                        dust.Rate = 100
                        dust.Acceleration = Vector3.new(0, 10, 0)
                        dust.Speed = NumberRange.new(5)
                        dust.Parent = v
                        Debris:AddItem(v, 3)
                        task.delay(1, function() dust.Enabled = false end)
                    end
                end
                -- Soul steal
                task.spawn(function() soulStealEffect(targetChar, isPlayer) end)
            end)
