                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and oh.Health > 0 then
                            if (ot.Position - knife.Position).Magnitude < 5 then
                                -- Damage scales with souls
                                local damage = math.random(15, 30) * ((souls / 5) + 1)
                                oh:TakeDamage(damage)
                                showDamage(ot.Position, tostring(math.floor(damage)), Color3.fromRGB(255, 0, 0))
                                -- If dead, soul steal
