        local function refuse()
            if hasRefused then return end
            hasRefused = true
            safeChat(head, "But it refused.", Enum.ChatColor.Red)
            -- Heal back to full
            h.Health = h.MaxHealth
            -- Soul animation visual
            local soul = Instance.new("Part")
            soul.Size = Vector3.new(2, 2, 0.05)
            soul.Color = Color3.fromRGB(255, 0, 0)
            soul.Material = Enum.Material.Neon
            soul.Anchored = true
            soul.CanCollide = false
            soul.CFrame = rp.CFrame
            soul.Parent = workspace
            Debris:AddItem(soul, 3)
            -- Heart decals
            local frontDecal = Instance.new("Decal")
            frontDecal.Face = Enum.NormalId.Front
            frontDecal.Texture = "rbxassetid://1569347904"
            frontDecal.Parent = soul
            local backDecal = Instance.new("Decal")
            backDecal.Face = Enum.NormalId.Back
            backDecal.Texture = "rbxassetid://1569347904"
            backDecal.Parent = soul
            -- Shatter sound
            playCharaSound(862552636, 3, 1, soul)
            task.wait(0.5)
            -- Crack (change texture)
            frontDecal.Texture = "rbxassetid://1569348344"
            backDecal.Texture = "rbxassetid://1569348344"
            task.wait(0.5)
            -- Reform
            playCharaSound(862552636, 3, 1, soul)
            frontDecal.Texture = "rbxassetid://1569347904"
            backDecal.Texture = "rbxassetid://1569347904"
            -- Heal visual
            magicSphere(CFrame.new(rp.Position), Color3.fromRGB(255, 0, 0), Vector3.new(8, 8, 8), 1)
            h.Health = h.MaxHealth
            safeChat(head, "Determination.", Enum.ChatColor.Red)
        end
        -- Main AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Priority 1: intercept threats to player
                if interceptThreatToPlayer(70, 5, function(t, d)
                    if d < 5 then
                        slashCooldown = slashCooldown + 1
                        if slashCooldown >= 2 then
                            slashCooldown = 0
                            pcall(charaSlash)
                        else
                            t:TakeDamage(20)
                        end
                    end
                end) then
                    didSomething = true
                end
                -- Priority 2: hunt killers
                local killer, kdist = scanForKillers(200)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist < 5 then
                            -- Slash
                            slashCooldown = slashCooldown + 1
                            if slashCooldown >= 2 then
                                slashCooldown = 0
                                pcall(charaSlash)
                            else
                                killer:TakeDamage(25)
                            end
                        else
                            pathTo(tp)
                        end
                        didSomething = true
                    end
                end
                -- Priority 3: hunt any enemy
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 120)
                    if enemy and edist > 5 then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            pathTo(tp)
                            didSomething = true
                        end
                    elseif enemy and edist < 5 then
                        slashCooldown = slashCooldown + 1
                        if slashCooldown >= 2 then
                            slashCooldown = 0
                            pcall(charaSlash)
                        else
                            enemy:TakeDamage(25)
                        end
                        didSomething = true
                    end
                end
                -- AOE Kill: every 25s if surrounded by 3+ enemies
                aoeKillCooldown = aoeKillCooldown + 1
                if aoeKillCooldown >= 25 then
                    local nearbyCount = 0
                    for _, obj in ipairs(workspace:GetDescendants()) do
                        pcall(function()
                            if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                                local oh = humanoidOf(obj); local ot = rootOf(obj)
                                if oh and ot and oh.Health > 0 and (ot.Position - rp.Position).Magnitude < 25 then
                                    nearbyCount = nearbyCount + 1
                                end
                            end
                        end)
                    end
                    if nearbyCount >= 3 then
                        aoeKillCooldown = 0
                        pcall(aoeKill)
                    end
                end
                -- Otherwise return to player
                if not didSomething then
                    returnToPlayer(30)
                    if math.random() > 0.8 then
                        safeChat(head, "...", Enum.ChatColor.Red)
                    end
                end
                task.wait(1)
            end
            -- On death: refuse (respawn once)
            if not hasRefused and h.Health <= 0 then
                pcall(refuse)
            end
            if music then pcall(function() music:Stop() music:Destroy() end) end
        end)

