            "ROCK!","Boulder incoming!","Catch this!","CRUSH!","EAT ROCK!",
        }
        -- Configuration (from the original tool script)
        local ROCK_MESH_ID = 18141065020
        local ROCK_SIZE = Vector3.new(12, 12, 12)
        local BLAST_RADIUS = 35
        local BLOOD_AMOUNT = 25
        -- Helper: throw a boulder at a target position
        local throwCooldown = 0
        local function throwBoulder(targetPos)
            safeChat(head, boulderPhrases[math.random(1,#boulderPhrases)], Enum.ChatColor.Brown)
            -- Calculate launch direction
            local origin = rp.Position + Vector3.new(0, 3, 0)
            local direction = (targetPos - origin)
            if direction.Magnitude < 0.1 then return end
            direction = direction.Unit
            -- Create the rock (from the original script)
            local rock = Instance.new("Part")
            rock.Name = "GiantRock"
            rock.Size = ROCK_SIZE
            rock.Shape = Enum.PartType.Block
            rock.BrickColor = BrickColor.new("Dark stone grey")
            rock.Material = Enum.Material.Slate
            rock.CanCollide = true
            rock.Massless = false
            rock.CastShadow = true
            rock.CFrame = CFrame.new(origin + direction * 4)
            -- Apply the mesh
            local mesh = Instance.new("SpecialMesh")
            mesh.MeshId = "rbxassetid://" .. ROCK_MESH_ID
            mesh.Scale = Vector3.new(3.5, 3.5, 3.5)
            mesh.Parent = rock
            -- Add velocity (250 speed from the original)
            rock.Velocity = direction * 250
            rock.Parent = workspace
            Debris:AddItem(rock, 5)
            -- Impact logic (from the original script's rock.Touched)
            local impacted = false
            rock.Touched:Connect(function(hit)
                if impacted then return end
                if hit:IsDescendantOf(model) then return end
                -- Check if we hit an enemy or terrain
                local hitModel = hit.Parent
                local isEnemy = hitModel and humanoidOf(hitModel) and not isNoobTeam(hitModel) and hitModel ~= model
                local isTerrain = hit.Anchored
                if not isEnemy and not isTerrain then return end
                impacted = true
                -- Stop the rock
                rock.Anchored = true
                rock.Velocity = Vector3.new(0, 0, 0)
                Debris:AddItem(rock, 3)
                -- Explosion (from the original)
                local explosion = Instance.new("Explosion")
                explosion.Position = rock.Position
                explosion.BlastRadius = BLAST_RADIUS
                explosion.BlastPressure = 50000
                explosion.Parent = workspace
                -- Unanchor nearby parts (but protect baseplate and terrain)
                explosion.Hit:Connect(function(part)
                    if part:IsA("BasePart") and part.Anchored then
                        if not string.find(string.lower(part.Name), "baseplate") and not part:IsA("Terrain") then
                            pcall(function() part.Anchored = false end)
                        end
                    end
                end)
                -- Instant kill + blood for all enemies in blast radius
                for _, obj in ipairs(workspace:GetDescendants()) do
                    pcall(function()
                        if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                            local oh = humanoidOf(obj); local ot = rootOf(obj)
                            if oh and ot and oh.Health > 0 then
                                local dist = (ot.Position - rock.Position).Magnitude
                                if dist <= BLAST_RADIUS then
                                    -- INSTANT KILL
                                    oh.Health = 0
                                    -- BLOOD EFFECT (25 particles per kill)
                                    for i = 1, BLOOD_AMOUNT do
                                        local blood = Instance.new("Part")
                                        blood.Name = "Blood"
                                        blood.Size = Vector3.new(0.5, 0.5, 0.5) + Vector3.new(math.random(), math.random(), math.random()) * 0.5
                                        blood.BrickColor = BrickColor.new("Crimson")
                                        blood.Material = Enum.Material.SmoothPlastic
                                        blood.CanCollide = true
                                        blood.Position = ot.Position + Vector3.new(math.random(-2, 2), math.random(0, 3), math.random(-2, 2))
                                        blood.Velocity = Vector3.new(math.random(-50, 50), math.random(20, 80), math.random(-50, 50))
                                        blood.Parent = workspace
                                        Debris:AddItem(blood, 15)
                                        -- Make blood stick to the floor
                                        blood.Touched:Connect(function(hitPart)
                                            if not hitPart:IsDescendantOf(obj) then
                                                blood.Velocity = Vector3.new(0, 0, 0)
                                                blood.Anchored = true
                                            end
                                        end)
                                    end
                                end
                            end
                        end
                    end)
                end
            end)
        end
        task.spawn(function()
            while isAlive(h) and rp.Parent do
