        -- Helper: camera shake (from original's CamShake)
        local function camShake(length, intensity)
            local camera = workspace.CurrentCamera
            if not camera then return end
            task.spawn(function()
                local intensityVal = intensity
                local rotM = 0.01 * intensity
                for i = 0, length, 0.1 do
                    task.wait()
                    intensityVal = intensityVal - 0.05 * intensity / length
                    rotM = rotM - 0.0005 * intensity / length
                    camera.CFrame = camera.CFrame * CFrame.new(
                        math.rad(math.random(-intensityVal, intensityVal)),
                        math.rad(math.random(-intensityVal, intensityVal)),
                        math.rad(math.random(-intensityVal, intensityVal))
                    ) * CFrame.Angles(
                        math.rad(math.random(-intensityVal, intensityVal)) * rotM,
                        math.rad(math.random(-intensityVal, intensityVal)) * rotM,
                        math.rad(math.random(-intensityVal, intensityVal)) * rotM
                    )
                end
            end)
        end
