                            oh.Health = 0
                        end
                    end
                end)
            end
        end
        -- ABILITY: CHARGE (mode 2) — heal self + allies
        local chargeCD = 0
        local function staffCharge()
            safeChat(head, "Charge!", Enum.ChatColor.Green)
            -- Turn staff green
            if glowPart then glowPart.BrickColor = BrickColor.new("Bright green") end
            if crystalPart then crystalPart.BrickColor = BrickColor.new("Bright green") end
            -- Heal self to full
            h.Health = h.MaxHealth
            -- Heal nearby allies
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and (ot.Position - rp.Position).Magnitude < 30 then
                            oh.Health = oh.MaxHealth
                        end
                    end
                end)
            end
            -- Also heal the player
            local pchar = getPlayerChar()
            if pchar then
                local ph = humanoidOf(pchar)
                if ph then ph.Health = ph.MaxHealth end
            end
            task.wait(0.7)
            -- Turn back to cyan
            if glowPart then glowPart.BrickColor = BrickColor.new("Cyan") end
            if crystalPart then crystalPart.BrickColor = BrickColor.new("Cyan") end
        end
        -- AI loop
        task.spawn(function()
            local modeTimer = 0
            while isAlive(h) and rp.Parent do
                local didSomething = false
                if interceptThreatToPlayer(70, 8, function(t, d)
                    if d < 8 then t:TakeDamage(20) end
                end) then didSomething = true end
                local killer, kdist = scanForKillers(200)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        -- Use current mode ability
                        if staffMode == 0 then
                            -- Laser
                            laserCD = laserCD + 1
                            if laserCD >= 5 then
                                laserCD = 0
                                pcall(function() staffLaser(tp) end)
                            else
                                pathTo(tp)
                            end
                        elseif staffMode == 1 then
                            -- Blast
                            blastCD = blastCD + 1
                            if blastCD >= 6 and kdist < 30 then
                                blastCD = 0
                                pcall(function() staffBlast(tp) end)
                            else
                                pathTo(tp)
                            end
                        else
                            -- Charge (heal)
                            chargeCD = chargeCD + 1
                            if chargeCD >= 8 then
                                chargeCD = 0
                                pcall(staffCharge)
                            else
                                pathTo(tp)
                            end
                        end
                        didSomething = true
                    end
                end
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 120)
                    if enemy and edist > 8 then
                        local tp = posOf(enemy.Parent)
                        if tp then pathTo(tp); didSomething = true end
                    elseif enemy and edist < 8 then
                        enemy:TakeDamage(20); didSomething = true
                    end
                end
                -- Cycle modes every 10 seconds
                modeTimer = modeTimer + 1
                if modeTimer >= 10 then
                    modeTimer = 0
                    staffMode = (staffMode + 1) % 3
                    safeChat(head, "Mode: " .. modeNames[staffMode + 1], Enum.ChatColor.Cyan)
                end
                -- Auto-charge if low health
                if h.Health < h.MaxHealth * 0.3 then
                    pcall(staffCharge)
                end
                if not didSomething then
                    returnToPlayer(30)
                    if math.random() > 0.8 then safeChat(head, "...", Enum.ChatColor.Cyan) end
                end
                task.wait(1)
            end
        end)


