        -- ABILITY 5: QUESTION MARK BLOCK 2 — coin spawn + heal
        local qmb2CD = 0
        local function questionMarkBlock2(targetPos)
            safeChat(head, "Coin!", Enum.ChatColor.Yellow)
            psnd(138702491, 3, rp)
            -- Heal self
            h.Health = h.MaxHealth
            -- Heal player
            local pchar = getPlayerChar()
            if pchar then
                local ph = humanoidOf(pchar)
                if ph then ph.Health = ph.MaxHealth end
            end
            -- Coin visual
            local coin = Instance.new("Part")
            coin.Size = Vector3.new(1.8, 1.8, 0.1)
            coin.Color = Color3.fromRGB(255, 220, 0)
            coin.Material = Enum.Material.Neon
            coin.Anchored = true; coin.CanCollide = false
            coin.Position = targetPos + Vector3.new(0, 5, 0)
            coin.Parent = workspace; Debris:AddItem(coin, 2)
            TweenService:Create(coin, TweenInfo.new(1.5), {Position = targetPos + Vector3.new(0, 20, 0), Transparency = 1}):Play()
        end
        -- AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                if interceptThreatToPlayer(70, 8, function(t, d)
                    if d < 8 then t:TakeDamage(20) end
                end) then didSomething = true end
                local killer, kdist = scanForKillers(250)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist < 8 then
                            -- Close: sword beam or punch
                            beamCD = beamCD + 1
                            if beamCD >= 4 then
                                beamCD = 0
                                pcall(function() swordBeam(tp) end)
                            else
                                killer:TakeDamage(20)
                            end
                        elseif kdist < 40 then
                            -- Medium: peashooter
                            peaCD = peaCD + 1
                            if peaCD >= 2 then
                                peaCD = 0
                                pcall(function() peashooter(tp) end)
                            else
                                pathTo(tp)
                            end
                        else
                            -- Long: question mark block
                            qmbCD = qmbCD + 1
                            if qmbCD >= 8 then
                                qmbCD = 0
                                pcall(function() questionMarkBlock(tp) end)
                            else
                                pathTo(tp)
                            end
                        end
                        didSomething = true
                    end
                end
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 150)
                    if enemy and edist > 40 then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            qmbCD = qmbCD + 1
                            if qmbCD >= 8 then
                                qmbCD = 0
                                pcall(function() questionMarkBlock(tp) end)
                            else
                                peaCD = peaCD + 1
                                if peaCD >= 2 then
                                    peaCD = 0
                                    pcall(function() peashooter(tp) end)
                                else
                                    pathTo(tp)
                                end
                            end
                            didSomething = true
                        end
                    elseif enemy and edist < 40 then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            beamCD = beamCD + 1
                            if beamCD >= 4 then
                                beamCD = 0
                                pcall(function() swordBeam(tp) end)
                            else
                                pathTo(tp)
                            end
                            didSomething = true
                        end
                    end
                end
                -- Candy buff: every 20s
                candyCD = candyCD + 1
                if candyCD >= 20 then
                    candyCD = 0
                    pcall(candyBuff)
                end
                -- QMB2 (heal): every 15s
                qmb2CD = qmb2CD + 1
                if qmb2CD >= 15 then
                    qmb2CD = 0
                    local ppos = getPlayerPos()
                    if ppos then pcall(function() questionMarkBlock2(ppos) end) end
                end
                if not didSomething then
                    returnToPlayer(30)
                    if math.random() > 0.8 then safeChat(head, "Pixels.", Enum.ChatColor.Cyan) end
                end
                task.wait(1)
            end
            if music then pcall(function() music:Stop() music:Destroy() end) end
        end)


