                            pointBlankCD = pointBlankCD + 1
                            if pointBlankCD >= 5 then
                                pointBlankCD = 0
                                pcall(function() pointBlank(tp) end)
                            else
                                killer:TakeDamage(20)
                            end
                        else
                            -- Medium/long: shoot
                            shootCD = shootCD + 1
                            if shootCD >= 2 then
                                shootCD = 0
                                pcall(function() shootFireball(tp) end)
                            else
                                pathTo(tp)
                            end
                        end
                        didSomething = true
                    end
                end
