                        else
                            enemy:TakeDamage(20)
                        end
                        didSomething = true
                    end
                end
                if not didSomething then
                    returnToPlayer(30)
                    if math.random() > 0.8 then safeChat(head, "Wreckage.", Enum.ChatColor.White) end
                end
                task.wait(1)
            end
        end)


