        -- ABILITY 1: SHOOT ARROW (from script's ShootArrow)
        -- Fires an arrow projectile from handle to targetPos.
        -- Arrow drops with gravity, sticks into hit parts, damages humanoids.
        local function shootArrow(targetPos, power)
            if not handle or not handle.Parent then return end
            power = power or 100
            local DMG = 25
            local accuracy = 1
            local Start = handle.Position
            local mag = (Start - targetPos).Magnitude / 200
            if mag > 12.5 then mag = 12.5 end
            -- Direction with accuracy spread (from script)
            local spread = (math.random(-accuracy*10000, accuracy*10000)/10000 + mag)
            local Face = CFrame.new(Start, targetPos)
                * CFrame.Angles(math.rad(spread), math.rad(spread), math.rad(spread))
            -- Arrow part (from script)
            local arr = Instance.new("Part")
            arr.Size = Vector3.new(0.2, 0.2, 0.2)
            arr.BrickColor = BrickColor.new("Brown")
            arr.CanCollide = false; arr.Anchored = true
            arr.CFrame = Face
            arr.Parent = workspace
            local arrMesh = Instance.new("SpecialMesh")
            arrMesh.MeshId = "http://www.roblox.com/asset/?id=15887356"
            arrMesh.TextureId = "http://www.roblox.com/asset/?id=15886781"
            arrMesh.Scale = Vector3.new(1, 1, 2.1)
            arrMesh.Parent = arr
            bowSnd(sndShoot, handle)
            local Go = 2.8 + (power / 30)
            local Dist = 200 + (power * 2.8)
            local Drop = 0.55 / (Go * 1.25)
            local lastP = Start
            local didhit = false
            local omg = 0
            -- Raycast along arrow path (from script's loop)
            task.spawn(function()
                for i = Go, Dist, Go do
                    if not isAlive(h) or not arr.Parent then break end
                    Drop = Drop + 1 / (Go * 3.5)
                    omg = omg + Drop
                    local dropping = (omg > 130) and CFrame.new() or CFrame.Angles(math.rad(-Drop), 0, 0)
                    Face = Face * dropping * CFrame.new(0, 0, -Go)
                    arr.CFrame = Face * CFrame.Angles(math.rad(-180), 0, 0)
                    -- Trail effect (from script)
                    local magn = (lastP - Face.p).Magnitude
                    local eff = Instance.new("Part")
                    eff.Size = Vector3.new(0.2, 1, 0.2)
                    eff.BrickColor = BrickColor.new("White")
                    eff.Anchored = true; eff.CanCollide = false
                    eff.Parent = workspace
                    local mes2 = Instance.new("SpecialMesh")
                    mes2.Scale = Vector3.new(0.6, magn, 0.6)
                    mes2.Parent = eff
                    eff.CFrame = CFrame.new(lastP, Face.p) * CFrame.Angles(math.rad(-90), 0, 0) * CFrame.new(0, magn/2, 0)
                    Debris:AddItem(eff, 0.3)
                    TweenService:Create(eff, TweenInfo.new(0.3), {Transparency = 1}):Play()
                    -- Raycast for hit (from script: RayC)
                    local hitPart, hitPos = workspace:FindPartOnRay(
                        Ray.new(lastP, (Face.p - lastP).Unit * (Go + 0.5)),
                        model
                    )
                    if hitPart then
                        magn = (lastP - hitPos).Magnitude
                        local hitHum = humanoidOf(hitPart.Parent)
                        if hitHum and hitPart.Parent ~= model and not isNoobTeam(hitPart.Parent) then
                            local d = math.random(12 + DMG + math.floor(power/8), 20 + DMG + math.floor(power/5.5))
                            if hitPart.Name == "Head" then d = math.floor(d * 1.4) end
                            dmgHum(hitHum, d, hitPos)
                            bowSnd(sndHit, hitPart)
                        elseif hitPart and not hitPart.Anchored and hitPart.Parent ~= model then
                            -- Knockback unanchored part (from script)
                            pcall(function()
                                local mas = hitPart:GetMass()/5 + 2
                                local vel = (16 + (power/3)) / mas
                                if vel > 0 then
                                    hitPart.Velocity = (CFrame.new(lastP, hitPos).lookVector) * vel
                                end
                            end)
                            bowSnd(sndStick, hitPart)
                        else
                            bowSnd(sndStick, hitPart)
                        end
                        -- Weld arrow to hit (from script)
                        pcall(function()
                            arr.CFrame = CFrame.new(hitPos, lastP) * CFrame.new(0, 0, -1.2)
                            arr.Anchored = false
                            local w = Instance.new("Weld")
                            w.Part0 = hitPart; w.Part1 = arr
                            w.C1 = (CFrame.new(hitPos, lastP) * CFrame.new(0, 0, -1.2)):toObjectSpace(hitPart.CFrame)
                            w.Parent = hitPart
                        end)
                        didhit = true
                        -- Fade arrow after 26s (from script)
                        task.spawn(function()
                            task.wait(26)
                            for i = 0, 1, 0.05 do
                                if arr.Parent then arr.Transparency = i end
                                task.wait()
                            end
                            if arr.Parent then arr:Destroy() end
                        end)
                        break
                    end
                    lastP = Face.p
                    task.wait()
                end
                -- Fade if missed (from script)
                if not didhit and arr.Parent then
                    for i = 0, 1, 0.2 do
                        if arr.Parent then arr.Transparency = i end
