                            pcall(specialShot, tp)
                        elseif kdist < 80 then
                            -- Shoot arrow (medium-long range)
                            pcall(shootArrow, tp, maxPower * 0.7)
                        else
                            -- Far: path closer
                            pathTo(tp)
                        end
                        didSomething = true
                    end
                end
                -- Hunt other enemies
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 150)
                    if enemy then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            if edist < 8 then
                                slashCD = slashCD + 1
                                if slashCD >= 2 then
                                    slashCD = 0
                                    pcall(slash)
