    -- SUPER RAGE NOOB ─────────────────────────────────────────
    -- Adapted from Ahtoh13131423144235's super rage script.
    -- Idle AI: hunts enemies like a normal noob.
    -- RAGE METER builds over time. When full AND an enemy is within 40 studs,
    -- triggers RAGE SEQUENCE:
    --   Phase 1 (3s): WalkSpeed 0, scream sound (448909138), violent Neck
    --     joint seizure (400 random CFrame.Angles rotations).
    --   Phase 2: Visual explosion (BlastPressure 0 to avoid friendly fire),
    --     face changes to "raged" image (187899224).
    --   Phase 3: AoE damage — 100-180 dmg to all non-noob-team within 30 studs,
    --     massive knockback. Plays ded sound (154872806).
    --   Phase 4: 10s cooldown, then resume hunting.
    -- WalkSpeed 16, Health 350. BrickColor: Bright red torso.
    elseif characterType == "super_rage_noob" then
        h.WalkSpeed = 18
        h.MaxHealth = 350; h.Health = 350
        colorModel(model, Color3.fromRGB(180, 30, 30))
        -- Set face to angry (from script: face change)
        if head then
            local faceDecal = head:FindFirstChildOfClass("Decal")
            if not faceDecal then
                faceDecal = Instance.new("Decal")
                faceDecal.Name = "face"
                faceDecal.Parent = head
            end
            pcall(function() faceDecal.Texture = "rbxassetid://7713222110" end)
        end
        -- Sounds (from script: screem 448909138, ded 154872806)
        local rageSounds = {}
        rageSounds.screem = Instance.new("Sound")
        rageSounds.screem.SoundId = "rbxassetid://448909138"
        rageSounds.screem.Volume = 5
        rageSounds.screem.Parent = head
        rageSounds.ded = Instance.new("Sound")
        rageSounds.ded.SoundId = "rbxassetid://154872806"
        rageSounds.ded.Volume = 3
        rageSounds.ded.Parent = head
        -- Hit/death sounds (from script: hit 260430060, hit1 138087186,
        -- hit2 131237241, hit3 278062209, ded 418892870)
        local hitSounds = {260430060, 138087186, 131237241, 278062209}
        local function playHitSound()
            pcall(function()
                local id = hitSounds[math.random(1, #hitSounds)]
                local s = Instance.new("Sound")
                s.SoundId = "rbxassetid://"..tostring(id)
                s.Volume = 3
                s.Parent = head
                s:Play()
                Debris:AddItem(s, 5)
            end)
        end
        -- Rage meter (regenerates over time, from script's wait-based pacing)
        local maxRage = 100
        local rage = 0
        local isRaging = false
        local rageCooldown = 0
        -- Get neck joint for seizure animation (from script)
        local torso = model:FindFirstChild("Torso")
        local neck = torso and torso:FindFirstChild("Neck")
        local rootJoint = rp:FindFirstChild("RootJoint")
        -- Save original neck C0 so we can restore after rage
        local neckC0Original = neck and neck.C0
        -- RAGE SEQUENCE (adapted from script's main flow)
        local function triggerRage()
            if isRaging then return end
            isRaging = true
            safeChat(head, "AAAAAAAAAAHHHH!!!", Enum.ChatColor.Red)
            pcall(function() rageSounds.screem:Play() end)
            -- Phase 1: WalkSpeed 0, sit, violent neck seizure (from script)
            local oldWalkSpeed = h.WalkSpeed
            h.WalkSpeed = 0
            -- Build a seat-like pose (from script: char:MoveTo(Seat57.Position))
            -- Just stand in place and shake
            local startTime = tick()
            local shakeCount = 0
            -- 400 frames of neck seizure (from script: for i = 1, 400 do)
            while isAlive(h) and tick() - startTime < 3 and shakeCount < 400 do
                if neck then
                    pcall(function()
                        neck.C0 = neck.C0 * CFrame.Angles(
                            math.rad(math.random()*0.9),
                            math.rad(math.random()*0.9),
                            math.rad(math.random()*0.9)
                        )
                    end)
                end
                -- Also shake other joints (more dramatic)
                if rootJoint then
                    pcall(function()
                        rootJoint.C0 = rootJoint.C0 * CFrame.Angles(
                            math.rad(math.random(-2, 2)*0.1),
                            math.rad(math.random(-2, 2)*0.1),
                            math.rad(math.random(-2, 2)*0.1)
                        )
                    end)
                end
                shakeCount = shakeCount + 1
                task.wait()
            end
            -- Phase 2: Visual explosion (from script: explosion with BlastPressure 0)
            pcall(function()
                local explosion = Instance.new("Explosion")
                explosion.BlastPressure = 0
                explosion.BlastRadius = 30
                explosion.Position = head.Position
                explosion.Parent = workspace
            end)
            -- Hide face (from script: char.Head.Transparency = 1, face removed)
            -- But we don't want to permanently destroy — just change face briefly
            local originalFace = nil
            if head then
                local fd = head:FindFirstChildOfClass("Decal")
                if fd then
                    originalFace = fd.Texture
                    pcall(function() fd.Texture = "rbxassetid://187899224" end)
                end
            end
            -- Phase 3: AoE damage + knockback (from script's explosion damage)
            pcall(function() rageSounds.ded:Play() end)
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and (ot.Position - rp.Position).Magnitude < 30 then
                            oh:TakeDamage(math.random(100, 180))
                            -- Massive knockback (from script: BodyVelocity * -5)
                            local kbv = Instance.new("BodyVelocity")
                            kbv.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
                            local dir = (ot.Position - rp.Position).Unit
                            kbv.Velocity = dir * math.random(40, 80) + Vector3.new(0, 30, 0)
                            kbv.Parent = ot
                            Debris:AddItem(kbv, 0.5)
                        end
                    end
                end)
            end
            -- Hit sounds (from script: random hit sounds)
            for i = 1, 3 do
                task.spawn(function() playHitSound() end)
                task.wait(0.1)
            end
            -- Phase 4: Jump (from script: Humanoid.Jump = true) and restore
            pcall(function() h.Jump = true end)
            h.WalkSpeed = oldWalkSpeed
            -- Restore face after 3s
            task.spawn(function()
                task.wait(3)
                if head and originalFace then
                    local fd = head:FindFirstChildOfClass("Decal")
                    if fd then pcall(function() fd.Texture = originalFace end) end
                end
            end)
            -- Restore neck C0 gradually
            task.spawn(function()
                task.wait(2)
                if neck and neckC0Original then
                    pcall(function() neck.C0 = neckC0Original end)
                end
                if rootJoint then
                    pcall(function() rootJoint.C0 = CFrame.new() end)
                end
            end)
            -- Cooldown
            rage = 0
            rageCooldown = 12
            isRaging = false
        end
        -- Rage meter regenerator (from script's while-true special regen)
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                if not isRaging then
                    if rageCooldown > 0 then
                        rageCooldown = rageCooldown - 0.1
                    else
                        rage = math.min(maxRage, rage + 1)
                    end
                end
                task.wait(0.1)
            end
        end)
        -- AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                -- If raging, wait
                if isRaging then
                    task.wait(0.5)
                else
                    local didSomething = false
                    -- Intercept threats to player
                    if interceptThreatToPlayer(70, 8, function(t, d)
                        if d < 8 then t:TakeDamage(15) end
                    end) then didSomething = true end
                    -- Hunt killers
                    local killer, kdist = scanForKillers(200)
                    if killer then
                        local tp = posOf(killer.Parent)
                        if tp then
                            -- Check rage trigger: rage full + enemy within 40 studs
                            if rage >= maxRage and rageCooldown <= 0 and kdist < 40 then
                                task.spawn(triggerRage)
                                didSomething = true
                            elseif kdist < 6 then
                                -- Melee
                                killer:TakeDamage(20)
                                if math.random() > 0.7 then playHitSound() end
                                didSomething = true
                            else
                                pathTo(tp)
                                didSomething = true
                            end
                        end
                    end
                    -- Hunt other enemies
                    if not didSomething then
                        local enemy, edist = findNearest(rp.Position, model, 150)
                        if enemy then
                            local tp = posOf(enemy.Parent)
                            if tp then
                                if rage >= maxRage and rageCooldown <= 0 and edist < 40 then
                                    task.spawn(triggerRage)
                                    didSomething = true
                                elseif edist < 6 then
                                    enemy:TakeDamage(20)
                                    if math.random() > 0.7 then playHitSound() end
                                    didSomething = true
                                else
                                    pathTo(tp)
                                    didSomething = true
                                end
                            end
                        end
                    end
                    -- Idle: return to player
                    if not didSomething then
                        returnToPlayer(35)
                        if math.random() > 0.92 then
                            local phrases = {"so mad...", "I can't take it...", "RAGE BUILDING...", "grrrr..."}
                            safeChat(head, phrases[math.random(1, #phrases)], Enum.ChatColor.Red)
                        end
                    end
                    task.wait(0.8)
                end
            end
        end)
        -- When this noob dies, do a mini rage explosion (from script's death ragdoll)
        local deathConn
        deathConn = h.Died:Connect(function()
            pcall(function()
                -- Final explosion (from script: explosion on death)
                local explosion = Instance.new("Explosion")
                explosion.BlastPressure = 0
                explosion.BlastRadius = 20
                explosion.Position = rp.Position
                explosion.Parent = workspace
                rageSounds.ded:Play()
                -- Damage nearby enemies as a parting gift
                for _, obj in ipairs(workspace:GetDescendants()) do
                    pcall(function()
                        if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                            local oh = humanoidOf(obj); local ot = rootOf(obj)
                            if oh and ot and (ot.Position - rp.Position).Magnitude < 20 then
                                oh:TakeDamage(math.random(50, 100))
                            end
                        end
                    end)
                end
            end)
            if deathConn then deathConn:Disconnect() end
        end)


