        -- Build helper (from script's prop function)
        local function ssp(part, parent, collide, tran, ref, x, y, z, color, anchor, form)
            part.Parent = parent
            part.formFactor = form or Enum.FormFactor.Custom
            part.CanCollide = collide
            part.Transparency = tran
            part.Reflectance = ref
            part.Size = Vector3.new(x,y,z)
            part.BrickColor = BrickColor.new(color)
            part.TopSurface = 0; part.BottomSurface = 0
            part.Anchored = anchor or false
            part.Locked = true
            part:BreakJoints()
        end
        -- Build main handle (from script)
