        local mme = Instance.new("SpecialMesh")
        mme.Scale = Vector3.new(1,1,1); mme.MeshType = Enum.MeshType.Head
        mme.Parent = main
        -- Hilt parts (from script: part1-6)
        local hiltParts = {
            {0.7, 0.45, 0.4, "Medium blue", 0, 0, 0, 0, 0.9, 0, "BlockMesh"},
            {0.7, 0.45, 0.4, "Medium blue", 0, 0, 0.8, 0.5, 0.85, 0, "BlockMesh"},
