            {1.3, 0.45, 0.4, "Medium blue", 0, 0, 1.25, -0.8, 1, 0, "BlockMesh"},
            {0.45, 0.6, 0.45, "Light blue", 0, 0, 0, 0, -0.9, 0, "Sphere"},
        }
        for _, hp in ipairs(hiltParts) do
