        -- Sounds (from script)
        local sndUns = Instance.new("Sound"); sndUns.SoundId = "rbxasset://sounds\\unsheath.wav"; sndUns.Volume = 1; sndUns.Parent = blade1
        local sndSlash = Instance.new("Sound"); sndSlash.SoundId = "rbxasset://sounds\\swordslash.wav"; sndSlash.Volume = 1; sndSlash.Parent = blade1
        local ndSpi = Instance.new("Sound"); ndSpi.SoundId = "rbxassetid://28144268"; ndSpi.Volume = 1; ndSpi.Parent = blade1
        local sndCharge = Instance.new("Sound"); sndCharge.SoundId = "rbxassetid://2692844"; sndCharge.Volume = 1; sndCharge.PlaybackSpeed = 0.5; sndCharge.Parent = blade1
        local sndBoom = Instance.new("Sound"); sndBoom.SoundId = "rbxasset://sounds\\Rocket shot.wav"; sndBoom.Volume = 1; sndBoom.PlaybackSpeed = 2.2; sndBoom.Parent = blade1
        -- Weld sword to Right Arm (held forward like sword)
        local holdW = Instance.new("Weld")
