        holdW.C1 = CFrame.new(0, -0.5, 0) * CFrame.Angles(math.rad(90), 0, 0)
        holdW.Parent = rArm
        -- Combat state (from script's globals)
        local normdmg = 9
        local avgdmg = normdmg
        local normchance = 9  -- 1 in 9 = 11% crit (script's 9333333333333 was a typo)
        local criticalchance = normchance
        local dela = 0.4
        local plat = 1
        local healcols = {"Bright blue", "Light blue", "Medium blue", "White"}
        local attacking = false
        -- Effect helpers (from script's block/blocks/blading/spikes/spikes2/bal/fade)
        local function fadeEffect(brick, msh, scale, tran, speed)
            task.spawn(function()
                for i = tran, 1, speed do
                    task.wait()
                    if brick.Parent then
                        brick.Transparency = i
                        msh.Scale = msh.Scale - Vector3.new(scale, scale, scale)
                    end
                end
                if brick.Parent then brick:Destroy() end
            end)
        end
        local function blockEffect(part, avg, cols)
            for i = 1, math.random(1, 3) do
                local sz = math.random((avg/5)*100, (avg*1.4)*100) / 100
                local p = Instance.new("Part")
                ssp(p, model, false, math.random(15, 50)/100, 0, sz, sz, sz, cols[math.random(1, #cols)], true)
                p.CFrame = CFrame.new(part.Position) * CFrame.Angles(math.rad(math.random(-320, 320)/100), math.rad(math.random(-320, 320)/100), math.rad(math.random(-320, 320)/100))
                p.Parent = model
                fadeEffect(p, (p:FindFirstChildOfClass("SpecialMesh") or p:FindFirstChildOfClass("BlockMesh")), 0.2, p.Transparency, 0.2)
            end
        end
        local function spikesEffect(part, color)
            local p = Instance.new("Part")
            ssp(p, model, false, 0.4, 0, 0.2, 0.2, 0.2, color, true)
