        -- Damage billboard (from script's blast function)
        local function blastGui(dmg, parent, crit)
            pcall(function()
                local bil = Instance.new("BillboardGui")
                bil.Adornee = parent
                bil.Size = UDim2.new(0, 110, 0, 70)
                bil.Parent = parent
                local img = Instance.new("ImageLabel")
                img.Size = UDim2.new(1, 0, 1, 0)
                img.Image = crit and "rbxassetid://42621315" or "rbxassetid://42621332"
                img.BackgroundTransparency = 1
                img.Parent = bil
                local txt = Instance.new("TextLabel")
                txt.Size = UDim2.new(1, 0, 1, 0)
                txt.BackgroundTransparency = 1
                txt.Text = tostring(dmg)
                txt.TextColor3 = crit and Color3.new(0.6, 0, 0) or Color3.new(0, 0, 0)
                txt.TextScaled = true
                txt.Parent = img
                task.spawn(function()
                    local yOff = math.random(-50, -10)
                    for i = 1, math.random(30, 50) do
                        if not bil.Parent then break end
                        img.Position = UDim2.new(0, math.random(-30, 30), 0, yOff)
                        yOff = yOff - 4
                        task.wait()
                    end
                    if bil.Parent then bil:Destroy() end
                end)
            end)
        end
        -- Damage application (from script's kill function)
        -- Returns true if landed a hit
        local function applyDamage(targetHum, targetHead, targetRoot, isMod)
            if not targetHum or targetHum.Health <= 0 then return false end
            local dm = math.random(0, avgdmg * 2)
            local cri = false
            if math.random(1, criticalchance) == 1 then
                cri = true
                dm = math.random(math.floor(avgdmg * 1.5), math.floor(avgdmg * 4.5))
            end
            pcall(function() targetHum.Health = targetHum.Health - dm end)
            if targetHead then blastGui(dm, targetHead, cri) end
            if cri then
                task.spawn(function()
                    if math.random(1, plat) == 1 and targetHum.Parent and targetHum.Parent:FindFirstChild("Torso") then
                        pcall(function()
                            targetHum.PlatformStand = true
                            targetHum.Parent.Torso.RotVelocity = Vector3.new(math.random(-20, 20), math.random(-20, 20), math.random(-20, 20))
                            task.wait(0.9)
                            if targetHum.Parent then
                                targetHum.PlatformStand = false
                                if isMod and targetHum.Parent:FindFirstChild("Torso") then
                                    targetHum.Parent.Torso.RotVelocity = Vector3.new(math.random(-30, 30), math.random(-30, 30), math.random(-30, 30))
                                    targetHum.Parent.Torso.Velocity = Vector3.new(math.random(-30, 30), math.random(15, 70), math.random(-30, 30))
                                end
                            end
                        end)
                    end
                end)
            end
            return true
        end
        -- ABILITY: SLASH (from script's att function)
