        -- ABILITY: SPIN (from script's spin function)
        local spinCD = 0
        local function spinAttack()
            if attacking then return end
            attacking = true
            local oldWalkSpeed = h.WalkSpeed
            h.WalkSpeed = 0
            pcall(function() ndSpi:Play() end)
            task.wait(0.2)
            pcall(function() ndSpi:Play() end)
            dela = 0.1; avgdmg = 6; criticalchance = 12
            -- Spin via BodyAngularVelocity + BodyVelocity (from script)
            local bv = Instance.new("BodyVelocity")
            bv.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
            bv.Velocity = rp.CFrame.lookVector * 22
            bv.Parent = rp
            local bav = Instance.new("BodyAngularVelocity")
            bav.MaxTorque = Vector3.new(math.huge, math.huge, math.huge)
            bav.AngularVelocity = Vector3.new(0, 36, 0)
