                    pcall(function()
                        if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) and not hitSet[obj] then
                            local oh = humanoidOf(obj); local ot = rootOf(obj)
                            local ohd = obj:FindFirstChild("Head")
                            if oh and ot and (ot.Position - rp.Position).Magnitude < 10 then
                                hitSet[obj] = true
                                applyDamage(oh, ohd, ot, true)
                            end
                        end
                    end)
                end
                task.wait()
            end
            bv:Destroy(); bav:Destroy()
            h.WalkSpeed = oldWalkSpeed
            dela = 0.4; avgdmg = normdmg; criticalchance = normchance
            attacking = false
        end
        -- ABILITY: SPRINT CHARGE (from script's sprint function)
        local sprintCD = 0
        local function sprintAttack(targetHum, targetHead, targetRoot)
            if attacking then return end
            attacking = true
            local oldWalkSpeed = h.WalkSpeed
            h.WalkSpeed = 0
            local pos = rp.CFrame
            local pos2 = pos * CFrame.new(0, 12, -15)
            local pos3 = pos2 * CFrame.new(0, -12, -12)
            -- Windup (from script: charge sound + effects)
            pcall(function() sndCharge:Play() end)
            for i = 1, 7 do
                if not isAlive(h) then break end
                spikes2Effect(rp, "Medium blue")
                task.wait()
            end
            -- Dash forward (from script: BodyPosition + BodyGyro)
            local bv = Instance.new("BodyPosition")
            bv.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
            bv.Position = pos2.p
            bv.Parent = rp
            -- Charge up critical
            criticalchance = 1; plat = 1; dela = 0
            avgdmg = 14
            task.wait(1.5)
            -- BOOM
            pcall(function() sndBoom:Play() end)
            bv.Position = pos3.p
            for i = 1, 7 do
                if not isAlive(h) then break end
                spikes2Effect(rp, "Medium blue")
                balEffect(blade5, "Medium blue", 28)
                task.wait()
            end
            -- Splash damage (from script: 14 stud radius)
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        local ohd = obj:FindFirstChild("Head")
                        if oh and ot and (ot.Position - blade5.Position).Magnitude < 14 then
                            applyDamage(oh, ohd, ot, true)
                        end
                    end
                end)
            end
            bv:Destroy()
            h.WalkSpeed = oldWalkSpeed
            avgdmg = normdmg; criticalchance = normchance; plat = 2; dela = 0.4
            attacking = false
        end
        -- ABILITY: RUSH (from script's rush function) — fast dash slash
        local rushCD = 0
        local function rushAttack()
            if attacking then return end
            attacking = true
            pcall(function() sndSlash:Play() end)
            local bv = Instance.new("BodyVelocity")
            bv.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
            bv.Velocity = rp.CFrame.lookVector * 80
            bv.Parent = rp
            local bav = Instance.new("BodyAngularVelocity")
            bav.MaxTorque = Vector3.new(math.huge, math.huge, math.huge)
            bav.AngularVelocity = Vector3.new(0, 36, 0)
            bav.P = 15000
            bav.Parent = rp
            local hitSet = {}
            for i = 1, 6 do
                if not isAlive(h) then break end
                blockEffect(blade5, 2, {"Medium blue", "Light blue", "White"})
                for _, obj in ipairs(workspace:GetDescendants()) do
                    pcall(function()
                        if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) and not hitSet[obj] then
                            local oh = humanoidOf(obj); local ot = rootOf(obj)
                            local ohd = obj:FindFirstChild("Head")
                            if oh and ot and (ot.Position - rp.Position).Magnitude < 10 then
                                hitSet[obj] = true
                                applyDamage(oh, ohd, ot, false)
                            end
                        end
                    end)
                end
                task.wait()
            end
            bv:Destroy(); bav:Destroy()
            attacking = false
        end
        -- ABILITY: MASTA STRIKE (from script's masta function) — high-damage combo
        local mastaCD = 0
        local function mastaAttack(targetHum, targetHead, targetRoot)
            if attacking then return end
            attacking = true
            -- Windup with full effects (from script)
            for i = 1, 8 do
                if not isAlive(h) then break end
                balEffect(rp, "Tr. Blue", 25)
                spikes2Effect(rp, "Medium blue")
                blockEffect(blade5, 2, {"Medium blue", "Light blue", "White"})
                task.wait(0.1)
            end
            pcall(function() sndSlash:Play() end)
            avgdmg = 37; criticalchance = 125
            task.wait(0.13)
            -- Dash + slash (from script)
            local bv = Instance.new("BodyVelocity")
            bv.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
            bv.Velocity = rp.CFrame.lookVector * 100
            bv.Parent = rp
            local bav = Instance.new("BodyAngularVelocity")
            bav.MaxTorque = Vector3.new(math.huge, math.huge, math.huge)
            bav.AngularVelocity = Vector3.new(0, 36, 0)
            bav.P = 15000
            bav.Parent = rp
            local hitSet = {}
            for i = 1, 6 do
                if not isAlive(h) then break end
                balEffect(rp, "Tr. Blue", 25)
                spikes2Effect(rp, "Medium blue")
                blockEffect(blade5, 2, {"Medium blue", "Light blue", "White"})
                for _, obj in ipairs(workspace:GetDescendants()) do
                    pcall(function()
                        if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) and not hitSet[obj] then
                            local oh = humanoidOf(obj); local ot = rootOf(obj)
                            local ohd = obj:FindFirstChild("Head")
                            if oh and ot and (ot.Position - rp.Position).Magnitude < 12 then
                                hitSet[obj] = true
                                applyDamage(oh, ohd, ot, true)
                            end
                        end
                    end)
                end
                task.wait()
            end
            bv:Destroy(); bav:Destroy()
            avgdmg = normdmg; criticalchance = normchance
            attacking = false
        end
        -- HEAL when low HP (from script's while-selected heal loop)
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                task.wait(0.8)
                if h.Health < 100 then
                    for i = 1, math.random(4, 12) do
                        if not isAlive(h) then break end
                        task.wait(0.1)
                        pcall(function()
                            local col = healcols[math.random(1, #healcols)]
                            local sa = math.random(30, 90) / 100
                            local p = Instance.new("Part")
                            ssp(p, model, false, 0.1, 0.05, 1, 1, 1, col, false, Enum.FormFactor.Symmetric)
                            p.CFrame = CFrame.new(rp.Position) * CFrame.Angles(math.rad(math.random(-320, 320)/100), math.rad(math.random(-320, 320)/100), math.rad(math.random(-320, 320)/100)) * CFrame.new(0, 0, math.random(4, 12))
                            p.Parent = model
                            local mes = Instance.new("SpecialMesh")
                            mes.Scale = Vector3.new(sa, sa, sa); mes.MeshType = Enum.MeshType.Sphere
                            mes.Parent = p
                            local bg = Instance.new("BodyPosition")
                            bg.MaxForce = Vector3.new(1000000, 1000000, 1000000)
                            bg.P = 100000
                            bg.Position = rp.Position
                            bg.Parent = p
                            task.spawn(function()
                                while p.Parent and isAlive(h) and rp.Parent do
                                    bg.Position = rp.Position
                                    if (p.Position - rp.Position).Magnitude < 1.8 then break end
                                    task.wait()
                                end
                                if p.Parent then
                                    pcall(function() h.Health = h.Health + 1.2 end)
                                    p:Destroy()
                                end
                            end)
                        end)
                    end
                end
            end
        end)
        -- AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Intercept threats to player
                if interceptThreatToPlayer(80, 8, function(t, d)
                    if d < 8 then
                        slashAttack(t, t.Parent:FindFirstChild("Head"), rootOf(t.Parent))
                    end
                end) then didSomething = true end
                -- Hunt killers
                local killer, kdist = scanForKillers(220)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        local kHead = killer.Parent:FindFirstChild("Head")
                        local kRoot = rootOf(killer.Parent)
                        if kdist < 5 then
                            -- Melee range: cycle attacks
                            slashCD = slashCD + 1
                            if slashCD >= 8 and mastaCD <= 0 then
                                slashCD = 0; mastaCD = 18
                                task.spawn(function() mastaAttack(killer, kHead, kRoot) end)
                            elseif slashCD >= 5 and rushCD <= 0 then
                                rushCD = 8
                                task.spawn(rushAttack)
                            elseif slashCD >= 3 and stabCD <= 0 then
                                stabCD = 6
                                task.spawn(function() stabAttack(killer, kHead, kRoot) end)
                            else
                                task.spawn(function() slashAttack(killer, kHead, kRoot) end)
                            end
                            didSomething = true
                        elseif kdist < 12 and sprintCD <= 0 then
                            sprintCD = 15
                            task.spawn(function() sprintAttack(killer, kHead, kRoot) end)
                            didSomething = true
                        elseif kdist < 25 and spinCD <= 0 then
                            spinCD = 10
                            task.spawn(spinAttack)
                            didSomething = true
                        else
                            pathTo(tp)
                            didSomething = true
                        end
                    end
                end
                -- Hunt other enemies
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 150)
                    if enemy then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            local eHead = enemy.Parent:FindFirstChild("Head")
                            local eRoot = rootOf(enemy.Parent)
                            if edist < 5 then
                                slashCD = slashCD + 1
                                if slashCD >= 8 and mastaCD <= 0 then
                                    slashCD = 0; mastaCD = 18
                                    task.spawn(function() mastaAttack(enemy, eHead, eRoot) end)
                                elseif slashCD >= 5 and rushCD <= 0 then
                                    rushCD = 8
                                    task.spawn(rushAttack)
                                elseif slashCD >= 3 and stabCD <= 0 then
                                    stabCD = 6
                                    task.spawn(function() stabAttack(enemy, eHead, eRoot) end)
                                else
                                    task.spawn(function() slashAttack(enemy, eHead, eRoot) end)
                                end
                                didSomething = true
                            elseif edist < 12 and sprintCD <= 0 then
                                sprintCD = 15
                                task.spawn(function() sprintAttack(enemy, eHead, eRoot) end)
                                didSomething = true
                            elseif edist < 25 and spinCD <= 0 then
                                spinCD = 10
                                task.spawn(spinAttack)
                                didSomething = true
                            else
                                pathTo(tp)
                                didSomething = true
                            end
                        end
                    end
                end
                -- Idle: return to player
                if not didSomething then
                    returnToPlayer(35)
                    if math.random() > 0.9 then
                        local phrases = {"My soul blade is sharp.", "Crits incoming...", "Blue light guides me."}
                        safeChat(head, phrases[math.random(1, #phrases)], Enum.ChatColor.Blue)
                    end
                end
                -- Decrement cooldowns
                if slashCD > 0 then slashCD = slashCD - 1 end
                if stabCD > 0 then stabCD = stabCD - 1 end
                if spinCD > 0 then spinCD = spinCD - 1 end
                if sprintCD > 0 then sprintCD = sprintCD - 1 end
                if rushCD > 0 then rushCD = rushCD - 1 end
                if mastaCD > 0 then mastaCD = mastaCD - 1 end
                task.wait(0.8)
            end
        end)

    -- CAN BOMB NOOB ───────────────────────────────────────────
    -- Adapted from OneLegend's Can Bomb script.
    -- Throws bean-can grenades (mesh 10470609, texture 45934917) that:
    --   1) Pin sound (31760113, looped) plays while lit.
    --   2) Light sound (19095020) plays once on light.
    --   3) Fire (Fire instance) shows on the rag wick.
    --   4) After 3-6s: Explosion (BlastPressure 20, BlastRadius 10),
    --      collide sound (rbxasset://sounds\\collide.wav).
    --   5) Thrown via BodyVelocity (75 speed toward target).
    -- WalkSpeed 16. Health 200. BrickColor: Dark grey (can-like).
    elseif characterType == "can_bomb_noob" then
        h.WalkSpeed = 16
        h.MaxHealth = 200; h.Health = 200
        colorModel(model, Color3.fromRGB(60, 50, 40))
        local rArm = model:FindFirstChild("Right Arm")
        local torso = model:FindFirstChild("Torso")
        -- Hold a bean can in hand (visible prop)
        local holdCan = Instance.new("Part")
        holdCan.Name = "BeanCanHold"
        holdCan.Size = Vector3.new(1, 1, 1)
        holdCan.BrickColor = BrickColor.new("Black")
        holdCan.CanCollide = false
        holdCan.Locked = true
        holdCan.TopSurface = 0; holdCan.BottomSurface = 0
        holdCan.Parent = model
        local holdMesh = Instance.new("SpecialMesh")
        holdMesh.MeshType = Enum.MeshType.FileMesh
        holdMesh.Scale = Vector3.new(1, 1, 1)
        holdMesh.MeshId = "http://www.roblox.com/asset/?id=10470609"
        holdMesh.TextureId = "http://www.roblox.com/asset/?id=45934917"
        holdMesh.Parent = holdCan
        local holdW = Instance.new("Weld")
        holdW.Part0 = rArm; holdW.Part1 = holdCan
        holdW.C1 = CFrame.new(-1.2, 0, 0) * CFrame.Angles(math.rad(90), 0, math.rad(90))
        holdW.Parent = rArm
        -- Throw a bean can grenade (from script's fire + onButton1Down)
        local throwCD = 0
        local function throwGrenade(targetPos)
            if throwCD > 0 then return end
            throwCD = 4
            -- Build grenade (from script's makeParts)
            local grenade = Instance.new("Model")
            grenade.Name = "CanBomb"
            grenade.Parent = workspace
            local pm = Instance.new("Part")
            pm.Name = "Handle"
            pm.formFactor = Enum.FormFactor.Symmetric
            pm.Size = Vector3.new(1, 1, 1)
            pm.BrickColor = BrickColor.new("Black")
            pm.CanCollide = true
            pm.Locked = true
            pm.TopSurface = 0; pm.BottomSurface = 0
            pm.CFrame = holdCan.CFrame
            pm.Parent = grenade
            local pmMesh = Instance.new("SpecialMesh")
            pmMesh.MeshType = Enum.MeshType.FileMesh
            pmMesh.Scale = Vector3.new(1, 1, 1)
            pmMesh.MeshId = "http://www.roblox.com/asset/?id=10470609"
            pmMesh.TextureId = "http://www.roblox.com/asset/?id=45934917"
            pmMesh.Parent = pm
            -- Sounds (from script)
            local sndExplode = Instance.new("Sound")
            sndExplode.Name = "Explode"
            sndExplode.SoundId = "rbxasset://sounds\\collide.wav"
            sndExplode.Volume = 1
            sndExplode.Parent = pm
            local sndPin = Instance.new("Sound")
            sndPin.Name = "Pin"
            sndPin.SoundId = "rbxassetid://31760113"
            sndPin.Volume = 1
            sndPin.Looped = true
            sndPin.Parent = pm
            local sndLight = Instance.new("Sound")
            sndLight.Name = "Light"
            sndLight.SoundId = "rbxassetid://19095020"
            sndLight.Volume = 1
            sndLight.Parent = pm
            -- Rag wick (from script)
            local rag = Instance.new("Part")
            rag.Name = "Rag"
            rag.formFactor = Enum.FormFactor.Symmetric
            rag.Size = Vector3.new(1, 1, 1)
            rag.BrickColor = BrickColor.new("White")
            rag.CanCollide = true
            rag.Transparency = 1
            rag.Locked = true
            rag.TopSurface = 0; rag.BottomSurface = 0
            rag.CFrame = pm.CFrame * CFrame.new(0, -0.6, 0)
            rag.Parent = grenade
            local fire = Instance.new("Fire")
            fire.Enabled = false
            fire.Name = "Fire"
            fire.Color = Color3.new(1, 0.5, 0)
            fire.SecondaryColor = Color3.new(1, 0.75, 0.5)
            fire.Heat = 25
            fire.Size = 2
            fire.Parent = rag
            local ragMesh = Instance.new("CylinderMesh")
            ragMesh.Scale = Vector3.new(0.15, 0.4, 0.15)
            ragMesh.Parent = rag
            local ragW = Instance.new("Weld")
            ragW.Part0 = rag; ragW.Part1 = pm
            ragW.C0 = CFrame.new(0, -0.6, 0)
            ragW.Parent = rag
            -- Light the fuse (from script: Pin + Light + Fire enabled)
            pcall(function() sndPin:Play() end)
            pcall(function() sndLight:Play() end)
            fire.Enabled = true
            -- Throw it (from script's fire function)
            local origin = holdCan.Position
            local dir = (targetPos - origin)
            if dir.Magnitude > 0.1 then dir = dir.Unit else dir = rp.CFrame.lookVector end
            local bodyVel = Instance.new("BodyVelocity")
            bodyVel.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
            bodyVel.Velocity = dir * 75 + Vector3.new(0, 15, 0)  -- arc up a bit
            bodyVel.Parent = pm
            Debris:AddItem(bodyVel, 0.2)
            -- Explode after 3-6s (from script's coroutine wait)
            task.spawn(function()
                task.wait(math.random(3, 6))
                if pm and pm.Parent then
                    -- Explosion (from script: BlastPressure 20, BlastRadius 10)
                    pcall(function()
                        local e = Instance.new("Explosion")
                        e.BlastPressure = 20
                        e.BlastRadius = 10
                        e.Position = pm.Position
                        e.Parent = workspace
                        sndExplode:Play()
                    end)
                    -- Damage bonus (since low BlastPressure may not kill)
                    for _, obj in ipairs(workspace:GetDescendants()) do
                        pcall(function()
                            if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                                local oh = humanoidOf(obj); local ot = rootOf(obj)
                                if oh and ot and (ot.Position - pm.Position).Magnitude < 12 then
                                    oh:TakeDamage(math.random(60, 100))
                                    local kbv = Instance.new("BodyVelocity")
                                    kbv.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
                                    kbv.Velocity = (ot.Position - pm.Position).Unit * 50 + Vector3.new(0, 30, 0)
                                    kbv.Parent = ot
                                    Debris:AddItem(kbv, 0.3)
                                end
                            end
                        end)
                    end
                    -- Hide the can (from script: Transparency 1)
                    pm.Transparency = 1
                    pm.CanCollide = false
                    rag.Transparency = 1
                    if sndPin then sndPin:Stop() end
                    Debris:AddItem(grenade, 3)
                end
            end)
        end
        -- AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Intercept threats to player
                if interceptThreatToPlayer(70, 8, function(t, d)
                    if d < 8 then t:TakeDamage(15) end
                end) then didSomething = true end
                -- Hunt killers
                local killer, kdist = scanForKillers(200)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist < 8 then
                            -- Close: melee + throw bomb at feet
                            killer:TakeDamage(15)
                            if throwCD <= 0 then
                                pcall(throwGrenade, tp)
                            end
                        elseif kdist < 60 then
                            -- Medium range: throw bomb
                            if throwCD <= 0 then
                                pcall(throwGrenade, tp)
                            else
                                pathTo(tp)
                            end
                        else
                            pathTo(tp)
                        end
                        didSomething = true
                    end
                end
                -- Hunt other enemies
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 150)
                    if enemy then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            if edist < 8 then
                                enemy:TakeDamage(15)
                                if throwCD <= 0 then
                                    pcall(throwGrenade, tp)
                                end
                            elseif edist < 60 then
                                if throwCD <= 0 then
                                    pcall(throwGrenade, tp)
                                else
                                    pathTo(tp)
                                end
                            else
                                pathTo(tp)
                            end
                            didSomething = true
                        end
                    end
                end
                -- Idle: return to player
                if not didSomething then
                    returnToPlayer(35)
                    if math.random() > 0.92 then
                        local phrases = {"Can bomb incoming!", "Beans of doom!", "Pull the pin..."}
                        safeChat(head, phrases[math.random(1, #phrases)], Enum.ChatColor.White)
                    end
                end
                -- Decrement throw cooldown
                if throwCD > 0 then throwCD = throwCD - 1 end
                task.wait(0.8)
            end
        end)


    -- ═══════════════════════════════════════════════════════════
    -- v9.4.0 NEW NOOBS — FLYING GORILLA + BURSTFIRE + RAGDOLL
