    -- FLYING GORILLA NOOB ─────────────────────────────────────
    -- Adapted from StarzoZero's flying gorilla train script.
    -- Noob's body is invisible; rides a train (mesh 431222734,
    -- texture 431222735) welded to torso. SpotLight on back of
    -- train. Smoke ParticleEmitter trails behind. WalkSpeed 60.
    -- Anything it touches breaks joints + whistle sound 428593644.
    -- Background music 3761684748 looped.
    elseif characterType == "flying_gorilla_noob" then
        h.WalkSpeed = 60
        h.MaxHealth = math.huge; h.Health = math.huge
        -- Make body invisible (from script: all parts Transparency 1)
        for _, v in pairs(model:GetChildren()) do
            if v:IsA("Part") then
                v.Transparency = 1
            elseif v:IsA("Hat") or v:IsA("Accessory") or v:IsA("CharacterMesh") then
                pcall(function() v:Destroy() end)
            end
        end
        -- Build train (from script)
        local trainMo = Instance.new("Part")
        trainMo.Name = "GorillaTrain"
        trainMo.Size = Vector3.new(3, 2, 6)
        trainMo.CanCollide = false
        trainMo.Anchored = false
        trainMo.CustomPhysicalProperties = PhysicalProperties.new(0, 0, 0, 0, 0)
        trainMo.Parent = model
        local trainMesh = Instance.new("SpecialMesh")
        trainMesh.MeshType = Enum.MeshType.FileMesh
        trainMesh.Scale = Vector3.new(0.05, 0.05, 0.05)
        trainMesh.MeshId = "rbxassetid://431222734"
        trainMesh.TextureId = "rbxassetid://431222735"
        trainMesh.Parent = trainMo
        -- Weld train to torso (from script: weld Part0=torso, Part1=train)
        local trainW = Instance.new("Weld")
        trainW.Part0 = rp; trainW.Part1 = trainMo
        trainW.C1 = CFrame.new(0, 0, 0) * CFrame.Angles(0, math.rad(180), 0)
        trainW.Parent = rp
        -- Smoke emitter (from script: Smoke part with ParticleEmitter)
        local smokePart = Instance.new("Part")
        smokePart.Size = Vector3.new(1, 1, 1)
        smokePart.CanCollide = false
        smokePart.Transparency = 1
        smokePart.Anchored = false
        smokePart.CustomPhysicalProperties = PhysicalProperties.new(0, 0, 0, 0, 0)
        smokePart.Parent = model
        local smokeW = Instance.new("Weld")
        smokeW.Part0 = rp; smokeW.Part1 = smokePart
        smokeW.C1 = CFrame.new(0, -4, 3.5)
        smokeW.Parent = rp
        local smokeParticle = Instance.new("ParticleEmitter")
        smokeParticle.Rate = 50
        smokeParticle.Speed = NumberRange.new(30, 60)
        smokeParticle.VelocitySpread = 4
        smokeParticle.Texture = "rbxasset://textures/particles/smoke_main.dds"
        smokeParticle.Lifetime = NumberRange.new(2, 4)
        smokeParticle.Size = NumberSequence.new(2, 6)
        smokeParticle.Color = ColorSequence.new(Color3.fromRGB(180, 180, 180))
        smokeParticle.Transparency = NumberSequence.new(0.5, 1)
        smokeParticle.Parent = smokePart
        -- SpotLight (from script: Light on train, Face=Back)
        local spot = Instance.new("SpotLight")
        spot.Angle = 45
        spot.Brightness = 5
        spot.Face = Enum.NormalId.Back
        spot.Range = 30
        spot.Parent = trainMo
        -- Background music (from script: 3761684748 looped)
        local music = Instance.new("Sound")
        music.SoundId = "rbxassetid://3761684748"
        music.Volume = 1
        music.Looped = true
        music.Parent = rp
        task.wait(1)
        pcall(function() music:Play() end)
        -- Touch kill (from script: train.Touched breaks joints + whistle)
        local whistleSnd = Instance.new("Sound")
        whistleSnd.SoundId = "rbxassetid://428593644"
        whistleSnd.Volume = 1
        whistleSnd.Parent = trainMo
        local touchDebounce = {}
        trainMo.Touched:Connect(function(hit)
            pcall(function()
                if hit.Parent and hit.Parent:IsA("Model") and hit.Parent ~= model then
                    if isNoobTeam(hit.Parent) then return end
                    if touchDebounce[hit.Parent] then return end
                    touchDebounce[hit.Parent] = true
                    -- Don't kill players on noob team
                    if Players:GetPlayerFromCharacter(hit.Parent) then return end
                    local hum = humanoidOf(hit.Parent)
                    if hum and hum.Health > 0 then
                        pcall(function() hum.Health = 0 end)
                        pcall(function()
                            -- Break joints (from script)
                            hit.Parent:BreakJoints()
                            local w = whistleSnd:Clone()
                            w.Parent = trainMo
                            w:Play()
                            Debris:AddItem(w, 5)
                        end)
                    end
                    task.wait(1)
                    touchDebounce[hit.Parent] = nil
                end
            end)
        end)
        -- Anti-stuck / WalkSpeed lock (from script's initiateCharacter)
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                pcall(function()
                    if h.WalkSpeed < 60 then h.WalkSpeed = 60 end
                end)
                task.wait(0.5)
            end
        end)
        -- AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Intercept threats to player (long range due to speed)
                if interceptThreatToPlayer(150, 8, function(t, d)
                    -- Train touch will kill on contact; just path to intercept
                end) then didSomething = true end
                -- Hunt killers (long range due to speed)
                local killer, kdist = scanForKillers(300)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        pathTo(tp)  -- train will kill on contact
                        didSomething = true
                    end
                end
                -- Hunt other enemies
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 250)
                    if enemy then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            pathTo(tp)
                            didSomething = true
                        end
                    end
                end
                -- Idle: orbit player
                if not didSomething then
                    local ppos = getPlayerPos()
                    if ppos then
                        -- Orbit around player
                        local offset = Vector3.new(math.random(-30, 30), 0, math.random(-30, 30))
                        pathTo(ppos + offset)
                    end
                    if math.random() > 0.95 then
                        safeChat(head, "CHOO CHOO!", Enum.ChatColor.White)
                    end
                end
                task.wait(0.6)
            end
            pcall(function() music:Stop() music:Destroy() end)
        end)

