                        task.wait()
                    end
                    if bill.Parent then bill:Destroy() end
                end)
            end)
        end
        -- OT damage (from script's OT function — hitbox touch)
        local function otDamage(hit)
            if hitDeb == 1 then return end
            if not hit.Parent or hit.Parent == model or isNoobTeam(hit.Parent) then return end
            local hum = humanoidOf(hit.Parent)
            if hum and hum ~= h then
                local critrnd = math.random(1, crtrate)
                local dmg
                if critrnd ~= 1 then
                    dmg = math.random(mindamage, maxdamage)
                    dmgSplat(dmg, hit, false)
                else
                    dmg = math.random(maxdamage, crtmaxdamage)
                    dmgSplat(dmg, hit, true)
                end
                pcall(function() hum:TakeDamage(dmg) end)
                hitDeb = 1
                task.delay(0.3, function() hitDeb = 0 end)
            end
        end
        hitbox.Touched:Connect(function(hit) pcall(otDamage, hit) end)
        -- AoE damage (from script: AoEP — AoE with push)
        local function aoep(p, magnitude, dmg, crit)
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and (ot.Position - p).Magnitude <= magnitude then
                            oh:TakeDamage(dmg)
                            dmgSplat(dmg, obj:FindFirstChild("Head"), crit)
                            oh.Sit = true
                            local bp = Instance.new("BodyVelocity")
                            bp.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
                            bp.Velocity = (CFrame.new(ot.Position, p).lookVector * 100) + Vector3.new(0, 25, 0)
                            bp.Parent = ot
                            Debris:AddItem(bp, 0.4)
                            task.delay(0.4, function() if oh and oh.Parent then oh.Sit = false end end)
                        end
                    end
                end)
            end
        end
