            eff.CFrame = CFrame.new((lp.p + p1.p)/2, p1.p) * CFrame.Angles(math.rad(90), 0, 0)
            task.spawn(function()
                for i = 0, 1, 0.1 do
                    if not eff.Parent then break end
                    eff.Transparency = i
