                                local oh = humanoidOf(obj); local ot = rootOf(obj)
                                if oh and ot then
                                    local d = (ot.Position - eff.Position).Magnitude
                                    if not ndist or d < ndist then nearest = ot; ndist = d end
                                end
                            end
                        end)
                    end
                    if not nearest then return end
                    -- Ice sword (from script: sword.mesh)
                    local shell = Instance.new("Part")
                    shell.Size = Vector3.new(2, 2, 5)
                    shell.BrickColor = BrickColor.new("Bright blue")
                    shell.Reflectance = 0.25
                    shell.Anchored = true; shell.CanCollide = false
                    local dur = CFrame.new(eff.Position, nearest.Position)
                    shell.CFrame = dur * CFrame.Angles(math.rad(180), 0, 0) * CFrame.new(0, 0, 6.5) * CFrame.Angles(0, 0, math.rad(90))
                    shell.Parent = swordMo
                    local m = Instance.new("SpecialMesh")
                    m.MeshType = Enum.MeshType.FileMesh
                    m.MeshId = "rbxasset://fonts/sword.mesh"
                    m.Scale = Vector3.new(5, 2, 1)
                    m.Parent = shell
                    uss(eff, 1)
                    -- Fly to target (from script: lerp toward target)
                    for i = 0, 1, 0.1 do
                        if not shell.Parent or not nearest.Parent then break end
                        shell.Transparency = 1 - i
                        shell.CFrame = dur * CFrame.Angles(math.rad(180), 0, 0) * CFrame.new(0, 0, 6.5 + 2*i) * CFrame.Angles(0, 0, math.rad(90))
                        m.Scale = Vector3.new(5, 2, 1 + 0.5*i)
                        task.wait()
                    end
                    ss(eff, 2)
                    -- Damage at target
                    for _, obj in ipairs(workspace:GetDescendants()) do
                        pcall(function()
                            if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                                local oh = humanoidOf(obj); local ot = rootOf(obj)
                                if oh and ot and (ot.Position - shell.Position).Magnitude < 5 then
                                    local critrnd = math.random(1, crtrate)
                                    local dmg = (critrnd == 1) and math.random(maxdamage+iceboost, crtmaxdamage+iceboost) or math.random(mindamage+iceboost, maxdamage+iceboost)
                                    oh:TakeDamage(dmg)
                                    dmgSplat(dmg, obj:FindFirstChild("Head"), critrnd == 1)
                                end
                            end
                        end)
                    end
                    -- Fade out
                    for i = 0, 1, 0.1 do
                        if not shell.Parent then break end
                        shell.Transparency = i
                        task.wait()
                    end
                    if shell.Parent then shell:Destroy() end
                end)
                task.wait(0.05)
            end
            task.delay(1.5, function()
                for _, eff in ipairs(effTab) do
                    if eff.Parent then eff:Destroy() end
                end
            end)
        end
        -- FLAME TRAIL (from script: leaves fire trails)
        local flameTrailCD = 0
        local function flameTrail()
            ss(head, 1.5)
            fs(head, 1)
            local effTab = {}
            -- Spawn 6 fire trail effects around the noob
            for i = 1, 6 do
                local lp = hitbox.CFrame * CFrame.new(0, hitbox.Size.y/2, 0)
                local p1 = hitbox.CFrame * CFrame.new(0, hitbox.Size.y/2, 0) * CFrame.new(math.random(-3, 3), 0, math.random(-3, 3))
                local eff = effectTrail("Bright red", 0.2, lp, p1)
                eff.Transparency = 0.5
                table.insert(effTab, eff)
                task.wait(0.1)
            end
            -- Each trail damages nearby enemies (from script: OTND)
            for _, eff in ipairs(effTab) do
                task.spawn(function()
                    for i = 1, 30 do
                        if not eff.Parent then break end
                        for _, obj in ipairs(workspace:GetDescendants()) do
                            pcall(function()
                                if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                                    local oh = humanoidOf(obj); local ot = rootOf(obj)
                                    if oh and ot and (ot.Position - eff.Position).Magnitude < 5 then
                                        local dmg = math.random(1, 12) + fireboost
                                        oh:TakeDamage(dmg)
                                        dmgSplat(dmg, obj:FindFirstChild("Head"), false)
                                    end
                                end
                            end)
                        end
                        task.wait(0.1)
                    end
                end)
            end
            -- Cleanup after 5s (from script)
            task.delay(5, function()
                for _, eff in ipairs(effTab) do
                    if eff.Parent then eff:Destroy() end
                end
            end)
        end
        -- LIFE DRAIN (from script: pull enemy, drain HP, heal self)
        local lifeDrainCD = 0
        local function lifeDrain()
            ss(head, 2)
            -- Find nearest enemy within 50 studs
            local nearest, ndist
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and oh.Health > 0 then
                            local d = (ot.Position - rp.Position).Magnitude
                            if d < 50 and (not ndist or d < ndist) then
                                nearest = obj; ndist = d
                            end
                        end
                    end
                end)
            end
            if not nearest then return end
            local targetTorso = nearest:FindFirstChild("Torso")
            local targetHum = humanoidOf(nearest)
            if not targetTorso or not targetHum then return end
            -- Move to target (from script: BodyPosition + BodyGyro)
            local bp = Instance.new("BodyPosition")
            bp.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
            bp.P = 20000
            bp.Position = targetTorso.Position + CFrame.new(rp.Position, targetTorso.Position).lookVector * -3
            bp.Parent = rp
            -- Damage + heal (from script)
            local critrnd = math.random(1, crtrate)
            local dmg = (critrnd == 1) and math.random(maxdamage, crtmaxdamage) or math.random(mindamage, maxdamage)
            targetHum:TakeDamage(dmg)
            dmgSplat(dmg, nearest:FindFirstChild("Head"), critrnd == 1)
            h.Health = h.Health + (dmg / 5)
            -- Drain particles (from script: white spheres flying to noob)
            for l = 1, math.floor(dmg / 5) do
                task.spawn(function()
                    local p = Instance.new("Part")
                    p.Size = Vector3.new(1, 1, 1); p.BrickColor = BrickColor.new("White")
                    p.Anchored = false; p.CanCollide = false
                    p.CFrame = targetTorso.CFrame + Vector3.new(math.random(-25, 25)/10, math.random(-25, 75)/10, math.random(-25, 25)/10)
                    p.Parent = workspace
                    local bv = Instance.new("BodyPosition")
                    bv.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
                    bv.P = 20000
                    bv.Position = rp.Position
                    bv.Parent = p
                    Debris:AddItem(p, 2)
                end)
                task.wait(0.01)
            end
            bp:Destroy()
        end
        -- FIRE MODE (from script: transformation with flame wings)
        local fireModeCD = 0
        local isFireMode = false
        local function fireMode()
            Mode = "Fire"
            fireboost = 5
            isFireMode = true
            cs(head, 1.5)
            bs(head, 0.75)
            -- Charge particles (from script: violet spheres)
            for l = 1, 10 do
                task.spawn(function()
                    local p = Instance.new("Part")
                    p.Size = Vector3.new(1, 1, 1); p.BrickColor = BrickColor.new("Really red")
                    p.Anchored = false; p.CanCollide = false
                    p.CFrame = hitbox.CFrame * CFrame.new(math.random(-5, 5), math.random(-5, 5), math.random(-5, 5))
                    p.Parent = swordMo
                    local bv = Instance.new("BodyPosition")
                    bv.MaxForce = Vector3.new(200000, 200000, 200000)
                    bv.Position = hitbox.Position
                    bv.Parent = p
                    Debris:AddItem(p, 0.5)
                end)
                task.wait(0.01)
            end
            -- AoE shockwave (from script: attackr + bewm)
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and (ot.Position - rp.Position).Magnitude < 24 then
                            oh:TakeDamage(10 + fireboost)
                            dmgSplat(10 + fireboost, obj:FindFirstChild("Head"), false)
                            if not ot.Anchored then
                                ot.Velocity = ((ot.Position - rp.Position).Unit + Vector3.new(0, 0.5, 0)) * 96
                            end
                        end
                    end
                end)
            end
            -- Shock ring (from script: shockRing)
            local shockRing = Instance.new("Part")
            shockRing.Size = Vector3.new(1, 0.4, 1)
            shockRing.BrickColor = BrickColor.new("Really red")
            shockRing.Anchored = true; shockRing.CanCollide = false
            shockRing.CFrame = CFrame.new(rp.Position + Vector3.new(0, -2.5, 0))
            shockRing.Parent = swordMo
            local decal = Instance.new("CylinderMesh")
            decal.Scale = Vector3.new(1, 0.1, 1); decal.Parent = shockRing
            for x = 0, 1, 0.0625 do
                task.spawn(function()
                    task.wait((x*16)/30)
                    shockRing.Size = Vector3.new(0, 0.4, 0) + Vector3.new(3.2, 0, 3.2) * (x*16)
                    shockRing.Transparency = x
                end)
            end
            Debris:AddItem(shockRing, 1)
            -- Flame wings (from script: wing1p + wing2p + ring spikes)
            local wingHolder = Instance.new("Model"); wingHolder.Name = "Wings"; wingHolder.Parent = swordMo
            local wing1p = Instance.new("Part")
            ssp(wing1p, wingHolder, "FlameWingP1", Vector3.new(0.2, 0.2, 0.2), "Bright red", 0, 1)
            local w1w = Instance.new("Weld"); w1w.Part0 = wing1p; w1w.Part1 = torso
            w1w.C0 = CFrame.new(-1, 0, 0); w1w.Parent = wing1p
            local wing2p = Instance.new("Part")
            ssp(wing2p, wingHolder, "FlameWingP2", Vector3.new(0.2, 0.2, 0.2), "Bright red", 0, 1)
            local w2w = Instance.new("Weld"); w2w.Part0 = wing2p; w2w.Part1 = torso
            w2w.C0 = CFrame.new(1, 0, 0); w2w.Parent = wing2p
            -- Wing spikes (from script: for ringi = -20, 130, 10)
            for ringi = math.rad(-20), math.rad(130), math.rad(10) do
                task.spawn(function()
                    task.wait(0.1)
                    local rp1 = Instance.new("Part")
                    ssp(rp1, wingHolder, "FlameWing"..tostring(ringi), Vector3.new(0.2, 2, 0.8), "Bright red", 0.1, 0)
                    local rpw = Instance.new("Weld")
                    rpw.Part0 = rp1; rpw.Part1 = wing1p
                    rpw.C1 = CFrame.Angles(ringi, 0, 0) * CFrame.new(0, 0.5, 0)
                    rpw.C0 = CFrame.Angles(0, 0, math.rad(45)) * CFrame.new(0, -1, 0)
                    rpw.Parent = rp1
                end)
                task.spawn(function()
                    task.wait(0.1)
                    local rp2 = Instance.new("Part")
                    ssp(rp2, wingHolder, "FlameWing2_"..tostring(ringi), Vector3.new(0.2, 2, 0.8), "Bright red", 0.1, 0)
                    local rpw = Instance.new("Weld")
                    rpw.Part0 = rp2; rpw.Part1 = wing2p
                    rpw.C1 = CFrame.Angles(ringi, 0, 0) * CFrame.new(0, 0.5, 0)
                    rpw.C0 = CFrame.Angles(0, 0, math.rad(-45)) * CFrame.new(0, -1, 0)
                    rpw.Parent = rp2
                end)
            end
            -- End fire mode after 15s (auto-revert)
            task.delay(15, function()
                Mode = "None"
                fireboost = 0
                isFireMode = false
                if wingHolder and wingHolder.Parent then wingHolder:Destroy() end
            end)
        end
        -- AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Intercept threats
                if interceptThreatToPlayer(80, 8, function(t, d)
                    if d < 8 then
                        -- Cycle combo attacks
                        if attackType == 1 then combo1a()
                        elseif attackType == 2 then combo1b()
                        elseif attackType == 3 then
                            local tRoot = rootOf(t.Parent)
                            if tRoot then combo1c(tRoot.Position) end
                        end
                    end
                end) then didSomething = true end
                -- Hunt killers
                local killer, kdist = scanForKillers(220)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist < 6 then
                            -- Melee range: cycle attacks
                            if attackType == 1 then combo1a()
                            elseif attackType == 2 then combo1b()
                            elseif attackType == 3 then combo1c(tp) end
                            didSomething = true
                        elseif kdist < 15 and blizzardCD <= 0 then
                            blizzardCD = 8
                            task.spawn(blizzardSword)
                            didSomething = true
                        elseif kdist < 30 and lifeDrainCD <= 0 then
                            lifeDrainCD = 10
                            task.spawn(lifeDrain)
                            didSomething = true
                        else
                            pathTo(tp)
                            didSomething = true
                        end
                    end
                end
                -- Hunt other enemies
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 150)
                    if enemy then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            if edist < 6 then
                                if attackType == 1 then combo1a()
                                elseif attackType == 2 then combo1b()
                                elseif attackType == 3 then combo1c(tp) end
                                didSomething = true
                            elseif edist < 15 and blizzardCD <= 0 then
                                blizzardCD = 8
                                task.spawn(blizzardSword)
                                didSomething = true
                            elseif edist < 30 and lifeDrainCD <= 0 then
                                lifeDrainCD = 10
                                task.spawn(lifeDrain)
                                didSomething = true
                            else
                                pathTo(tp)
                                didSomething = true
                            end
                        end
                    end
                end
                -- Activate fire mode occasionally (from script's z key)
                if not didSomething and not isFireMode and fireModeCD <= 0 and h.Health < h.MaxHealth * 0.6 then
                    fireModeCD = 30
                    task.spawn(fireMode)
                end
                -- Flame trail when moving (from script's r key)
                if didSomething and flameTrailCD <= 0 and isFireMode then
                    flameTrailCD = 6
                    task.spawn(flameTrail)
                end
                -- Idle
                if not didSomething then
                    returnToPlayer(35)
                    if math.random() > 0.92 then
                        safeChat(head, "Yamato, shed blood.", Enum.ChatColor.White)
                    end
                end
                -- Decrement cooldowns
                if blizzardCD > 0 then blizzardCD = blizzardCD - 1 end
                if flameTrailCD > 0 then flameTrailCD = flameTrailCD - 1 end
                if lifeDrainCD > 0 then lifeDrainCD = lifeDrainCD - 1 end
                if fireModeCD > 0 then fireModeCD = fireModeCD - 1 end
                task.wait(0.8)
            end
        end)

    -- ALBERT NOOB (FLAMINGO) ──────────────────────────────────
    -- Adapted from the Albert/Flamingo script.
    -- Colors: cool yellow head/arms, medium blue legs, bright yellow torso.
    -- Wears signature sunglasses accessory (mesh 120626701, texture 120626735).
    -- Removes default Animator + Animate script (custom C1 lerp animations).
    -- Abilities:
    --   1) normpunch() — 3-punch combo with lerped C1 poses, 5-10 dmg/hit,
    --      hit sound 386946017, while dodamage flag is true.
    --   2) lazor() — SCREECH laser from Right Arm, raycast + Explosion
    --      (BlastPressure 100001, BlastRadius 1) + beam part. 3s duration,
    --      sound 1251737869 (echo), 245537790 (10x).
    --   3) SUPERlazor() — rainbow beam, 1/3 chance destroy hit part,
    --      random velocity, larger blast (radius 10), sound 1179921724.
    --   4) transition() — Super Mode: particle emitter (232918622),
    --      GirlRocker character meshes (717353151/483/619/723/920,
    --      overlay 717346901), 90-frame pose, sound 1321047607.
    --   5) Idle/Run/Jump/Fall animations via C1 lerp (from script's while loop).
    -- WalkSpeed 16. Health 350.
    elseif characterType == "albert_noob" then
        h.WalkSpeed = 18
        h.MaxHealth = 350; h.Health = 350
        -- Body colors (from script: cool yellow arms/head, medium blue legs, bright yellow torso)
        for _, v in pairs(model:GetChildren()) do
            if v:IsA("Part") then
                if v.Name == "Right Arm" or v.Name == "Left Arm" or v.Name == "Head" then
                    v.BrickColor = BrickColor.new("Cool yellow")
                elseif v.Name == "Right Leg" or v.Name == "Left Leg" then
                    v.BrickColor = BrickColor.new("Medium blue")
                elseif v.Name == "Torso" then
                    v.BrickColor = BrickColor.new("Bright yellow")
                end
            end
        end
        -- Sunglasses accessory (from script: mesh 120626701, texture 120626735)
        if head then
            local ac = Instance.new("Accessory")
            ac.AttachmentPos = Vector3.new(0, -0.1, 0.2)
            local handle = Instance.new("Part")
            handle.Name = "Handle"
            handle.Size = Vector3.new(1.6, 0.8, 1.6)
            handle.CanCollide = false; handle.Locked = true
            handle.CFrame = head.CFrame * CFrame.new(0, -0.1, 0.2)
            handle.Parent = ac
            local hm = Instance.new("SpecialMesh")
            hm.MeshId = "http://www.roblox.com/asset/?id=120626701"
            hm.TextureId = "http://www.roblox.com/asset/?id=120626735"
            hm.Scale = Vector3.new(0.9, 0.82, 0.82)
            hm.MeshType = Enum.MeshType.FileMesh
            hm.Parent = handle
            pcall(function() ac.Parent = model end)
        end
        -- Remove default Animator + Animate (from script)
        pcall(function()
            local anim = h:FindFirstChildOfClass("Animator")
            if anim then anim:Destroy() end
            local animate = model:FindFirstChild("Animate")
            if animate then animate:Destroy() end
        end)
        -- Get joints for custom C1 animations (from script)
        local torso = model:FindFirstChild("Torso")
        local rArm = model:FindFirstChild("Right Arm")
        local lArm = model:FindFirstChild("Left Arm")
        local rLeg = model:FindFirstChild("Right Leg")
        local lLeg = model:FindFirstChild("Left Leg")
        local rsh, lsh, rhip, lhip, neck, rootJoint
        if torso then
            rsh = torso:FindFirstChild("Right Shoulder")
            lsh = torso:FindFirstChild("Left Shoulder")
            rhip = torso:FindFirstChild("Right Hip")
            lhip = torso:FindFirstChild("Left Hip")
            neck = torso:FindFirstChild("Neck")
        end
        local hrp = model:FindFirstChild("HumanoidRootPart")
        if hrp then rootJoint = hrp:FindFirstChild("RootJoint") end
        -- Sound helper (from script: sound function)
        local function albertSnd(id, looped, tim, endtim, eff, vol)
            pcall(function()
                local s = Instance.new("Sound")
                s.SoundId = id
                s.Parent = torso
                if looped then
                    s.Looped = true
                    s.Name = "Music"
                else
                    s.Volume = vol or 2
                    if id ~= "rbxassetid://245537790" and id ~= "rbxassetid://1179921724" and id ~= "rbxassetid://1251737869" then
                        s.PlaybackSpeed = 1 + math.random(-100, 100) / 1000
                    end
                end
                if tim then s.TimePosition = tim end
                if eff == "quiet" then s.Volume = 0.3 end
                s:Play()
                Debris:AddItem(s, 10)
            end)
        end
        -- Animation state (from script)
        local animpose = "Idle"
        local cananim = true
        local attacking = false
        local dodamage = false
        local supermode = false
        local punch = 1
        -- Detect animpose (from script)
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                if torso and h then
                    local velocity = torso.Velocity
                    if h.MoveDirection == Vector3.new(0, 0, 0) then
                        animpose = "Idle"
                    else
                        animpose = "Running"
                    end
                    if velocity.Y > 0.5 then animpose = "Jumping" end
                    if velocity.Y < -0.5 then animpose = "Falling" end
                end
                task.wait()
            end
        end)
        -- Custom C1 animation loop (from script's while swait() loop, simplified)
        task.spawn(function()
            local num = 0
            while isAlive(h) and rp.Parent do
                num = num + 0.05
                local sin = math.sin(num)
                if cananim and rsh and lsh and rhip and lhip and neck then
                    if animpose == "Idle" then
                        pcall(function()
                            rsh.C1 = rsh.C1:lerp(CFrame.new(-0.5, 0.5, 0) * CFrame.Angles(0, 0.05, 0), 0.1)
                            lsh.C1 = lsh.C1:lerp(CFrame.new(0.5, 0.5, 0) * CFrame.Angles(0, -0.05, 0), 0.1)
                            neck.C1 = neck.C1:lerp(CFrame.new(0, -0.5, 0) * CFrame.Angles(0, 0, 0), 0.1)
                            rhip.C1 = rhip.C1:lerp(CFrame.new(0.5, 1, 0) * CFrame.Angles(0, 0, 0), 0.1)
                            lhip.C1 = lhip.C1:lerp(CFrame.new(-0.5, 1, 0) * CFrame.Angles(0, 0, 0), 0.1)
                        end)
                    elseif animpose == "Running" then
                        pcall(function()
                            rsh.C1 = rsh.C1:lerp(CFrame.new(-0.5, 0.5, 0) * CFrame.Angles(math.rad(-30) * sin, 0, 0), 0.2)
                            lsh.C1 = lsh.C1:lerp(CFrame.new(0.5, 0.5, 0) * CFrame.Angles(math.rad(30) * sin, 0, 0), 0.2)
                            rhip.C1 = rhip.C1:lerp(CFrame.new(0.5, 1, 0) * CFrame.Angles(math.rad(30) * sin, 0, 0), 0.2)
                            lhip.C1 = lhip.C1:lerp(CFrame.new(-0.5, 1, 0) * CFrame.Angles(math.rad(-30) * sin, 0, 0), 0.2)
                            neck.C1 = neck.C1:lerp(CFrame.new(0, -0.5, 0) * CFrame.Angles(math.rad(-5), 0, 0), 0.2)
                        end)
                    elseif animpose == "Jumping" or animpose == "Falling" then
                        pcall(function()
                            rsh.C1 = rsh.C1:lerp(CFrame.new(-0.5, 0.5, 0) * CFrame.Angles(math.rad(-90), 0, 0), 0.2)
                            lsh.C1 = lsh.C1:lerp(CFrame.new(0.5, 0.5, 0) * CFrame.Angles(math.rad(-90), 0, 0), 0.2)
                            rhip.C1 = rhip.C1:lerp(CFrame.new(0.5, 1, 0) * CFrame.Angles(math.rad(20), 0, 0), 0.2)
                            lhip.C1 = lhip.C1:lerp(CFrame.new(-0.5, 1, 0) * CFrame.Angles(math.rad(-20), 0, 0), 0.2)
                            neck.C1 = neck.C1:lerp(CFrame.new(0, -0.5, 0) * CFrame.Angles(math.rad(10), 0, 0), 0.2)
                        end)
                    end
                end
                task.wait()
            end
        end)
        -- NORMAL PUNCH (from script: 3-punch combo with lerped C1 poses)
        local punchCD = 0
        local function normpunch(targetHum)
            if attacking then return end
            dodamage = true
            attacking = true
            cananim = false
            albertSnd("rbxassetid://138097048", false)
            -- 3 punch animations (from script: punch 1/2/3 C1 lerp poses)
            -- Damage during punch (from script: hum.Touched handler)
            if targetHum then
                pcall(function() targetHum.Health = targetHum.Health - math.random(5, 10) end)
                albertSnd("rbxassetid://386946017", false, nil, nil, "quiet")
            end
            -- Punch animation pose (alternating)
            if rsh and torso then
                pcall(function()
                    if punch == 1 then
                        rsh.C1 = rsh.C1:lerp(CFrame.new(-0.31, 0.8, -0.04) * CFrame.Angles(math.rad(-20), 0.06, math.rad(85)), 0.3)
                    elseif punch == 2 then
                        lsh.C1 = lsh.C1:lerp(CFrame.new(0.5, 0.5, 0) * CFrame.Angles(math.rad(-90), 0, math.rad(20)), 0.3)
                    else
                        rsh.C1 = rsh.C1:lerp(CFrame.new(-0.5, 0.5, 0) * CFrame.Angles(math.rad(-120), 0, 0), 0.3)
                    end
                end)
            end
            if punch ~= 3 then punch = punch + 1 else punch = 1 end
            task.wait(0.4)
            cananim = true
            dodamage = false
