        -- Effect helpers (from script's MagicSphere + MagicBlock)
        local function magicSphere(size, waitFrames, cframe, color, grow, trans)
            local p = Instance.new("Part")
            p.Material = Enum.Material.Neon; p.BrickColor = BrickColor.new(color)
            p.Size = Vector3.new(1, 1, 1); p.Anchored = true; p.CanCollide = false
            p.CFrame = cframe; p.Transparency = trans or 0
            p.Parent = effectsFolder
            local m = Instance.new("SpecialMesh")
            m.MeshType = Enum.MeshType.Sphere; m.Scale = size; m.Parent = p
            task.spawn(function()
                for i = 1, waitFrames do
                    if not p.Parent then break end
                    m.Scale = m.Scale + grow
                    p.Transparency = p.Transparency + ((1 - (trans or 0)) / waitFrames)
                    if p.Transparency > 0.99 then p:Destroy(); break end
                    task.wait()
                end
                if p.Parent then p:Destroy() end
            end)
        end
        local function magicBlock(size, waitFrames, cframe, color, grow, trans)
            local p = Instance.new("Part")
            p.Material = Enum.Material.Neon; p.BrickColor = BrickColor.new(color)
            p.Size = Vector3.new(size, size, size); p.Anchored = true; p.CanCollide = false
            p.CFrame = cframe; p.Transparency = trans or 0
            p.Parent = effectsFolder
            task.spawn(function()
                for i = 1, waitFrames do
                    if not p.Parent then break end
                    p.Size = p.Size + grow
                    p.CFrame = cframe * CFrame.Angles(math.rad(math.random(-360, 360)), math.rad(math.random(-360, 360)), math.rad(math.random(-360, 360)))
                    p.Transparency = p.Transparency + ((1 - (trans or 0)) / waitFrames)
                    if p.Transparency > 0.99 then p:Destroy(); break end
                    task.wait()
                end
                if p.Parent then p:Destroy() end
            end)
        end
        -- AoE damage (from script's AoEDamage, simplified)
        local function aoEDamage(position, radius, minDmg, maxDmg, maxStrength, critRate, critMult)
            local dmg = math.random(minDmg, maxDmg)
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and oh.Health > 0 and (ot.Position - position).Magnitude < radius then
                            local finalDmg = dmg
                            if math.random(1, 100) < critRate + 1 then
                                finalDmg = dmg * critMult
                            end
                            oh:TakeDamage(finalDmg)
                            if not ot.Anchored then
                                ot.Velocity = CFrame.new(position, ot.Position).lookVector * 5 * maxStrength
                            end
                        end
                    end
                end)
            end
        end
