        -- Dispatch ability by stance (from script's KeyDown handler)
        local abilityCD = 0
        local function useStanceAbility(targetPos)
            if abilityCD > 0 then return end
            abilityCD = 4
            local stance = currentStance
            if stance == 1 then turretCannon(targetPos)
            elseif stance == 2 then fireball(targetPos)
            elseif stance == 3 then icicleStorm(targetPos)
            elseif stance == 4 then shriek()
            elseif stance == 5 then rockThrow(targetPos)
            elseif stance == 6 then radiantVoid()
            elseif stance == 7 then divineGlow()
            elseif stance == 8 then leafStorm(targetPos)
            elseif stance == 9 then meteor(targetPos)
            elseif stance == 10 then selfexplosion()
            end
        end
        -- Stance cycler (cycles every 15s, from script's 1-0 keys)
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                task.wait(15)
                if not isAlive(h) then break end
                local nextStance = (currentStance % 10) + 1
                applyStance(nextStance)
                safeChat(head, "Stance "..tostring(nextStance).."!", Enum.ChatColor.White)
            end
        end)
        -- AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Intercept threats
                if interceptThreatToPlayer(100, 10, function(t, d)
                    if d > 10 and d < 150 then
                        local tRoot = rootOf(t.Parent)
                        if tRoot then useStanceAbility(tRoot.Position) end
                    elseif d < 10 then
                        t:TakeDamage(20)
                    end
                end) then didSomething = true end
                -- Hunt killers
                local killer, kdist = scanForKillers(250)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist < 10 then
                            killer:TakeDamage(20)
                        elseif kdist < 150 then
                            useStanceAbility(tp)
                        else
                            pathTo(tp)
                        end
                        didSomething = true
                    end
                end
                -- Hunt other enemies
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 200)
                    if enemy then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            if edist < 10 then
                                enemy:TakeDamage(20)
                            elseif edist < 150 then
                                useStanceAbility(tp)
                            else
                                pathTo(tp)
                            end
                            didSomething = true
                        end
                    end
                end
                -- Idle
                if not didSomething then
                    returnToPlayer(40)
                    if math.random() > 0.9 then
                        local stanceNames = {"Pearl","Flame","Frost","Blood","Earth","Void","Holy","Leaf","Meteor","Crimson"}
                        safeChat(head, stanceNames[currentStance].." stance active.", Enum.ChatColor.White)
                    end
                end
                if abilityCD > 0 then abilityCD = abilityCD - 1 end
                task.wait(0.8)
            end
            pcall(function() sick:Stop() sick:Destroy() end)
        end)


