    --   4) shadowRoam() — go invisible, spawn shadow spikes on click
    --   5) taunt() — enrage scream, AoE knockback (200 fling)
    -- HP = math.huge, WalkSpeed 25. Music 900318768 looped.
    -- Sounds: vocals 468972244/378/711/944, charge 459523787,
    --         roughblast 461105534, wall 424195952, 278641993, 84005018.
    elseif characterType == "satan_noob" then
        h.WalkSpeed = 25
        h.MaxHealth = math.huge; h.Health = math.huge
        local SIZE = 2
        -- Resize body parts (from script)
        for _, v in pairs(model:GetChildren()) do
            if v:IsA("BasePart") and v.Name ~= "HumanoidRootPart" then
                v.Size = v.Size * SIZE
            end
        end
        -- Make all parts Granite + black (from script's while-loop material/color)
        for _, v in pairs(model:GetChildren()) do
            if v:IsA("BasePart") and v.Name ~= "HumanoidRootPart" then
                v.Material = Enum.Material.Granite
                v.Color = Color3.new(0, 0, 0)
            end
        end
        -- Custom head mesh (from script: 1532586252/1532589976)
        if head then
            pcall(function()
                head:ClearAllChildren()
