        -- AoE damage (from script's ApplyAoE, simplified)
        local function satanAoE(pos, range, minDmg, maxDmg, fling)
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and oh.Health > 0 and (ot.Position - pos).Magnitude <= range then
                            oh:TakeDamage(math.random(minDmg, maxDmg))
                            if fling > 0 and not ot.Anchored then
                                local bv = Instance.new("BodyVelocity")
                                bv.MaxForce = Vector3.new(1e9, 1e9, 1e9)
                                bv.Velocity = CFrame.new(pos, ot.Position).lookVector * fling
                                bv.Parent = ot
                                Debris:AddItem(bv, 0.1)
                            end
                        end
                    end
                end)
            end
        end
        -- Effect: expanding sphere (from script's WACKYEFFECT Sphere)
        local function effectSphere(size, endSize, cframe, color, time)
            local p = Instance.new("Part")
            p.Material = Enum.Material.Neon; p.BrickColor = BrickColor.new(color)
            p.Size = Vector3.new(1, 1, 1); p.Anchored = true; p.CanCollide = false
            p.CFrame = cframe; p.Transparency = 0; p.Parent = workspace
            local m = Instance.new("SpecialMesh")
            m.MeshType = Enum.MeshType.Sphere; m.Scale = size; m.Parent = p
            task.spawn(function()
                local growth = size - endSize
                for i = 1, (time or 30) do
                    if not p.Parent then break end
                    m.Scale = m.Scale - growth / (time or 30)
                    p.Transparency = p.Transparency + (1 / (time or 30))
                    task.wait()
                end
                if p.Parent then p:Destroy() end
            end)
        end
