        -- ABILITY 4: TAUNT (from script — enrage scream + AoE knockback)
        local tauntCD = 0
        local function taunt()
            ssnd(528589078, head, 10, 1)
            local tauntDuration = 60
            for i = 1, tauntDuration do
                if not isAlive(h) then break end
                -- AoE knockback (from script: ApplyAoE with 200 fling)
                satanAoE(head.Position, 15, 0, 0, 200)
                -- Visual waves (from script)
                effectWave(Vector3.new(0, 2, 0), Vector3.new(15, 0, 15), CFrame.new(head.Position) * CFrame.Angles(math.rad(math.random(0, 360)), math.rad(math.random(0, 360)), math.rad(math.random(0, 360))), "White", 15)
                task.wait()
            end
        end
        -- AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Intercept threats
                if interceptThreatToPlayer(120, 10, function(t, d)
                    if d < 10 then
                        t:TakeDamage(30)
                    elseif d > 10 and d < 80 and missilesCD <= 0 then
                        missilesCD = 12
                        local tRoot = rootOf(t.Parent)
                        if tRoot then task.spawn(missilesOfDespair, tRoot.Position) end
                    end
                end) then didSomething = true end
                -- Hunt killers
                local killer, kdist = scanForKillers(300)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist < 10 then
                            killer:TakeDamage(30)
                            didSomething = true
                        elseif kdist < 60 and missilesCD <= 0 then
                            missilesCD = 12
                            task.spawn(missilesOfDespair, tp)
                            didSomething = true
                        elseif kdist < 100 and pillarCD <= 0 then
                            pillarCD = 20
                            task.spawn(pillarOfDespair)
                            didSomething = true
                        elseif kdist < 80 and infernoCD <= 0 then
                            infernoCD = 15
                            task.spawn(infernoWall)
                            didSomething = true
                        else
                            pathTo(tp)
                            didSomething = true
                        end
                    end
                end
                -- Hunt other enemies
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 200)
                    if enemy then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            if edist < 10 then
                                enemy:TakeDamage(30)
                                didSomething = true
                            elseif edist < 60 and missilesCD <= 0 then
                                missilesCD = 12
                                task.spawn(missilesOfDespair, tp)
                                didSomething = true
                            elseif edist < 100 and pillarCD <= 0 then
                                pillarCD = 20
                                task.spawn(pillarOfDespair)
                                didSomething = true
                            elseif edist < 80 and infernoCD <= 0 then
                                infernoCD = 15
                                task.spawn(infernoWall)
                                didSomething = true
                            else
                                pathTo(tp)
                                didSomething = true
                            end
                        end
                    end
                end
                -- Random taunt (from script's t key)
                if not didSomething and tauntCD <= 0 and math.random() > 0.7 then
                    tauntCD = 25
                    task.spawn(taunt)
                end
                -- Idle
                if not didSomething then
                    returnToPlayer(45)
                    if math.random() > 0.92 then
                        local phrases = {"Bow before me.", "Despair.", "Your soul is mine.", "Inferno awaits."}
                        safeChat(head, phrases[math.random(1, #phrases)], Enum.ChatColor.Red)
                    end
                end
                if missilesCD > 0 then missilesCD = missilesCD - 1 end
                if pillarCD > 0 then pillarCD = pillarCD - 1 end
                if infernoCD > 0 then infernoCD = infernoCD - 1 end
                if tauntCD > 0 then tauntCD = tauntCD - 1 end
                task.wait(0.8)
            end
