        local lLeg = model:FindFirstChild("Left Leg")
        local torso = model:FindFirstChild("Torso")
        -- MP system (from script)
        local maxmp = 1250000
        local mp = maxmp
        local ns = 18
        -- Build spike suit model (from script: invisible real body + suit parts)
        local suitMo = Instance.new("Model")
        suitMo.Name = "Suit"
        suitMo.Parent = model
        -- Make real body invisible (from script: invis(c))
        for _, v in pairs(model:GetChildren()) do
