            end
        end
        -- Suit parts (from script: lime green BlockMesh, 5x scale)
        local suitColor = "Lime green"
        local function makeSuitPart(name, size, meshScale, meshOffset)
            local p = Instance.new("Part")
            p.Name = name; p.Shape = Enum.PartType.Block
            p.formFactor = Enum.FormFactor.Custom
            p.Size = Vector3.new(0, 0, 0)  -- size from mesh
            p.CanCollide = false; p.Anchored = false
            p.BrickColor = BrickColor.new(suitColor)
            p.Transparency = 0; p.BottomSurface = 0; p.TopSurface = 0
            p.Velocity = Vector3.new(0, 10, 0)
            p:BreakJoints()
            p.Parent = suitMo
            local m = Instance.new("BlockMesh")
            m.Offset = meshOffset or Vector3.new(0, 0, 0)
            m.Scale = meshScale
            m.Parent = p
            return p
        end
        local suitTorso = makeSuitPart("Torso", nil, Vector3.new(10, 10, 5), Vector3.new(0, 0, 0))
        local suitLArm = makeSuitPart("Left Arm", nil, Vector3.new(5, 10, 5), Vector3.new(0, -1, 0))
        local suitRArm = makeSuitPart("Right Arm", nil, Vector3.new(5, 10, 5), Vector3.new(0, -1, 0))
        local suitLLeg = makeSuitPart("Left Leg", nil, Vector3.new(5, 10, 5), Vector3.new(0, -1, 0))
        local suitRLeg = makeSuitPart("Right Leg", nil, Vector3.new(5, 10, 5), Vector3.new(0, -1, 0))
        -- Weld suit parts to real body (from script)
        local function weldSuit(part, realPart, c0)
            local w = Instance.new("Weld")
            w.Part0 = part; w.Part1 = realPart
            w.C0 = c0
            w.Parent = part
            return w
        end
        local suitTW = weldSuit(suitTorso, torso, CFrame.new(0, 0, 0))
        local suitLAW = weldSuit(suitLArm, lArm, CFrame.new(-1.5, 1, 0))
        local suitRAW = weldSuit(suitRArm, rArm, CFrame.new(1.5, 1, 0))
        local suitLLW = weldSuit(suitLLeg, lLeg, CFrame.new(-0.5, -1, 0))
        local suitRLW = weldSuit(suitRLeg, rLeg, CFrame.new(0.5, -1, 0))
        -- Spike model holder (from script: Misc["x"])
