        spikeMisc.Name = "MiscX"
        spikeMisc.Parent = suitMo
        -- Sound helper (from script: Sound function)
        local function spikeSnd(sid, pit, vol)
            pcall(function()
                local s = Instance.new("Sound")
                s.SoundId = (sid:find("rbxasset") or sid:find("http")) and sid or ("rbxassetid://"..sid)
                s.Pitch = pit or 1; s.Volume = (vol or 1) / 3
                s.PlayOnRemove = true
                s.Parent = head
                task.wait()
                s:Destroy()
            end)
        end
        -- Trail effect (from script: Trail function)
        local function trail(ob, times, col, thickz, ofz)
            task.spawn(function()
                local oldpos = (ob.CFrame * ofz).p
                for i = 1, times do
                    if not ob.Parent then break end
                    local obp = (ob.CFrame * ofz).p
                    local mag = (oldpos - obp).Magnitude
                    local tr = Instance.new("Part")
                    tr.BrickColor = BrickColor.new(col); tr.Anchored = true
                    tr.CanCollide = false; tr.Transparency = 0.5
                    tr.Size = Vector3.new(0, 0, 0)
                    tr.Parent = workspace
                    local trm = Instance.new("CylinderMesh")
                    trm.Scale = Vector3.new(5*thickz, mag*5, 5*thickz)
                    trm.Parent = tr
                    tr.CFrame = CFrame.new(oldpos, obp) * CFrame.new(0, 0, mag/2) * CFrame.Angles(math.rad(90), 0, 0)
                    oldpos = obp
                    -- Fade
                    task.spawn(function()
                        for j = 5*thickz, 0, -5*thickz/10 do
                            if not tr.Parent then break end
                            trm.Scale = Vector3.new(j, mag*5, j)
                            task.wait()
                        end
                        if tr.Parent then tr:Destroy() end
                    end)
                    task.wait(0.15)
                end
            end)
        end
        -- SHOOT SPIKE (from script: ShootSpike function)
        local function shootSpike(scale, origin, targetPos, isTrail)
            spikeSnd("rbxasset://sounds/swordslash.wav", 1.1, 1)
            local spi = Instance.new("Part")
            spi.BrickColor = BrickColor.new(suitColor)
            spi.Size = Vector3.new(0.6*scale, 2*scale, 0.6*scale)
            spi.CanCollide = false; spi.Anchored = true
            spi.Parent = workspace
            local spim = Instance.new("SpecialMesh")
            spim.MeshType = Enum.MeshType.FileMesh
            spim.MeshId = "rbxassetid://1033714"
            spim.Scale = Vector3.new(0.12*scale, 3*scale, 0.12*scale)
            spim.Parent = spi
            spi.CFrame = CFrame.new(origin, targetPos) * CFrame.Angles(math.rad(-90), 0, 0)
            if isTrail then task.spawn(function() trail(spi, 15, suitColor, 0.35, CFrame.new(0, -1, 0)) end) end
            -- Fly + hit detection (from script)
            task.spawn(function()
                local tyms = 0
                local minusz = 0
                repeat
                    if not spi.Parent or not isAlive(h) then break end
                    tyms = tyms + 2
                    minusz = (-90/3000/110) * tyms
                    local bhit, bpos = workspace:FindPartOnRay(Ray.new(spi.Position, spi.Position - (spi.CFrame * CFrame.new(0, -1, 0)).p), model)
                    if bpos and (bpos - (spi.CFrame * CFrame.new(0, 1, 0)).p).Magnitude < 2.2 then
                        -- Hit
                        if bhit and bhit.Parent and not isNoobTeam(bhit.Parent) then
                            local oh = humanoidOf(bhit.Parent)
                            if oh then
                                oh:TakeDamage(math.random(10, 24))
                                spikeSnd("rbxassetid://2801263", 1.35, 1)
                            end
                        end
                        spi:Destroy()
                        break
                    else
                        spi.CFrame = spi.CFrame * CFrame.new(0, 2, 0) * CFrame.Angles(math.rad(minusz), 0, 0)
                    end
                    if tyms % 8 == 0 then task.wait() end
                until not spi.Parent or tyms > 3000
                if spi.Parent then spi:Destroy() end
            end)
        end
        -- ABILITY: SUMMON SPIKES (from script: Anim.Act "x" true)
        local spikesActive = false
        local bodySpikes = {}
