            if spikesActive then return end
            spikesActive = true
            -- Torso spikes (18, from script)
            for i = 1, 18 do
                local spi = Instance.new("Part")
                spi.BrickColor = BrickColor.new(suitColor); spi.CanCollide = false
                spi.Size = Vector3.new(0, 0, 0); spi.Parent = spikeMisc
                local spim = Instance.new("SpecialMesh")
                spim.MeshType = Enum.MeshType.FileMesh; spim.MeshId = "rbxassetid://1033714"
                spim.Scale = Vector3.new(0.1, 0, 0.1); spim.Parent = spi
                local spiw = Instance.new("Weld")
                spiw.Part0 = suitTorso; spiw.Part1 = spi
                spiw.C0 = CFrame.new(math.random(-8, 8)/10, math.random(-8, 8)/10, 0)
                    * CFrame.Angles(math.rad(math.random(60, 120)), 0, math.rad(math.random(-30, 30)))
                spiw.Parent = spi
                table.insert(bodySpikes, {weld = spiw, mesh = spim})
                -- Grow (from script)
                task.spawn(function()
                    for j = 0, 1, 0.1 do
                        if not spiw.Parent then break end
                        spiw.C0 = spiw.C0 * CFrame.new(0, 0.17, 0)
                        spim.Scale = Vector3.new(0.25, j*4, 0.25)
