            end
            -- Arm + leg spikes (4 each, from script)
            for _, info in ipairs({{suitLArm, CFrame.new(0.2, -0.2, -0.25) * CFrame.Angles(math.rad(-45), 0, math.rad(120))},
                                    {suitRArm, CFrame.new(-0.2, -0.2, -0.25) * CFrame.Angles(math.rad(-45), 0, math.rad(-120))},
                                    {suitLLeg, CFrame.new(0.2, 0.2, -0.3) * CFrame.Angles(0, math.rad(50), math.rad(70))},
                                    {suitRLeg, CFrame.new(-0.2, 0.2, -0.3) * CFrame.Angles(0, math.rad(-50), math.rad(-70))}}) do
                for i = 1, 2 do
                    local spi = Instance.new("Part")
