        -- AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Intercept threats
                if interceptThreatToPlayer(90, 8, function(t, d)
                    if d < 8 then
                        t:TakeDamage(math.random(10, 24))
                    elseif d > 8 and d < 100 and spikeShootCD <= 0 and mp >= 6 then
                        local tRoot = rootOf(t.Parent)
                        if tRoot then spikeShoot(tRoot.Position) end
                    end
                end) then didSomething = true end
                -- Hunt killers
                local killer, kdist = scanForKillers(250)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist < 8 then
                            killer:TakeDamage(math.random(10, 24))
                            didSomething = true
                        elseif kdist < 100 and mp >= 6 then
                            spikeShoot(tp)
                            didSomething = true
                        elseif kdist < 30 and spinSlashCD <= 0 and mp >= 150 then
                            task.spawn(spinSlash)
                            didSomething = true
                        elseif kdist < 50 and spikeWallCD <= 0 and mp >= 60 then
                            task.spawn(spikeWall, tp)
                            didSomething = true
                        elseif kdist < 80 and spikeCannonCD <= 0 and mp >= 8 then
                            task.spawn(spikeCannon, tp)
                            didSomething = true
                        else
                            pathTo(tp)
                            didSomething = true
                        end
                    end
                end
                -- Hunt other enemies
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 200)
                    if enemy then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            if edist < 8 then
                                enemy:TakeDamage(math.random(10, 24))
                                didSomething = true
                            elseif edist < 100 and mp >= 6 then
                                spikeShoot(tp)
                                didSomething = true
                            elseif edist < 30 and spinSlashCD <= 0 and mp >= 150 then
                                task.spawn(spinSlash)
                                didSomething = true
                            elseif edist < 50 and spikeWallCD <= 0 and mp >= 60 then
                                task.spawn(spikeWall, tp)
                                didSomething = true
                            elseif edist < 80 and spikeCannonCD <= 0 and mp >= 8 then
                                task.spawn(spikeCannon, tp)
                                didSomething = true
                            else
                                pathTo(tp)
                                didSomething = true
                            end
                        end
                    end
                end
                -- Idle
                if not didSomething then
                    returnToPlayer(40)
                    if math.random() > 0.92 then
                        safeChat(head, "Spike power: "..tostring(math.floor(mp/1000)).."K", Enum.ChatColor.Green)
                    end
                end
                if spikeShootCD > 0 then spikeShootCD = spikeShootCD - 1 end
                if spikeWallCD > 0 then spikeWallCD = spikeWallCD - 1 end
                if spikeCannonCD > 0 then spikeCannonCD = spikeCannonCD - 1 end
                if spinSlashCD > 0 then spinSlashCD = spinSlashCD - 1 end
                task.wait(0.6)
            end
        end)


