                tl.Parent = bb
                -- Clone body parts as red neon (from script)
                for _, v in ipairs(character:GetChildren()) do
                    if v:IsA("BasePart") and v.Name ~= "HumanoidRootPart" then
                        local bod = v:Clone()
                        bod.CanCollide = false; bod.Anchored = true
                        bod.CFrame = v.CFrame; bod.Parent = banFolder
                        bod.Material = Enum.Material.Neon
                        bod.Color = Color3.new(1, 0, 0)
                        local decal = bod:FindFirstChildOfClass("Decal")
                        if decal then decal:Destroy() end
                        if bod.Name == "Head" then bb.Adornee = bod end
                    end
                end
                -- Kill the character (from script: CHARACTER:remove())
                pcall(function() character:BreakJoints() end)
                local oh = humanoidOf(character)
                if oh then pcall(function() oh.Health = 0 end) end
                -- Blink effect (from script: 50-frame blink)
                task.spawn(function()
                    for i = 1, 50 do
                        if not banFolder.Parent then break end
                        for _, v in ipairs(banFolder:GetChildren()) do
                            if v:IsA("BasePart") then v.Transparency = 1 end
                        end
                        bb.Enabled = false
                        task.wait()
                        for _, v in ipairs(banFolder:GetChildren()) do
                            if v:IsA("BasePart") then v.Transparency = 0 end
                        end
                        bb.Enabled = true
                        task.wait()
                    end
                    if banFolder.Parent then banFolder:Destroy() end
                end)
            end)
        end
        -- BAN NEAREST (from script: BANNEAREST function)
        local function banNearest(pos, range)
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and (ot.Position - pos).Magnitude < range then
                            BAN(obj)
                        end
                    end
                end)
            end
        end
        -- Create debris ring (from script: CreateDebreeRing)
        local function createDebreeRing(position, size, blockSize)
            task.spawn(function()
                local center = Instance.new("Part")
                center.Material = Enum.Material.Plastic; center.BrickColor = BrickColor.new("Pearl")
                center.Size = Vector3.new(0, 0, 0); center.Transparency = 1
                center.Anchored = true; center.CanCollide = false
                center.CFrame = CFrame.new(position); center.Parent = workspace
                for i = 1, 45 do
                    local piece = Instance.new("Part")
                    piece.Material = Enum.Material.Plastic; piece.BrickColor = BrickColor.new("Pearl")
                    piece.Size = blockSize; piece.CanCollide = false
                    piece.CFrame = center.CFrame * CFrame.Angles(0, math.rad(i*8), 0)
                        * CFrame.new(size*4, 0, 0)
                        * CFrame.Angles(math.rad(math.random(-360, 360)), math.rad(math.random(-360, 360)), math.rad(math.random(-360, 360)))
                    piece.Parent = workspace
                    Debris:AddItem(piece, 1)
                end
                center:Destroy()
            end)
        end
        -- Create wave effect (from script: CreateWave, mesh 20329976)
        local function createWave(size, waitFrames, cframe, rot, color, grow)
            local wave = Instance.new("Part")
            wave.Material = Enum.Material.Neon; wave.BrickColor = BrickColor.new(color)
            wave.Size = Vector3.new(0, 0, 0); wave.Transparency = 0.5
            wave.Anchored = true; wave.CanCollide = false
            wave.CFrame = cframe; wave.Parent = workspace
            local m = Instance.new("SpecialMesh")
            m.MeshType = Enum.MeshType.FileMesh; m.MeshId = "rbxassetid://20329976"
            m.Scale = size; m.Offset = Vector3.new(0, 0, -size.X/8)
            m.Parent = wave
            task.spawn(function()
                for i = 1, waitFrames do
                    if not wave.Parent then break end
                    m.Scale = m.Scale + grow
                    m.Offset = Vector3.new(0, 0, -m.Scale.X/8)
                    if rot then wave.CFrame = wave.CFrame * CFrame.Angles(0, math.rad(2), 0) end
                    wave.Transparency = wave.Transparency + (0.5/waitFrames)
                    if wave.Transparency > 0.99 then wave:Destroy(); break end
                    task.wait()
                end
                if wave.Parent then wave:Destroy() end
            end)
        end
        -- ABILITY: BAN SLAM (from script: BANSLAM function)
        local banSlamCD = 0
        local function banSlam()
            -- Jump up (from script: RootJoint.C0 CF(0,0,7))
            hsnd(147722910, torso, 10, 1)
            -- BAN nearest (from script: BANNEAREST 25-stud range)
            local slamPos = rp.CFrame * CFrame.new(0, 0, -6)
            banNearest(slamPos.p, 25)
            -- Debris ring (from script: CreateDebreeRing)
            createDebreeRing((rp.CFrame * CFrame.new(0, -5, -6)).p, 5, Vector3.new(8, 8, 8))
            -- Red waves (from script: 2x CreateWave)
            createWave(Vector3.new(25, 0, 25), 45, rp.CFrame * CFrame.new(0, -5, -6), true, "Really red", Vector3.new(0, 3, 0))
            createWave(Vector3.new(25, 0, 25), 45, rp.CFrame * CFrame.new(0, -5, -6), true, "Really red", Vector3.new(0, 3, 0))
            -- Slam sounds (from script: 4x 289842971)
            hsnd(289842971, handle, 10, 1)
            hsnd(289842971, handle, 10, 1)
            hsnd(289842971, handle, 10, 1)
            hsnd(289842971, handle, 10, 1)
        end
        -- ABILITY: TELEPORT (from script: KeyDown "b")
        local teleportCD = 0
        local function teleport(targetPos)
            local pos = rp.Position
            rp.CFrame = CFrame.new(targetPos + Vector3.new(0, 3, 0), pos)
            hsnd(769380905, torso, 10, 1)
        end
        -- AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Intercept threats
                if interceptThreatToPlayer(100, 8, function(t, d)
                    if d < 25 and banSlamCD <= 0 then
                        banSlamCD = 6
                        task.spawn(banSlam)
                    elseif d > 25 and d < 80 and teleportCD <= 0 then
                        teleportCD = 10
                        local tRoot = rootOf(t.Parent)
                        if tRoot then teleport(tRoot.Position) end
                    elseif d < 8 then
                        t:TakeDamage(50)
                    end
                end) then didSomething = true end
                -- Hunt killers
                local killer, kdist = scanForKillers(300)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist < 25 and banSlamCD <= 0 then
                            banSlamCD = 6
                            task.spawn(banSlam)
                            didSomething = true
                        elseif kdist > 25 and kdist < 80 and teleportCD <= 0 then
                            teleportCD = 10
                            teleport(tp)
                            didSomething = true
                        else
                            pathTo(tp)
                            didSomething = true
                        end
                    end
                end
                -- Hunt other enemies
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 200)
                    if enemy then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            if edist < 25 and banSlamCD <= 0 then
                                banSlamCD = 6
                                task.spawn(banSlam)
                                didSomething = true
                            elseif edist > 25 and edist < 80 and teleportCD <= 0 then
                                teleportCD = 10
                                teleport(tp)
                                didSomething = true
                            else
                                pathTo(tp)
                                didSomething = true
                            end
                        end
                    end
                end
                -- Idle
                if not didSomething then
                    returnToPlayer(40)
                    if math.random() > 0.92 then
                        safeChat(head, "IS HAMMER TIME!", Enum.ChatColor.Yellow)
                    end
                end
                if banSlamCD > 0 then banSlamCD = banSlamCD - 1 end
                if teleportCD > 0 then teleportCD = teleportCD - 1 end
                task.wait(0.8)
            end
            pcall(function() sick:Stop() sick:Destroy() end)
        end)


