            bl.Parent = workspace
            local bv = Instance.new("BodyVelocity")
            bv.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
            bv.Velocity = (targetPos - rp.Position).Unit * 160
            bv.Parent = bl
            -- Ring effect (from script: expanding white ring)
            task.spawn(function()
                local ring = Instance.new("Part")
                ring.Size = Vector3.new(1, 1, 1); ring.CanCollide = false; ring.Anchored = true
                ring.CFrame = rp.CFrame * CFrame.new(0, 0, -9)
                ring.BrickColor = BrickColor.new("Institutional white")
                ring.Parent = workspace
                local rm = Instance.new("SpecialMesh")
                rm.MeshId = "rbxassetid://3270017"; rm.Scale = Vector3.new(1, 1, 0.1)
                rm.Parent = ring
                for i = 1, 50 do
                    if not ring.Parent then break end
