                    ring.Transparency = ring.Transparency + 0.07
                    task.wait()
                end
                if ring.Parent then ring:Destroy() end
            end)
            -- Hit handler (from script: 60 dmg + WalkSpeed 2)
            local hitDeb = false
            bl.Touched:Connect(function(hit)
                if hitDeb then return end
                if hit:IsDescendantOf(model) or isNoobTeam(hit.Parent) then return end
                hitDeb = true
                local oh = humanoidOf(hit.Parent)
