                if oh and ot then
                    oh:TakeDamage(60)
                    oh.WalkSpeed = 2
                    spsnd(539294959, hit.Parent:FindFirstChild("Head"), 1, 1)
                    -- Hit effect: expanding yellow sphere + 6 white rings (from script)
                    task.spawn(function()
                        local ef = Instance.new("Part")
                        ef.Size = Vector3.new(1, 1, 1); ef.CanCollide = false; ef.Anchored = true
                        ef.Shape = Enum.PartType.Ball; ef.Material = Enum.Material.Neon
                        ef.BrickColor = BrickColor.new("New Yeller")
                        ef.CFrame = ot.CFrame; ef.Parent = workspace
                        local efm = Instance.new("SpecialMesh")
                        efm.MeshType = Enum.MeshType.Sphere; efm.Scale = Vector3.new(1, 1, 1)
                        efm.Parent = ef
                        for i = 1, 100 do
                            if not ef.Parent then break end
                            efm.Scale = efm.Scale + Vector3.new(1, 1, 1)
                            ef.Transparency = ef.Transparency + 0.01
                            task.wait()
                        end
                        if ef.Parent then ef:Destroy() end
                    end)
                    for i = 1, 6 do
                        task.spawn(function()
                            local ring = Instance.new("Part")
                            ring.Size = Vector3.new(1, 1, 1); ring.CanCollide = false; ring.Anchored = true
                            ring.CFrame = ot.CFrame * CFrame.Angles(math.rad(math.random(-4, 4)), math.rad(math.random(-4, 4)), math.rad(math.random(-4, 4)))
                            ring.BrickColor = BrickColor.new("Institutional white")
                            ring.Parent = workspace
                            local rm = Instance.new("SpecialMesh")
                            rm.MeshId = "rbxassetid://3270017"; rm.Scale = Vector3.new(1, 1, 0.1)
                            rm.Parent = ring
                            for j = 1, 100 do
                                if not ring.Parent then break end
                                rm.Scale = rm.Scale + Vector3.new(1, 1, 0)
                                ring.Transparency = ring.Transparency + 0.01
                                task.wait()
                            end
                            if ring.Parent then ring:Destroy() end
