        -- ABILITY 4: TIME STOP (from script: 300-stud AoE anchor for 7s)
        local timeStopCD = 0
        local function timeStop()
            if timeStopCD > 0 then return end
            timeStopCD = 30
            spsnd(1631612542, st, 5, 1.2)
            -- White sphere expand/contract (from script)
            task.spawn(function()
                local ef = Instance.new("Part")
                ef.Size = Vector3.new(1, 1, 1); ef.Material = Enum.Material.Neon
                ef.BrickColor = BrickColor.new("White"); ef.Transparency = 0.4
                ef.CFrame = rp.CFrame; ef.Anchored = true; ef.CanCollide = false
                ef.Shape = Enum.PartType.Ball; ef.Parent = workspace
                local efm = Instance.new("SpecialMesh")
                efm.MeshType = Enum.MeshType.Sphere; efm.Scale = Vector3.new(1, 1, 1)
                efm.Parent = ef
                for i = 1, 70 do
                    if not ef.Parent then break end
                    efm.Scale = efm.Scale + Vector3.new(1, 1, 1)
                    task.wait()
                end
                for i = 1, 70 do
                    if not ef.Parent then break end
                    efm.Scale = efm.Scale - Vector3.new(1, 1, 1)
                    task.wait()
                end
                if ef.Parent then ef:Destroy() end
            end)
            -- Anchor all enemies in 300-stud range for 7s (from script)
            local anchored = {}
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and oh.Health > 0 and (ot.Position - rp.Position).Magnitude < 300 then
                            -- Anchor all parts (from script)
                            for _, p in ipairs(obj:GetChildren()) do
                                if p:IsA("BasePart") then
                                    p.Anchored = true
                                    table.insert(anchored, p)
                                end
                            end
                        end
                    end
                end)
            end
            -- Unanchor after 7s (from script: wait(Time))
            task.delay(7, function()
                for _, p in ipairs(anchored) do
                    if p and p.Parent then
                        pcall(function() p.Anchored = false end)
                    end
                end
            end)
            safeChat(head, "ZA WARUDO! TIME STOP!", Enum.ChatColor.Yellow)
        end
        -- ABILITY 5: JUMP (from script: BodyPosition launch)
        local jumpCD = 0
        local function standJump()
            if jumpCD > 0 then return end
            jumpCD = 4
            -- BodyPosition launch (from script: up 80 + forward 80)
            local bod = Instance.new("BodyPosition")
            bod.MaxForce = Vector3.new(math.huge, math.huge, math.huge)
            bod.Position = (rp.CFrame * CFrame.new(0, 80, -80)).p
            bod.Parent = rp
            Debris:AddItem(bod, 0.2)
            -- Yellow sphere effect (from script)
            task.spawn(function()
                local ef = Instance.new("Part")
                ef.Size = Vector3.new(1, 1, 1); ef.CanCollide = false; ef.Anchored = true
                ef.BrickColor = BrickColor.new("New Yeller"); ef.Material = Enum.Material.Neon
                ef.Shape = Enum.PartType.Ball
                ef.CFrame = st.CFrame * CFrame.new(0, -2.3, 0)
                ef.Parent = workspace
                for i = 1, 30 do
                    if not ef.Parent then break end
                    ef.Size = ef.Size + Vector3.new(0.8, 0.8, 0.8)
                    ef.Transparency = ef.Transparency + 0.07
                    task.wait()
                end
                if ef.Parent then ef:Destroy() end
            end)
        end
        -- AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Intercept threats
                if interceptThreatToPlayer(120, 8, function(t, d)
                    if d < 8 then
                        ohOra(t, rootOf(t.Parent))
                    elseif d > 30 and d < 100 and blastCD <= 0 then
                        local tRoot = rootOf(t.Parent)
                        if tRoot then blast(tRoot.Position) end
                    end
                end) then didSomething = true end
                -- Hunt killers
                local killer, kdist = scanForKillers(300)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist < 8 then
                            -- Cycle: ohOra barrage, strongOra every 5 hits
                            ohOra(killer, rootOf(killer.Parent))
                            if math.random() > 0.7 then
                                strongOra(killer, rootOf(killer.Parent))
                            end
                            didSomething = true
                        elseif kdist < 100 and blastCD <= 0 then
                            blast(tp)
                            didSomething = true
                        elseif kdist > 100 and kdist < 200 and jumpCD <= 0 then
                            standJump()
                            didSomething = true
                        else
                            pathTo(tp)
                            didSomething = true
                        end
                    end
                end
                -- Hunt other enemies
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 200)
                    if enemy then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            if edist < 8 then
                                ohOra(enemy, rootOf(enemy.Parent))
                                if math.random() > 0.7 then
                                    strongOra(enemy, rootOf(enemy.Parent))
                                end
                                didSomething = true
                            elseif edist < 100 and blastCD <= 0 then
                                blast(tp)
                                didSomething = true
                            elseif edist > 100 and edist < 200 and jumpCD <= 0 then
                                standJump()
                                didSomething = true
                            else
                                pathTo(tp)
                                didSomething = true
                            end
                        end
                    end
                end
                -- Time stop: rare trigger when multiple enemies near
                if timeStopCD <= 0 and math.random() > 0.95 then
                    local nearCount = 0
                    for _, obj in ipairs(workspace:GetDescendants()) do
                        pcall(function()
                            if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                                local ot = rootOf(obj)
                                if ot and (ot.Position - rp.Position).Magnitude < 100 then
                                    nearCount = nearCount + 1
                                end
                            end
                        end)
                    end
                    if nearCount >= 2 then
                        task.spawn(timeStop)
                    end
                end
                -- Idle
                if not didSomething then
                    returnToPlayer(45)
                    if math.random() > 0.92 then
                        safeChat(head, "ORA ORA ORA!", Enum.ChatColor.Yellow)
                    end
                end
                if ohOraCD > 0 then ohOraCD = ohOraCD - 1 end
                if strongOraCD > 0 then strongOraCD = strongOraCD - 1 end
                if blastCD > 0 then blastCD = blastCD - 1 end
                if timeStopCD > 0 then timeStopCD = timeStopCD - 1 end
                if jumpCD > 0 then jumpCD = jumpCD - 1 end
                task.wait(0.6)
            end
        end)


