        mailDecal.Face = Enum.NormalId.Top; mailDecal.Texture = "rbxassetid://8052441"
        mailDecal.Parent = mailTemplate
        -- SHOOT MAIL (from script: ShootMail function)
        local function shootMail(part, strength, debris)
            local mail = mailTemplate:Clone()
            mail.CFrame = part.CFrame; mail.Parent = effectsFolder
            Debris:AddItem(mail, debris or 2)
            local bv = Instance.new("BodyVelocity")
            bv.MaxForce = Vector3.new(1e9, 1e9, 1e9)
            bv.Velocity = part.CFrame.lookVector * strength
            bv.Name = "DASH"; bv.Parent = mail
            mail.Touched:Connect(function(hit)
                if hit.Parent ~= model and not isNoobTeam(hit.Parent) and hit.Name ~= "Mail" then
                    local oh = humanoidOf(hit.Parent)
                    if oh and oh.Health > 0 then
                        oh:TakeDamage(math.random(15, 45))
                    end
                end
            end)
            return mail
        end
        -- Magic sphere effect (from script: black neon sphere)
        local function magicSphere(cframe)
            task.spawn(function()
                local p = Instance.new("Part")
                p.Material = Enum.Material.Neon; p.BrickColor = BrickColor.new("Really black")
                p.Size = Vector3.new(1, 1, 1); p.Transparency = 0
                p.Anchored = true; p.CanCollide = false
                p.CFrame = cframe; p.Parent = effectsFolder
                local m = Instance.new("SpecialMesh")
                m.MeshType = Enum.MeshType.Sphere; m.Scale = Vector3.new(0.5, 0.5, 0.5)
                m.Parent = p
                for i = 1, 25 do
                    if not p.Parent then break end
                    m.Scale = m.Scale - Vector3.new(0.02, 0.02, 0.02)
                    p.Transparency = p.Transparency + 0.04
                    task.wait()
                end
                if p.Parent then p:Destroy() end
            end)
        end
        -- ABILITY 1: MAILMAN'S WRATH (from script: 3-phase spiral)
        local wrathCD = 0
        local function mailmansWrath()
            local twist = 0
            local twist2 = false
            local spinpart = Instance.new("Part")
            spinpart.Anchored = true; spinpart.CanCollide = false; spinpart.Transparency = 1
            spinpart.CFrame = opening.CFrame; spinpart.Parent = weaponMo
            local spinpart2 = spinpart:Clone(); spinpart2.Parent = weaponMo
            -- Phase 1: 30 mails, 0.1 rad/spin (from script)
            for i = 1, 30 do
                if not isAlive(h) then break end
                pcall(function() chuck:Play() end)
                magicSphere(opening.CFrame)
                twist = twist + 1
                spinpart.CFrame = spinpart.CFrame * CFrame.Angles(0, 0.1, 0)
                spinpart2.CFrame = spinpart2.CFrame * CFrame.Angles(0, -0.1, 0)
                if twist == 10 then
                    spinpart.CFrame = opening.CFrame; spinpart2.CFrame = opening.CFrame; twist = 0
                end
                shootMail(spinpart, 65, 2); shootMail(spinpart2, 65, 2)
                task.wait(0.1)
            end
            -- Phase 2: 40 mails, alternating direction (from script)
            spinpart.CFrame = opening.CFrame; spinpart2.CFrame = opening.CFrame; twist = 10
            for i = 1, 40 do
                if not isAlive(h) then break end
                pcall(function() chuck:Play() end)
                magicSphere(opening.CFrame)
                twist = twist + 1
                if twist2 then
                    spinpart.CFrame = spinpart.CFrame * CFrame.Angles(0, 0.2, 0)
                    spinpart2.CFrame = spinpart2.CFrame * CFrame.Angles(0, 0.1, 0)
                else
                    spinpart.CFrame = spinpart.CFrame * CFrame.Angles(0, -0.2, 0)
                    spinpart2.CFrame = spinpart2.CFrame * CFrame.Angles(0, -0.1, 0)
                end
                if twist == 20 then twist2 = not twist2; twist = 0 end
                shootMail(spinpart, 65, 2); shootMail(spinpart2, 65, 2)
                task.wait(0.1)
            end
            -- Phase 3: 30 mails, 0.15 rad/spin, 75 speed (from script)
            spinpart.CFrame = opening.CFrame; spinpart2.CFrame = opening.CFrame; twist = 0
            for i = 1, 30 do
                if not isAlive(h) then break end
                pcall(function() chuck:Play() end)
                magicSphere(opening.CFrame)
                twist = twist + 1
                spinpart.CFrame = spinpart.CFrame * CFrame.Angles(0, 0.15, 0)
                spinpart2.CFrame = spinpart2.CFrame * CFrame.Angles(0, -0.15, 0)
                if twist == 10 then
                    spinpart.CFrame = opening.CFrame; spinpart2.CFrame = opening.CFrame; twist = 0
                end
                shootMail(spinpart, 75, 2); shootMail(spinpart2, 75, 2)
                task.wait(0.1)
            end
            spinpart:Destroy(); spinpart2:Destroy()
        end
        -- ABILITY 2: PAPERCUT CHAOS (from script: forward mail + side spirals)
        local papercutCD = 0
        local function papercutChaos()
            local twist = 0
            -- 5 forward mails with 15 side spirals each (from script)
            for i = 1, 5 do
                if not isAlive(h) then break end
                pcall(function() chuck:Play() end)
                magicSphere(opening.CFrame)
                local mail = shootMail(opening, 25, 20)
                for j = 1, 15 do
                    if not isAlive(h) then break end
                    pcall(function() chuck:Play() end)
                    local sp1 = Instance.new("Part")
                    sp1.Anchored = true; sp1.CanCollide = false; sp1.Transparency = 1
                    sp1.CFrame = mail.CFrame * CFrame.Angles(0, math.rad(70), 0)
                    sp1.Parent = weaponMo
                    local sp2 = sp1:Clone()
                    sp2.CFrame = mail.CFrame * CFrame.Angles(0, math.rad(-70), 0)
                    sp2.Parent = weaponMo
                    magicSphere(mail.CFrame)
                    shootMail(sp1, 35, 2); shootMail(sp2, 35, 2)
                    sp1:Destroy(); sp2:Destroy()
                    task.wait(0.1)
                end
                mail:Destroy()
            end
            -- 2 forward mails with 20 escalating spirals (from script)
            for i = 1, 2 do
                if not isAlive(h) then break end
                pcall(function() chuck:Play() end)
                magicSphere(opening.CFrame)
                local mail = shootMail(opening, 45, 20)
                for j = 1, 20 do
                    if not isAlive(h) then break end
                    twist = twist + 1
                    pcall(function() chuck:Play() end)
                    local sp1 = Instance.new("Part")
                    sp1.Anchored = true; sp1.CanCollide = false; sp1.Transparency = 1
                    sp1.CFrame = mail.CFrame * CFrame.Angles(0, math.rad(twist), 0)
                    sp1.Parent = weaponMo
                    local sp2 = sp1:Clone()
                    sp2.CFrame = mail.CFrame * CFrame.Angles(0, math.rad(-twist), 0)
                    sp2.Parent = weaponMo
                    magicSphere(mail.CFrame)
                    shootMail(sp1, 35, 2); shootMail(sp2, 35, 2)
                    sp1:Destroy(); sp2:Destroy()
                    task.wait(0.1)
                end
                twist = 0; mail:Destroy()
            end
