        -- ABILITY 5: CARD MADNESS (from script: ultimate combo)
        local cardMadnessCD = 0
        local function cardMadness()
            safeChat(head, "SPELL CARD! CARD MADNESS!", Enum.ChatColor.Red)
            task.wait(1)
            safeChat(head, "THEN DIE!", Enum.ChatColor.Red)
            task.wait(1)
            safeChat(head, "ULTIMATE CARD MADNESS ATTACK!", Enum.ChatColor.Red)
            task.wait(1)
            -- Chain all abilities (from script)
            mailboxMadness()
            mailmansWrath()
            finalInbox()
            mailboxMadness()
            mailmansWrath()
        end
        -- AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Intercept threats
                if interceptThreatToPlayer(120, 8, function(t, d)
                    if d < 80 and wrathCD <= 0 then
                        wrathCD = 15
                        safeChat(head, "Spell card! Mailman's Wrath!", Enum.ChatColor.White)
                        task.spawn(mailmansWrath)
                    end
                end) then didSomething = true end
                -- Hunt killers
                local killer, kdist = scanForKillers(300)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist < 100 and wrathCD <= 0 then
                            wrathCD = 15
                            safeChat(head, "Spell card! Mailman's Wrath!", Enum.ChatColor.White)
                            task.spawn(mailmansWrath)
                            didSomething = true
                        elseif kdist < 150 and papercutCD <= 0 then
                            papercutCD = 20
                            safeChat(head, "Spell card! Papercut Chaos!", Enum.ChatColor.White)
                            task.spawn(papercutChaos)
                            didSomething = true
                        elseif kdist < 200 and madnessCD <= 0 then
                            madnessCD = 25
                            safeChat(head, "Spell card! Mailbox Madness!", Enum.ChatColor.White)
                            task.spawn(mailboxMadness)
                            didSomething = true
                        elseif kdist < 250 and finalInboxCD <= 0 then
                            finalInboxCD = 40
                            -- Switch to Final Inbox music (from script)
                            pcall(function()
                                sick.SoundId = "rbxassetid://195916147"
                                sick.Volume = 3; sick:Play()
                            end)
                            safeChat(head, "SPELL CARD! FINAL INBOX!", Enum.ChatColor.White)
                            task.wait(1)
                            safeChat(head, "DIE!", Enum.ChatColor.Red)
                            task.spawn(finalInbox)
                            -- Switch back to normal music after
                            task.delay(30, function()
                                pcall(function()
                                    sick.SoundId = "rbxassetid://596220347"
                                    sick.Volume = 0.6; sick:Play()
                                end)
                            end)
                            didSomething = true
                        else
                            pathTo(tp)
                            didSomething = true
                        end
                    end
                end
                -- Hunt other enemies
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 200)
                    if enemy then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            if edist < 100 and wrathCD <= 0 then
                                wrathCD = 15
                                safeChat(head, "Spell card! Mailman's Wrath!", Enum.ChatColor.White)
                                task.spawn(mailmansWrath)
                                didSomething = true
                            elseif edist < 150 and papercutCD <= 0 then
                                papercutCD = 20
                                safeChat(head, "Spell card! Papercut Chaos!", Enum.ChatColor.White)
                                task.spawn(papercutChaos)
                                didSomething = true
                            elseif edist < 200 and madnessCD <= 0 then
                                madnessCD = 25
                                safeChat(head, "Spell card! Mailbox Madness!", Enum.ChatColor.White)
                                task.spawn(mailboxMadness)
                                didSomething = true
                            else
                                pathTo(tp)
                                didSomething = true
                            end
                        end
                    end
                end
                -- Card Madness: rare ultimate when low health (but HP = inf, so use timer)
                if cardMadnessCD <= 0 and math.random() > 0.98 then
                    cardMadnessCD = 120
                    task.spawn(cardMadness)
                end
                -- Idle
                if not didSomething then
                    returnToPlayer(45)
                    if math.random() > 0.92 then
                        safeChat(head, "You've got mail!", Enum.ChatColor.White)
                    end
                end
                if wrathCD > 0 then wrathCD = wrathCD - 1 end
                if papercutCD > 0 then papercutCD = papercutCD - 1 end
                if madnessCD > 0 then madnessCD = madnessCD - 1 end
                if finalInboxCD > 0 then finalInboxCD = finalInboxCD - 1 end
                if cardMadnessCD > 0 then cardMadnessCD = cardMadnessCD - 1 end
                task.wait(0.8)
            end
            pcall(function() sick:Stop() sick:Destroy() end)
        end)


