        -- Sound helper
        local function psnd(id, parent, vol, pitch)
            pcall(function()
                local s = Instance.new("Sound")
                s.SoundId = "rbxassetid://"..tostring(id)
                s.Volume = vol or 1; s.PlaybackSpeed = pitch or 1
                s.Parent = parent or torso; s:Play()
                Debris:AddItem(s, 10)
            end)
        end
        -- AoE damage (from script's ApplyAoE)
        local function applyAoE(pos, range, minDmg, maxDmg, fling)
            for _, obj in ipairs(workspace:GetDescendants()) do
                pcall(function()
                    if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                        local oh = humanoidOf(obj); local ot = rootOf(obj)
                        if oh and ot and oh.Health > 0 and (ot.Position - pos).Magnitude <= range then
                            oh:TakeDamage(math.random(minDmg, maxDmg))
                            if fling > 0 and not ot.Anchored then
                                local bv = Instance.new("BodyVelocity")
                                bv.MaxForce = Vector3.new(1e9, 1e9, 1e9)
                                bv.Velocity = CFrame.new(pos, ot.Position).lookVector * fling
                                bv.Parent = ot; Debris:AddItem(bv, 0.05)
                            end
                        end
                    end
                end)
            end
        end
        -- Effect: WACKYEFFECT (from script)
        local function wackyEffect(effectType, size, endSize, cframe, color, time, soundId)
            task.spawn(function()
                local p = Instance.new("Part")
                p.Material = Enum.Material.Neon; p.BrickColor = BrickColor.new("Pearl")
                p.Size = Vector3.new(1, 1, 1); p.Transparency = 0
                p.Anchored = true; p.CanCollide = false
                p.CFrame = cframe; p.Color = color; p.Parent = workspace
                local m
                if effectType == "Sphere" then
                    m = Instance.new("SpecialMesh"); m.MeshType = Enum.MeshType.Sphere
                    m.Scale = size; m.Parent = p
                elseif effectType == "Block" then
                    m = Instance.new("BlockMesh"); m.Scale = Vector3.new(size.X, size.X, size.X)
                    m.Parent = p
                    p.CFrame = cframe * CFrame.Angles(math.rad(math.random(0, 360)), math.rad(math.random(0, 360)), math.rad(math.random(0, 360)))
                elseif effectType == "Wave" then
                    m = Instance.new("SpecialMesh"); m.MeshType = Enum.MeshType.FileMesh
                    m.MeshId = "rbxassetid://20329976"; m.Scale = size
                    m.Offset = Vector3.new(0, 0, -size.X/8); m.Parent = p
                elseif effectType == "Ring" then
                    m = Instance.new("SpecialMesh"); m.MeshType = Enum.MeshType.FileMesh
                    m.MeshId = "rbxassetid://559831844"
                    m.Scale = Vector3.new(size.X, size.X, 0.1); m.Parent = p
                elseif effectType == "Swirl" then
                    m = Instance.new("SpecialMesh"); m.MeshType = Enum.MeshType.FileMesh
                    m.MeshId = "rbxassetid://1051557"; m.Scale = size; m.Parent = p
                elseif effectType == "Crystal" then
                    m = Instance.new("SpecialMesh"); m.MeshType = Enum.MeshType.FileMesh
                    m.MeshId = "rbxassetid://9756362"; m.Scale = size; m.Parent = p
                end
                if soundId then psnd(soundId, p, 2, 1) end
                local growth = size - endSize
                for i = 1, (time or 25) do
                    if not p.Parent then break end
                    if m then m.Scale = m.Scale - growth / (time or 25) end
                    if effectType == "Wave" and m then m.Offset = Vector3.new(0, 0, -m.Scale.X/8) end
                    p.Transparency = p.Transparency + (1 / (time or 25))
                    if effectType ~= "Block" then
                        p.CFrame = p.CFrame * CFrame.Angles(0, math.rad(5), 0)
                    end
                    task.wait()
                end
                if p.Parent then p:Destroy() end
            end)
        end
