                        -- Crystal rise effect (from script)
                        wackyEffect("Crystal", Vector3.new(1, 0, 1), Vector3.new(0, 100, 0), CFrame.new(pos.Position), SKILLTEXTCOLOR, 25, 743521450)
                        -- Create mummy (simplified from script: use a basic NPC)
                        task.wait(1)
                        -- Spawn a simple mummy minion
                        local mummyOk, mummyModel = pcall(function()
                            local d = Players:GetHumanoidDescriptionFromUserId(1)
                            local m = Players:CreateHumanoidModelFromDescription(d, Enum.HumanoidRigType.R6)
                            m.Name = "Mummy_"..math.random(1000, 9999)
                            m.Parent = workspace
                            -- Make it look like a mummy (dark color)
                            for _, p in ipairs(m:GetChildren()) do
                                if p:IsA("BasePart") then
                                    p.BrickColor = BrickColor.new("Dark orange")
                                    p.Material = Enum.Material.Neon
                                end
                            end
                            local mh = humanoidOf(m)
                            local mr = rootOf(m)
                            if mh and mr then
                                mh.MaxHealth = math.random(20, 65); mh.Health = mh.MaxHealth
                                mh.WalkSpeed = 12
                                mr.CFrame = CFrame.new(hitPos)
                            end
                            -- Tag as noob team so it doesn't get targeted
                            local tag = Instance.new("BoolValue")
                            tag.Name = "IsNoobTeam"; tag.Value = true; tag.Parent = m
                            return m
                        end)
                        if mummyOk and mummyModel then
                            -- Mummy AI (from script: hunt nearest enemy, 5-25 dmg melee)
                            task.spawn(function()
                                local mh = humanoidOf(mummyModel)
                                local mr = rootOf(mummyModel)
                                if not mh or not mr then return end
                                -- Death sound (from script)
                                mh.Died:Connect(function()
                                    psnd(1158091961, mr, 3, 0.5)
                                end)
                                for i = 1, 60 do
                                    if mh.Health <= 0 or not mr.Parent then break end
                                    -- Find nearest enemy
                                    local nearest, ndist
                                    for _, obj in ipairs(workspace:GetDescendants()) do
                                        pcall(function()
                                            if obj:IsA("Model") and obj ~= model and obj ~= mummyModel and not isNoobTeam(obj) then
                                                local oh = humanoidOf(obj); local ot = rootOf(obj)
                                                if oh and oh.Health > 0 and ot then
                                                    local d = (ot.Position - mr.Position).Magnitude
                                                    if not ndist or d < ndist then nearest = ot; ndist = d end
                                                end
                                            end
                                        end)
                                    end
                                    if nearest and ndist then
                                        mh:MoveTo(nearest.Position)
                                        if ndist < 5 then
                                            psnd(1158091961, mr, 1, 1)
                                            applyAoE(mr.CFrame * CFrame.new(0, 0, -1.2).p, 3, 5, 25, 3)
                                        end
                                    end
                                    task.wait(1)
                                end
                                if mummyModel and mummyModel.Parent then
                                    mummyModel:BreakJoints()
                                    Debris:AddItem(mummyModel, 4)
                                end
                            end)
                        end
                    end
                end)
                task.wait(0.3)
            end
        end
        -- ABILITY 2: WARP (from script: swirl fade teleport)
        local warpCD = 0
        local function warp(targetPos)
            local playPos = rp.Position
            -- Fade out (from script: 10-frame swirl + transparency)
            for i = 1, 10 do
                wackyEffect("Swirl", Vector3.new(25, 25, 25), Vector3.new(0, 0, 0), CFrame.new(torso.Position), SKILLTEXTCOLOR, 25, 743521450)
                task.wait(0.1)
            end
            psnd(743521450, torso, 5, 0.5)
            rp.CFrame = CFrame.new(targetPos + Vector3.new(0, 15, 0), playPos)
            -- Fade in (from script)
            for i = 1, 10 do
                wackyEffect("Swirl", Vector3.new(0, 0, 0), Vector3.new(25, 25, 25), CFrame.new(torso.Position), SKILLTEXTCOLOR, 25)
                task.wait(0.04)
            end
        end
        -- ABILITY 3: PHEONIX GLARE (from script: phoenix + AoE burn)
        local pheonixCD = 0
        local function pheonixGlare()
            local SIZE = 2
            -- Build phoenix (from script: mesh 90615474 body + 90615661/90615581 wings)
            local phxMo = Instance.new("Model")
            phxMo.Name = "PHEONIX"
            phxMo.Parent = weaponMo
            local body = Instance.new("Part")
            body.Material = Enum.Material.Neon; body.BrickColor = BrickColor.new("Deep orange")
            body.Color = FIRECOLOR; body.Size = Vector3.new(0, 0, 0)
            body.CanCollide = false; body.Parent = phxMo
            local bm = Instance.new("SpecialMesh")
            bm.MeshId = "rbxassetid://90615474"; bm.Scale = Vector3.new(1.5, 1.5, 1.5) * SIZE
            bm.Parent = body
            local bw = Instance.new("Weld")
            bw.Part0 = rp; bw.Part1 = body
            bw.C0 = CFrame.new(0, 4*SIZE, 3*SIZE); bw.Parent = body
            local rwing = Instance.new("Part")
            rwing.Material = Enum.Material.Neon; rwing.BrickColor = BrickColor.new("Deep orange")
            rwing.Color = FIRECOLOR; rwing.Size = Vector3.new(0, 0, 0)
            rwing.CanCollide = false; rwing.Parent = phxMo
            local rwm = Instance.new("SpecialMesh")
            rwm.MeshId = "rbxassetid://90615661"; rwm.Scale = Vector3.new(1.5, 1.5, 1.5) * SIZE
            rwm.Parent = rwing
            local rww = Instance.new("Weld")
            rww.Part0 = body; rww.Part1 = rwing
            rww.C0 = CFrame.new(2*SIZE, 2*SIZE, 0.75*SIZE); rww.Parent = rwing
            local lwing = Instance.new("Part")
            lwing.Material = Enum.Material.Neon; lwing.BrickColor = BrickColor.new("Deep orange")
            lwing.Color = FIRECOLOR; lwing.Size = Vector3.new(0, 0, 0)
            lwing.CanCollide = false; lwing.Parent = phxMo
            local lwm = Instance.new("SpecialMesh")
            lwm.MeshId = "rbxassetid://90615581"; lwm.Scale = Vector3.new(1.5, 1.5, 1.5) * SIZE
            lwm.Parent = lwing
            local lww = Instance.new("Weld")
            lww.Part0 = body; lww.Part1 = lwing
            lww.C0 = CFrame.new(-2*SIZE, 2*SIZE, 0.75*SIZE); lww.Parent = lwing
            -- Wing flap animation (from script: 20 + 65 frames lerp)
            task.spawn(function()
                for i = 1, 20 do
                    if not isAlive(h) then break end
                    rww.C0 = rww.C0:lerp(CFrame.new(2*(SIZE/2), 3*(SIZE/2), 0.75*SIZE) * CFrame.Angles(math.rad(-25), math.rad(65), 0), 0.1)
                    lww.C0 = lww.C0:lerp(CFrame.new(-2*(SIZE/2), 3*(SIZE/2), 0.75*SIZE) * CFrame.Angles(math.rad(-25), math.rad(-65), 0), 0.1)
                    task.wait()
                end
                for i = 1, 65 do
                    if not isAlive(h) then break end
                    rww.C0 = rww.C0:lerp(CFrame.new(2*(SIZE/2), 3*(SIZE/2), 0.75*SIZE) * CFrame.Angles(math.rad(25), math.rad(65), 0), 0.1)
                    lww.C0 = lww.C0:lerp(CFrame.new(-2*(SIZE/2), 3*(SIZE/2), 0.75*SIZE) * CFrame.Angles(math.rad(25), math.rad(-65), 0), 0.1)
                    task.wait()
                end
            end)
            task.wait(2)
            -- Blast (from script: 5 sphere effects + AoE)
            for i = 1, 5 do
                wackyEffect("Sphere", Vector3.new(0, 0, 0), Vector3.new(35, 35, 35) * (SIZE/2), CFrame.new(body.Position) * CFrame.Angles(math.rad(math.random(0, 360)), math.rad(math.random(0, 360)), math.rad(math.random(0, 360))) * CFrame.new(0, 0, 35*(SIZE/2)), Color3.new(0.1, 0.1, 0.1), 25)
                wackyEffect("Sphere", Vector3.new(0, 0, 0), Vector3.new(45, 45, 45) * (SIZE/2), CFrame.new(body.Position) * CFrame.Angles(math.rad(math.random(0, 360)), math.rad(math.random(0, 360)), math.rad(math.random(0, 360))) * CFrame.new(0, 0, 35*(SIZE/2)), FIRECOLOR, 25)
            end
            wackyEffect("Sphere", Vector3.new(0, 0, 0), Vector3.new(200, 200, 200) * (SIZE/2), CFrame.new(body.Position), FIRECOLOR, 25, 462676772)
            applyAoE(body.Position, 50 * (SIZE/2), 0, 0, 130)
            -- Burn enemies over time (from script: 150 ticks, 0.5 dmg)
            task.spawn(function()
                local burning = {}
                for _, obj in ipairs(workspace:GetDescendants()) do
                    pcall(function()
                        if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                            local oh = humanoidOf(obj); local ot = rootOf(obj)
                            if oh and ot and oh.Health > 0 and (ot.Position - body.Position).Magnitude < 50 * (SIZE/2) then
                                table.insert(burning, obj)
                            end
                        end
                    end)
                end
                for i = 1, 100 do
                    for _, obj in ipairs(burning) do
                        pcall(function()
                            local oh = humanoidOf(obj)
                            if oh and oh.Health > 0 then
                                oh.Health = oh.Health - 0.5
                            end
                        end)
                    end
                    task.wait()
                end
            end)
            -- Fade phoenix (from script)
            task.spawn(function()
                for i = 1, 50 do
                    if not body.Parent then break end
                    body.Transparency = body.Transparency + 0.5/50
                    rwing.Transparency = body.Transparency
                    lwing.Transparency = body.Transparency
                    task.wait()
                end
                if phxMo.Parent then phxMo:Destroy() end
            end)
        end
        -- ABILITY 4: SHADE ZONE (from script: expanding black cylinder)
        local shadeCD = 0
        local function shadeZone()
            local hit, hitPos = workspace:FindPartOnRay(Ray.new(rp.Position, Vector3.new(0, -1, 0)), model, 15)
            if not hit then return end
            task.spawn(function()
                -- Zone cylinder (from script)
                local zone = Instance.new("Part")
                zone.Material = Enum.Material.Neon; zone.Color = Color3.new(0, 0, 0)
                zone.Size = Vector3.new(45, 0, 45); zone.Transparency = 1
                zone.Anchored = true; zone.CanCollide = false
                zone.CFrame = CFrame.new(hitPos); zone.Parent = workspace
                local zm = Instance.new("CylinderMesh"); zm.Parent = zone
                psnd(1393698948, zone, 5, 0.5)
                -- Expand (from script: 45 frames)
                for i = 1, 45 do
                    if not zone.Parent then break end
                    zone.Transparency = zone.Transparency - 1/45
                    zone.Size = zone.Size + Vector3.new(2, 0, 2)
                    task.wait()
                end
                local baseSize = zone.Size
                -- Active phase (from script: 400 frames, damage + sphere effects)
                for i = 1, 200 do
                    if not zone.Parent or not isAlive(h) then break end
                    -- Random sphere effects (from script)
                    if math.random(1, 5) == 1 then
                        wackyEffect("Sphere", Vector3.new(5, 0, 5), Vector3.new(0, 135, 0), CFrame.new(zone.Position) * CFrame.Angles(0, math.rad(math.random(0, 360)), 0) * CFrame.new(0, 0, math.random(0, math.ceil(zone.Size.X/2.1))), Color3.new(0, 0, 0), 25)
                    end
                    zone.Size = baseSize + Vector3.new(2 * math.cos(i / 12), 0, 2 * math.cos(i / 12))
                    -- Damage + anchor enemies in zone (from script)
                    for _, obj in ipairs(workspace:GetDescendants()) do
                        pcall(function()
                            if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                                local oh = humanoidOf(obj); local ot = rootOf(obj)
                                if oh and ot and oh.Health > 0 and (ot.Position - zone.Position).Magnitude < zone.Size.X/2 then
                                    if not ot.Anchored then
                                        ot.Anchored = true
                                        task.delay(3, function()
                                            if ot and ot.Parent then ot.Anchored = false end
                                        end)
                                    end
                                    oh.Health = oh.Health - 1.5
                                end
                            end
                        end)
                    end
                    task.wait()
                end
                -- Shrink (from script: 45 frames)
                for i = 1, 45 do
                    if not zone.Parent then break end
                    zone.Transparency = zone.Transparency + 1/45
                    zone.Size = zone.Size - Vector3.new(2, 0, 2)
                    task.wait()
                end
                if zone.Parent then zone:Destroy() end
            end)
        end
        -- ABILITY 5: PHARAOH'S THRONE (from script: build pyramid)
        local throneCD = 0
        local function pharaohsThrone()
            local hit, hitPos = workspace:FindPartOnRay(Ray.new(rp.Position, Vector3.new(0, -1, 0)), model, 4)
            if not hit then return end
            task.spawn(function()
                -- Build pyramid model (from script)
                local pyr = Instance.new("Model")
                pyr.Name = "Pyramid"
                pyr.Parent = weaponMo
                -- Base (from script: 100x1x100 Wheat)
                local base = Instance.new("Part")
                base.Material = Enum.Material.Concrete; base.BrickColor = BrickColor.new("Wheat")
                base.Size = Vector3.new(100, 1, 100); base.Anchored = true; base.CanCollide = false
                base.CFrame = CFrame.new(hitPos); base.Parent = pyr
                pyr.PrimaryPart = base
                -- 4 corner pillars with fire (from script)
                for _, offset in ipairs({Vector3.new(25, 25, 25), Vector3.new(-25, 25, 25), Vector3.new(25, 25, -25), Vector3.new(-25, 25, -25)}) do
                    local pillar = Instance.new("Part")
                    pillar.Material = Enum.Material.Concrete; pillar.BrickColor = BrickColor.new("Wheat")
                    pillar.Size = Vector3.new(5, 25, 5); pillar.Anchored = true; pillar.CanCollide = false
                    pillar.CFrame = base.CFrame * CFrame.new(offset.X, offset.Y, offset.Z)
                    pillar.Parent = pyr
                    local pm = Instance.new("CylinderMesh"); pm.Parent = pillar
                    -- Pillar top (from script)
                    local ptop = Instance.new("Part")
                    ptop.Material = Enum.Material.Concrete; ptop.BrickColor = BrickColor.new("Wheat")
                    ptop.Size = Vector3.new(6, 4, 6); ptop.Anchored = true; ptop.CanCollide = false
                    ptop.CFrame = pillar.CFrame * CFrame.new(0, 12.5, 0); ptop.Parent = pyr
                    local ptm = Instance.new("CylinderMesh"); ptm.Parent = ptop
                    -- Coal + fire (from script)
                    local coal = Instance.new("Part")
                    coal.Material = Enum.Material.Pebble; coal.BrickColor = BrickColor.new("Black")
                    coal.Size = Vector3.new(2, 2, 2); coal.Anchored = true; coal.CanCollide = false
                    coal.CFrame = ptop.CFrame * CFrame.new(0, ptop.Size.Y/2, 0); coal.Parent = pyr
                    local fire = Instance.new("ParticleEmitter")
                    fire.Texture = "rbxassetid://1460745664"; fire.Color = ColorSequence.new(FIRECOLOR)
                    fire.Size = NumberSequence.new(2, 0); fire.Lifetime = NumberRange.new(1, 2)
                    fire.Speed = NumberRange.new(3); fire.Rate = 45; fire.Enabled = true
                    fire.Acceleration = Vector3.new(0, 15, 0); fire.Parent = coal
                end
                -- 35 stacked layers (from script: decreasing size)
                local lastPart = base
                for i = 1, 35 do
                    local layer = Instance.new("Part")
                    layer.Material = Enum.Material.Concrete; layer.BrickColor = BrickColor.new("Wheat")
                    layer.Size = Vector3.new(100 - i*2, 1, 100 - i*2)
                    layer.Anchored = true; layer.CanCollide = false
                    layer.CFrame = base.CFrame * CFrame.new(0, i, 0); layer.Parent = pyr
                    lastPart = layer
                end
                -- Throne seat (from script)
                local chair = Instance.new("Part")
                chair.Material = Enum.Material.Concrete; chair.BrickColor = BrickColor.new("Dark stone grey")
                chair.Size = Vector3.new(7, 1, 7); chair.Anchored = true; chair.CanCollide = false
                chair.CFrame = base.CFrame * CFrame.new(0, 36, 0); chair.Parent = pyr
                -- Start underground (from script: SetPrimaryPartCFrame -50 Y)
                pyr:SetPrimaryPartCFrame(CFrame.new(hitPos - Vector3.new(0, 50, 0)))
                psnd(130972023, base, 10, 0.8)
                -- Rise up (from script: 46*4 frames)
                for i = 1, 46*4 do
                    if not pyr.Parent or not isAlive(h) then break end
                    pyr:SetPrimaryPartCFrame(base.CFrame * CFrame.new(0, 0.25, 0))
                    task.wait()
                end
                -- Enable collision (from script)
                for _, c in pairs(pyr:GetChildren()) do
                    if c:IsA("BasePart") then c.CanCollide = true end
                end
                -- Auto-sink after 30s (from script)
                task.delay(30, function()
                    if pyr and pyr.Parent then
                        for i = 1, 46*4 do
                            if not pyr.Parent then break end
                            pyr:SetPrimaryPartCFrame(base.CFrame * CFrame.new(0, -0.25, 0))
                            task.wait()
                        end
                        if pyr.Parent then pyr:Destroy() end
                    end
                end)
            end)
        end
        -- AI loop
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local didSomething = false
                -- Intercept threats
                if interceptThreatToPlayer(100, 8, function(t, d)
                    if d < 8 then
                        t:TakeDamage(20)
                    end
                end) then didSomething = true end
                -- Hunt killers
                local killer, kdist = scanForKillers(300)
                if killer then
                    local tp = posOf(killer.Parent)
                    if tp then
                        if kdist < 8 then
                            killer:TakeDamage(20)
                            didSomething = true
                        elseif kdist < 60 and pheonixCD <= 0 then
                            pheonixCD = 25
                            safeChat(head, "Pheonix Glare!", Enum.ChatColor.White)
                            task.spawn(pheonixGlare)
                            didSomething = true
                        elseif kdist < 100 and summonCD <= 0 then
                            summonCD = 15
                            safeChat(head, "Summon!", Enum.ChatColor.White)
                            task.spawn(summon)
                            didSomething = true
                        elseif kdist < 150 and warpCD <= 0 then
                            warpCD = 10
                            task.spawn(warp, tp)
                            didSomething = true
                        else
                            pathTo(tp)
                            didSomething = true
                        end
                    end
                end
                -- Hunt other enemies
                if not didSomething then
                    local enemy, edist = findNearest(rp.Position, model, 200)
                    if enemy then
                        local tp = posOf(enemy.Parent)
                        if tp then
                            if edist < 8 then
                                enemy:TakeDamage(20)
                                didSomething = true
                            elseif edist < 60 and pheonixCD <= 0 then
                                pheonixCD = 25
                                safeChat(head, "Pheonix Glare!", Enum.ChatColor.White)
                                task.spawn(pheonixGlare)
                                didSomething = true
                            elseif edist < 100 and summonCD <= 0 then
                                summonCD = 15
                                safeChat(head, "Summon!", Enum.ChatColor.White)
                                task.spawn(summon)
                                didSomething = true
                            elseif edist < 150 and warpCD <= 0 then
                                warpCD = 10
                                task.spawn(warp, tp)
                                didSomething = true
                            else
                                pathTo(tp)
                                didSomething = true
                            end
                        end
                    end
                end
                -- Shade Zone: when 3+ enemies near
                if shadeCD <= 0 and math.random() > 0.9 then
                    local nearCount = 0
                    for _, obj in ipairs(workspace:GetDescendants()) do
                        pcall(function()
                            if obj:IsA("Model") and obj ~= model and not isNoobTeam(obj) then
                                local ot = rootOf(obj)
                                if ot and (ot.Position - rp.Position).Magnitude < 50 then
                                    nearCount = nearCount + 1
                                end
                            end
                        end)
                    end
                    if nearCount >= 3 then
                        shadeCD = 30
                        safeChat(head, "Shade Zone!", Enum.ChatColor.White)
                        task.spawn(shadeZone)
                    end
                end
                -- Pharaoh's Throne: rare
                if throneCD <= 0 and math.random() > 0.97 then
                    throneCD = 60
                    safeChat(head, "Pharaoh's Throne!", Enum.ChatColor.White)
                    task.spawn(pharaohsThrone)
                end
                -- Idle
                if not didSomething then
                    returnToPlayer(45)
                    if math.random() > 0.92 then
                        safeChat(head, "Bow before the Pharaoh.", Enum.ChatColor.White)
                    end
                end
                if summonCD > 0 then summonCD = summonCD - 1 end
                if warpCD > 0 then warpCD = warpCD - 1 end
                if pheonixCD > 0 then pheonixCD = pheonixCD - 1 end
                if shadeCD > 0 then shadeCD = shadeCD - 1 end
                if throneCD > 0 then throneCD = throneCD - 1 end
                task.wait(0.8)
            end
            pcall(function() sick:Stop() sick:Destroy() end)
        end)

    -- ── DEFAULT catch-all ────────────────────────────────────


















    else
        task.spawn(function()
            while isAlive(h) and rp.Parent do
                local target, dist = findNearest(rp.Position, model, 45)
                if target then
                    local tp = posOf(target.Parent)
                    if tp then
                        pathTo(tp)
                        if dist < 6 then
                            target:TakeDamage(5)
                            safeChat(head, "I may be basic but I bite!", Enum.ChatColor.White)
                        else
                            safeChat(head, "I am just a noob! (but chasing u)", Enum.ChatColor.White)
                        end
                    end
                else
                    safeChat(head, "I am just a noob!", Enum.ChatColor.White)
                    patrol()
                end
                task.wait(math.random(2,4))
            end
        end)
    end
