local function onActivated()
    EatSound:Play()
    task.wait(1.5)
    local randomType = characterTypes[math.random(1,#characterTypes)]
    task.spawn(function() spawnNoob(randomType, 0) end)
end

tool.Activated:Connect(onActivated)

